-- Poems batch 446
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('yuding-30','朝下寄韓舍人','耿湋','唐','御定全唐诗','yuding','','[]','侍臣鳴佩出西曹，鸞殿分階翊彩旄。瑞氣迥浮青玉案，',40,'御定全唐詩/json/269.json','["侍臣鳴佩出西曹，鸞殿分階翊彩旄。瑞氣迥浮青玉案，", "肯念萬年芳樹裏，隨風一葉在蓬蒿。"]'),
('yuding-31','賀李觀察禱河神降雨','耿湋','唐','御定全唐诗','yuding','','[]','質明齋祭北風微，騶馭千群擁廟扉。玉帛才敷雲淡淡，',40,'御定全唐詩/json/269.json','["質明齋祭北風微，騶馭千群擁廟扉。玉帛才敷雲淡淡，", "若出敬亭山下作，何人敢和謝玄暉。"]'),
('yuding-32','上將行','耿湋','唐','御定全唐诗','yuding','','[]','蕭關掃定犬羊群，閉閣層城白日曛。櫪上驊騮嘶鼓角，',40,'御定全唐詩/json/269.json','["蕭關掃定犬羊群，閉閣層城白日曛。櫪上驊騮嘶鼓角，", "誰道古來多簡冊，功臣唯有衛將軍。"]'),
('yuding-33','許下書情寄張韓二舍人','耿湋','唐','御定全唐诗','yuding','','[]','謫宦軍城老更悲，近來頻夜夢丹墀。銀盃乍滅心中火，',40,'御定全唐詩/json/269.json','["謫宦軍城老更悲，近來頻夜夢丹墀。銀盃乍滅心中火，", "故人高步雲衢上，肯念前程杳未期。"]'),
('yuding-34','九日','耿湋','唐','御定全唐诗','yuding','','[]','重陽寒寺滿秋梧，客在南樓顧老夫。步蹇強登遊藻井，',40,'御定全唐詩/json/269.json','["重陽寒寺滿秋梧，客在南樓顧老夫。步蹇強登遊藻井，", "更望尊中菊花酒，殷勤能得幾回沽。"]'),
('yuding-35','送大谷高少府','耿湋','唐','御定全唐诗','yuding','','[]','縣屬並州北近胡，悠悠此別宦仍孤。應知史筆思循吏，',40,'御定全唐詩/json/269.json','["縣屬並州北近胡，悠悠此別宦仍孤。應知史筆思循吏，", "雕殘貴有親仁術，梅福何須去隱吳。"]'),
('yuding-36','同李端春望','耿湋','唐','御定全唐诗','yuding','','[]','二毛羈旅尚迷津，萬井鶯花雨後春。宮闕參差當晚日，',40,'御定全唐詩/json/269.json','["二毛羈旅尚迷津，萬井鶯花雨後春。宮闕參差當晚日，", "南北東西各自去，年年依舊物華新。"]'),
('yuding-37','岳祠送薛近貶官','耿湋','唐','御定全唐诗','yuding','','[]','枯松老柏仙山下，白帝祠堂枕古逵。遷客無辜祝史告，',40,'御定全唐詩/json/269.json','["枯松老柏仙山下，白帝祠堂枕古逵。遷客無辜祝史告，", "度嶺梅花翻向北，回看不見樹南枝。"]'),
('yuding-38','送友人游江南','耿湋','唐','御定全唐诗','yuding','','[]','遠別悠悠白髮新，江潭何處是通津，潮聲偏懼初來客，',40,'御定全唐詩/json/269.json','["遠別悠悠白髮新，江潭何處是通津，潮聲偏懼初來客，", "汀洲更有南回雁，亂起聯翩北向秦。"]'),
('yuding-39','長門怨','耿湋','唐','御定全唐诗','yuding','','[]','聞道昭陽宴，嚬蛾落葉中。清歌逐寒月，遙夜入深宮。',24,'御定全唐詩/json/269.json','["聞道昭陽宴，嚬蛾落葉中。清歌逐寒月，遙夜入深宮。"]'),
('yuding-40','秋日','耿湋','唐','御定全唐诗','yuding','','[]','反照入閭巷，憂來與誰語。古道無人行，秋風動禾黍。',24,'御定全唐詩/json/269.json','["反照入閭巷，憂來與誰語。古道無人行，秋風動禾黍。"]'),
('yuding-41','秋夜','耿湋','唐','御定全唐诗','yuding','','[]','高秋夜分後，遠客雁來時。寂寞重門掩，無人問所思。',24,'御定全唐詩/json/269.json','["高秋夜分後，遠客雁來時。寂寞重門掩，無人問所思。"]'),
('yuding-42','慈恩寺殘春','耿湋','唐','御定全唐诗','yuding','','[]','雙林花已盡，葉色占殘芳。若問同遊客，高年最斷腸。',24,'御定全唐詩/json/269.json','["雙林花已盡，葉色占殘芳。若問同遊客，高年最斷腸。"]'),
('yuding-43','早次眉縣界','耿湋','唐','御定全唐诗','yuding','','[]','匹馬曉路歸，悠悠渭川道。晴山向孤城，秋日滿白草。',24,'御定全唐詩/json/269.json','["匹馬曉路歸，悠悠渭川道。晴山向孤城，秋日滿白草。"]'),
('yuding-44','路傍墓','耿湋','唐','御定全唐诗','yuding','','[]','石馬雙雙當古樹，不知何代公侯墓。',32,'御定全唐詩/json/269.json','["石馬雙雙當古樹，不知何代公侯墓。", "墓前靡靡春草深，唯有行人看碑路。"]'),
('yuding-45','代園中老人','耿湋','唐','御定全唐诗','yuding','','[]','傭賃難堪一老身，皤皤力役在青春。',32,'御定全唐詩/json/269.json','["傭賃難堪一老身，皤皤力役在青春。", "林園手種唯吾事，桃李成陰歸別人。"]'),
('yuding-46','古意','耿湋','唐','御定全唐诗','yuding','','[]','雖言千騎上頭居，一世生離恨有餘。',32,'御定全唐詩/json/269.json','["雖言千騎上頭居，一世生離恨有餘。", "葉下綺窗銀燭冷，含啼自草錦中書。"]'),
('yuding-47','涼州詞','耿湋','唐','御定全唐诗','yuding','','[]','國使翻翻隨旆旌，隴西岐路足荒城。',32,'御定全唐詩/json/269.json','["國使翻翻隨旆旌，隴西岐路足荒城。", "氈裘牧馬胡雛小，日暮蕃歌三兩聲。"]'),
('yuding-48','安邑王校書居','耿湋','唐','御定全唐诗','yuding','','[]','秋來池館清，夜聞宮漏聲。迢遞玉山迥，泛灩銀河傾。',48,'御定全唐詩/json/269.json','["秋來池館清，夜聞宮漏聲。迢遞玉山迥，泛灩銀河傾。", "琴上松風至，窗裏竹煙生。多君不家食，孰雲事岩耕。"]'),
('yuding-49','登總持寺閣','耿湋','唐','御定全唐诗','yuding','','[]','今日登高閣，三休忽自悲。因知筋力減，不及往年時。',48,'御定全唐詩/json/269.json','["今日登高閣，三休忽自悲。因知筋力減，不及往年時。", "草樹還如舊，山河亦在茲。龍鍾兼老病，更有重來期。"]'),
('yuding-50','寄錢起','耿湋','唐','御定全唐诗','yuding','','[]','草長花落樹，羸病強尋春。無複少年意，空餘華髮新。',48,'御定全唐詩/json/269.json','["草長花落樹，羸病強尋春。無複少年意，空餘華髮新。", "青原高見水，白社靜逢人。寄謝南宮客，軒車不見親。"]'),
('yuding-51','宿青龍寺故曇上人院','耿湋','唐','御定全唐诗','yuding','','[]','年深宮院在，閑客自相逢。閉戶臨寒竹，無人有夜鐘。',48,'御定全唐詩/json/269.json','["年深宮院在，閑客自相逢。閉戶臨寒竹，無人有夜鐘。", "降龍今已去，巢鶴竟何從。坐見繁星曉，淒涼識舊峰。"]'),
('yuding-52','新蟬','耿湋','唐','御定全唐诗','yuding','','[]','今朝蟬忽鳴，遷客若為情。便覺一年謝，能令萬感生。',48,'御定全唐詩/json/269.json','["今朝蟬忽鳴，遷客若為情。便覺一年謝，能令萬感生。", "微風方滿樹，落日稍沈城。為問同懷者，淒涼聽幾聲。"]'),
('yuding-53','秋中雨田園即事','耿湋','唐','御定全唐诗','yuding','','[]','漠漠重雲暗，蕭蕭密雨垂。為霖淹古道，積日滿荒陂。',72,'御定全唐詩/json/269.json','["漠漠重雲暗，蕭蕭密雨垂。為霖淹古道，積日滿荒陂。", "五稼何時獲，孤村幾戶炊。亂流發通圃，腐葉著秋枝。", "暮爨新樵濕，晨漁舊浦移。空餘去年菊，花發在東籬。"]'),
('yuding-54','拜新月','耿湋','唐','御定全唐诗','yuding','','[]','開簾見新月，便即下階拜。細語人不聞，北風吹裙帶。',24,'御定全唐詩/json/269.json','["開簾見新月，便即下階拜。細語人不聞，北風吹裙帶。"]'),
('yuding-55','客行贈人','耿湋','唐','御定全唐诗','yuding','','[]','旅行雖別路，日暮各思歸。欲下今朝淚，知君亦濕衣。',24,'御定全唐詩/json/269.json','["旅行雖別路，日暮各思歸。欲下今朝淚，知君亦濕衣。"]'),
('yuding-56','贈山老人','耿湋','唐','御定全唐诗','yuding','','[]','白首獨一身，青山為四鄰。雖行故鄉陌，不見故鄉人。',24,'御定全唐詩/json/269.json','["白首獨一身，青山為四鄰。雖行故鄉陌，不見故鄉人。"]'),
('yuding-57','贈胡居士','耿湋','唐','御定全唐诗','yuding','','[]','孔融過五十，海內故人稀。相府恩猶在，知君未拂衣。',24,'御定全唐詩/json/269.json','["孔融過五十，海內故人稀。相府恩猶在，知君未拂衣。"]'),
('yuding-58','薦福寺送元偉','耿湋','唐','御定全唐诗','yuding','','[]','送客攀花後，尋僧坐竹時。明朝莫回望，青草馬行遲。',24,'御定全唐詩/json/269.json','["送客攀花後，尋僧坐竹時。明朝莫回望，青草馬行遲。"]'),
('yuding-59','觀鄰老栽松','耿湋','唐','御定全唐诗','yuding','','[]','雖過老人宅，不解老人心。何事斜陽裏，栽松欲待陰。',24,'御定全唐詩/json/269.json','["雖過老人宅，不解老人心。何事斜陽裏，栽松欲待陰。"]'),
('yuding-60','哭麹象','耿湋','唐','御定全唐诗','yuding','','[]','憶昨秋風起，君曾歎逐臣。何言芳草日，自作九泉人。',24,'御定全唐詩/json/269.json','["憶昨秋風起，君曾歎逐臣。何言芳草日，自作九泉人。"]'),
('yuding-61','哭苗垂','耿湋','唐','御定全唐诗','yuding','','[]','舊友無由見，孤墳草欲長。月斜鄰笛盡，車馬出山陽。',24,'御定全唐詩/json/269.json','["舊友無由見，孤墳草欲長。月斜鄰笛盡，車馬出山陽。"]'),
('yuding-62','題雲際寺故僧院','耿湋','唐','御定全唐诗','yuding','','[]','白髮匆匆色，青山草草心。遠公仍下世，從此別東林。',24,'御定全唐詩/json/269.json','["白髮匆匆色，青山草草心。遠公仍下世，從此別東林。"]'),
('yuding-63','句','耿湋','唐','御定全唐诗','yuding','','[]','高樹多涼吹，疏蟬足斷聲。。',13,'御定全唐詩/json/269.json','["高樹多涼吹，疏蟬足斷聲。。"]'),
('yuding-0','塞下曲','戎昱','唐','御定全唐诗','yuding','','[]','慘慘寒日沒，北風卷蓬根。將軍領疲兵，卻入古塞門。',228,'御定全唐詩/json/270.json','["慘慘寒日沒，北風卷蓬根。將軍領疲兵，卻入古塞門。", "回頭指陰山，殺氣成黃雲。", "上山望胡兵，胡馬馳驟速。黃河冰已合，意又向南牧。", "嫖姚夜出軍，霜雪割人肉。", "塞北無草木，烏鳶巢僵屍。泱渀沙漠空，終日胡風吹。", "戰卒多苦辛，苦辛無四時。", "晚渡西海西，向東看日沒。傍岸砂礫堆，半和戰兵骨。", "單于竟未滅，陰氣常勃勃。", "城上畫角哀，即知兵心苦。試問左右人，無言淚如雨。", "何意休明時，終年事鼙鼓。", "北風凋白草，胡馬日駸駸。夜後戍樓月，秋來邊將心。", "鐵衣霜露重，戰馬歲年深。自有盧龍塞，煙塵飛至今。"]'),
('yuding-1','苦哉行五首','戎昱','唐','御定全唐诗','yuding','','[]','彼鼠侵我廚，縱狸授粱肉。鼠雖為君卻，狸食自須足。',408,'御定全唐詩/json/270.json','["彼鼠侵我廚，縱狸授粱肉。鼠雖為君卻，狸食自須足。", "冀雪大國恥，翻是大國辱。膻腥逼綺羅，磚瓦雜珠玉。", "登樓非騁望，目笑是心哭。何意天樂中，至今奏胡曲。", "官軍收洛陽，家住洛陽裏。夫婿與兄弟，目前見傷死。", "吞聲不許哭，還遣衣羅綺。上馬隨匈奴，數秋黃塵裏。", "生為名家女，死作塞垣鬼。鄉國無還期，天津哭流水。", "登樓望天衢，目極淚盈睫。強笑無笑容，須妝舊花靨。", "昔年買奴僕，奴僕來碎葉。豈意未死間，自為匈奴妾。", "一生忽至此，萬事痛苦業。得出塞垣飛，不如彼蜂蝶。", "妾家清河邊，七葉承貂蟬。身為最小女，偏得渾家憐。", "親戚不相識，幽閨十五年。有時最遠出，只到中門前。", "前年狂胡來，懼死翻生全。今秋官軍至，豈意遭戈鋋。", "匈奴為先鋒，長鼻黃發拳。彎弓獵生人，百步牛羊膻。", "脫身落虎口，不及歸黃泉。苦哉難重陳，暗哭蒼蒼天。", "可汗奉親詔，今月歸燕山。忽如亂刀劍，攪妾心腸間。", "出戶望北荒，迢迢玉門關。生人為死別，有去無時還。", "漢月割妾心，胡風凋妾顏。去去斷絕魂，叫天天不聞。"]'),
('yuding-2','苦辛行','戎昱','唐','御定全唐诗','yuding','','[]','且莫奏短歌，聽余苦辛詞。如今刀筆士，不及屠沽兒。',116,'御定全唐詩/json/270.json','["且莫奏短歌，聽余苦辛詞。如今刀筆士，不及屠沽兒。", "少年無事學詩賦，豈意文章複相誤。東西南北少知音，", "天地生我尚如此，陌上他人何足論。誰謂西江深，", "險巇唯有世間路，一晌令人堪白頭。貴人立意不可測，", "悲來卻憶漢天子，不棄相如家舊貧。勸君且飲酒，"]'),
('yuding-3','長安秋夕','戎昱','唐','御定全唐诗','yuding','','[]','八月更漏長，愁人起常早。閉門寂無事，滿院生秋草。',48,'御定全唐詩/json/270.json','["八月更漏長，愁人起常早。閉門寂無事，滿院生秋草。", "昨宵西窗夢，夢入荊南道。遠客歸去來，在家貧亦好。"]'),
('yuding-4','羅江客舍','戎昱','唐','御定全唐诗','yuding','','[]','山縣秋雲暗，茅亭暮雨寒。自傷庭葉下，誰問客衣單。',48,'御定全唐詩/json/270.json','["山縣秋雲暗，茅亭暮雨寒。自傷庭葉下，誰問客衣單。", "有興時添酒，無聊懶整冠。近來鄉國夢，夜夜到長安。"]'),
('yuding-5','贈岑郎中','戎昱','唐','御定全唐诗','yuding','','[]','童年未解讀書時，誦得郎中數首詩。四海煙塵猶隔闊，',40,'御定全唐詩/json/270.json','["童年未解讀書時，誦得郎中數首詩。四海煙塵猶隔闊，", "天下無人鑒詩句，不尋詩伯重尋誰。"]'),
('yuding-6','聞笛','戎昱','唐','御定全唐诗','yuding','','[]','入夜思歸切，笛聲清更哀。愁人不願聽，自到枕前來。',48,'御定全唐詩/json/270.json','["入夜思歸切，笛聲清更哀。愁人不願聽，自到枕前來。", "風起塞雲斷，夜深關月開。平明獨惆悵，飛盡一庭梅。"]'),
('yuding-7','漢上題韋氏莊','戎昱','唐','御定全唐诗','yuding','','[]','結茅同楚客，卜築漢江邊。日落數歸鳥，夜深聞扣舷。',48,'御定全唐詩/json/270.json','["結茅同楚客，卜築漢江邊。日落數歸鳥，夜深聞扣舷。", "水痕侵岸柳，山翠借廚煙。調笑提筐婦，春來蠶幾眠。"]'),
('yuding-8','閨情','戎昱','唐','御定全唐诗','yuding','','[]','側聽宮官說，知君寵尚存。未能開笑頰，先欲換愁魂。',48,'御定全唐詩/json/270.json','["側聽宮官說，知君寵尚存。未能開笑頰，先欲換愁魂。", "寶鏡窺妝影，紅衫裛淚痕。昭陽今再入，寧敢恨長門。"]'),
('yuding-9','衡陽春日遊僧院','戎昱','唐','御定全唐诗','yuding','','[]','曾共劉諮議，同時事道林。與君相掩淚，來客豈知心。',48,'御定全唐詩/json/270.json','["曾共劉諮議，同時事道林。與君相掩淚，來客豈知心。", "階雪淩春積，爐煙向暝深。依然舊童子，相送出花林。"]'),
('yuding-10','玉台體題湖上亭','戎昱','唐','御定全唐诗','yuding','','[]','湖入縣西邊，湖頭勝事偏。綠竿初長筍，紅顆未開蓮。',48,'御定全唐詩/json/270.json','["湖入縣西邊，湖頭勝事偏。綠竿初長筍，紅顆未開蓮。", "蔽日高高樹，迎人小小船。清風長入坐，夏月似秋天。"]'),
('yuding-11','早梅','戎昱','唐','御定全唐诗','yuding','','[]','一樹寒梅白玉條，迥臨村路傍溪橋。',32,'御定全唐詩/json/270.json','["一樹寒梅白玉條，迥臨村路傍溪橋。", "應緣近水花先發，疑是經春雪未銷。"]'),
('yuding-12','移家別湖上亭','戎昱','唐','御定全唐诗','yuding','','[]','好是春風湖上亭，柳條藤蔓系離情。',32,'御定全唐詩/json/270.json','["好是春風湖上亭，柳條藤蔓系離情。", "黃鶯久住渾相識，欲別頻啼四五聲。"]'),
('yuding-13','客堂秋夕','戎昱','唐','御定全唐诗','yuding','','[]','隔窗螢影滅複流，北風微雨虛堂秋。蟲聲竟夜引鄉淚，',40,'御定全唐詩/json/270.json','["隔窗螢影滅複流，北風微雨虛堂秋。蟲聲竟夜引鄉淚，", "寂寂江城無所聞，梧桐葉上偏蕭索。"]'),
('yuding-14','湖南雪中留別','戎昱','唐','御定全唐诗','yuding','','[]','草草還草草，湖東別離早。何處愁殺人，歸鞍雪中道。',48,'御定全唐詩/json/270.json','["草草還草草，湖東別離早。何處愁殺人，歸鞍雪中道。", "出門迷轍跡，雲水白浩浩。明日武陵西，相思鬢堪老。"]'),
('yuding-15','贈別張駙馬','戎昱','唐','御定全唐诗','yuding','','[]','上元年中長安陌，見君朝下欲歸宅。飛龍騎馬三十匹，',112,'御定全唐詩/json/270.json','["上元年中長安陌，見君朝下欲歸宅。飛龍騎馬三十匹，", "從奴斜抱敕賜錦，雙雙蹙出金麒麟。天子愛婿皇后弟，", "鳳凰樓上伴吹簫，鸚鵡杯中醉留客。泰去否來何足論，", "冠冕淒涼幾遷改，眼看桑田變成海。華堂金屋別賜人，", "看君風骨殊未歇，不用愁來雙淚垂。"]'),
('yuding-16','涇州觀元戎出師','戎昱','唐','御定全唐诗','yuding','','[]','寒日征西將，蕭蕭萬馬叢。吹笳覆樓雪，祝纛滿旗風。',96,'御定全唐詩/json/270.json','["寒日征西將，蕭蕭萬馬叢。吹笳覆樓雪，祝纛滿旗風。", "遮虜黃雲斷，燒羌白草空。金鐃肅天外，玉帳靜霜中。", "朔野長城閉，河源舊路通。衛青師自老，魏絳賞何功。", "槍壘依沙迥，轅門壓塞雄。燕然如可勒，萬里願從公。"]'),
('yuding-17','從軍行','戎昱','唐','御定全唐诗','yuding','','[]','昔從李都尉，雙鞬照馬蹄。擒生黑山北，殺敵黃雲西。',108,'御定全唐詩/json/270.json','["昔從李都尉，雙鞬照馬蹄。擒生黑山北，殺敵黃雲西。", "太白沈虜地，邊草複萋萋。歸來邯鄲市，百尺青樓梯。", "感激然諾重，平生膽力齊。芳筵暮歌發，豔粉輕鬟低。", "半酣秋風起，鐵騎門前嘶。遠戍報烽火，孤城嚴鼓鼙。", "揮鞭望塵去，少婦莫含啼。"]'),
('yuding-18','古意','戎昱','唐','御定全唐诗','yuding','','[]','女伴朝來說，知君欲棄捐。懶梳明鏡下，羞到畫堂前。',48,'御定全唐詩/json/270.json','["女伴朝來說，知君欲棄捐。懶梳明鏡下，羞到畫堂前。", "有淚沾脂粉，無情理管弦。不知將巧笑，更遣向誰憐。"]'),
('yuding-19','聽杜山人彈胡笳','戎昱','唐','御定全唐诗','yuding','','[]','綠琴胡笳誰妙彈，山人杜陵名庭蘭。杜君少與山人友，',136,'御定全唐詩/json/270.json','["綠琴胡笳誰妙彈，山人杜陵名庭蘭。杜君少與山人友，", "杜陵攻琴四十年，琴聲在音不在弦。座中為我奏此曲，", "更聞出塞入塞聲，穹廬氈帳難為情。胡天雨雪四時下，", "南看漢月雙眼明，卻顧胡兒寸心死。回鶻數年收洛陽，", "杜陵先生證此道，沈家祝家皆絕倒。如今世上雅風衰，", "今朝促軫為君奏，不向俗流傳此心。"]'),
('yuding-20','詠史','戎昱','唐','御定全唐诗','yuding','','[]','漢家青史上，計拙是和親。社稷依明主，安危托婦人。',48,'御定全唐詩/json/270.json','["漢家青史上，計拙是和親。社稷依明主，安危托婦人。", "豈能將玉貌，便擬靜胡塵。地下千年骨，誰為輔佐臣。"]'),
('yuding-21','桂州臘夜','戎昱','唐','御定全唐诗','yuding','','[]','坐到三更盡，歸仍萬里賒。雪聲偏傍竹，寒夢不離家。',48,'御定全唐詩/json/270.json','["坐到三更盡，歸仍萬里賒。雪聲偏傍竹，寒夢不離家。", "曉角分殘漏，孤燈落碎花。二年隨驃騎，辛苦向天涯。"]'),
('yuding-22','再赴桂州先寄李大夫','戎昱','唐','御定全唐诗','yuding','','[]','玷玉甘長棄，朱門喜再遊。過因讒後重，恩合死前酬。',48,'御定全唐詩/json/270.json','["玷玉甘長棄，朱門喜再遊。過因讒後重，恩合死前酬。", "養驥須憐瘦，栽松莫厭秋。今朝兩行淚，一半血和流。"]'),
('yuding-23','題招提寺','戎昱','唐','御定全唐诗','yuding','','[]','招提精舍好，石壁向江開。山影水中盡，鳥聲天上來。',48,'御定全唐詩/json/270.json','["招提精舍好，石壁向江開。山影水中盡，鳥聲天上來。", "一燈傳歲月，深院長莓苔。日暮雙林磬，泠泠送客回。"]'),
('yuding-24','謫官辰州冬至日有懷','戎昱','唐','御定全唐诗','yuding','','[]','去年長至在長安，策杖曾簪獬豸冠。此歲長安逢至日，',40,'御定全唐詩/json/270.json','["去年長至在長安，策杖曾簪獬豸冠。此歲長安逢至日，", "北望南郊消息斷，江頭唯有淚闌幹。"]'),
('yuding-25','贈韋況征君','戎昱','唐','御定全唐诗','yuding','','[]','身欲逃名名自隨，鳳銜丹詔降茅茨。苦節難違天子命，',40,'御定全唐詩/json/270.json','["身欲逃名名自隨，鳳銜丹詔降茅茨。苦節難違天子命，", "今日巢由舊冠帶，聖朝風化勝堯時。"]'),
('yuding-26','送吉州閻使君入道二首','戎昱','唐','御定全唐诗','yuding','','[]','聞道桃源去，塵心忽自悲。餘當從宦日，君是棄官時。',112,'御定全唐詩/json/270.json','["聞道桃源去，塵心忽自悲。餘當從宦日，君是棄官時。", "金汞封仙骨，靈津咽玉池。受傳三籙備，起坐五雲隨。", "洞裏花常發，人間鬢易衰。他年會相訪，莫作爛柯棋。", "廬陵太守近隳官，霞帔初朝五帝壇。風過鬼神延受籙，", "莫遣桃花迷客路，千山萬水訪君難。"]'),
('yuding-27','入劍門','戎昱','唐','御定全唐诗','yuding','','[]','劍門兵革後，萬事盡堪悲。鳥鼠無巢穴，兒童話別離。',48,'御定全唐詩/json/270.json','["劍門兵革後，萬事盡堪悲。鳥鼠無巢穴，兒童話別離。", "山川同昔日，荊棘是今時。征戰何年定，家家有畫旗。"]'),
('yuding-28','過商山','戎昱','唐','御定全唐诗','yuding','','[]','雨暗商山過客稀，路傍孤店閉柴扉。',32,'御定全唐詩/json/270.json','["雨暗商山過客稀，路傍孤店閉柴扉。", "卸鞍良久茅簷下，待得巴人樵采歸。"]'),
('yuding-29','閏春宴花溪嚴侍禦莊','戎昱','唐','御定全唐诗','yuding','','[]','一團青翠色，雲是子陵家。山帶新晴雨，溪留閏月花。',48,'御定全唐詩/json/270.json','["一團青翠色，雲是子陵家。山帶新晴雨，溪留閏月花。", "瓶開巾漉酒，地坼筍抽芽。彩縟承顏面，朝朝賦白華。"]'),
('yuding-30','歲暮客懷','戎昱','唐','御定全唐诗','yuding','','[]','異鄉三十口，親老複家貧。無事乾坤內，虛為翰墨人。',48,'御定全唐詩/json/270.json','["異鄉三十口，親老複家貧。無事乾坤內，虛為翰墨人。", "歲華南去後，愁夢北來頻。惆悵江邊柳，依依又欲春。"]'),
('yuding-31','秋望興慶宮','戎昱','唐','御定全唐诗','yuding','','[]','先皇歌舞地，今日未遊巡。幽咽龍池水，淒涼禦榻塵。',48,'御定全唐詩/json/270.json','["先皇歌舞地，今日未遊巡。幽咽龍池水，淒涼禦榻塵。", "隨風秋樹葉，對月老宮人。萬事如桑海，悲來欲慟神。"]'),
('yuding-32','送鄭煉師貶辰州','戎昱','唐','御定全唐诗','yuding','','[]','辰州萬里外，想得逐臣心。謫去刑名枉，人間痛惜深。',48,'御定全唐詩/json/270.json','["辰州萬里外，想得逐臣心。謫去刑名枉，人間痛惜深。", "誤將瑕指玉，遂使謾消金。計日西歸在，休為澤畔吟。"]'),
('yuding-33','雲夢故城秋望','戎昱','唐','御定全唐诗','yuding','','[]','故國遺墟在，登臨想舊遊。一朝人事變，千載水空流。',48,'御定全唐詩/json/270.json','["故國遺墟在，登臨想舊遊。一朝人事變，千載水空流。", "夢渚鴻聲晚，荊門樹色秋。片雲凝不散，遙掛望鄉愁。"]'),
('yuding-34','秋日感懷','戎昱','唐','御定全唐诗','yuding','','[]','洛陽岐路信悠悠，無事辭家兩度秋。日下未馳千里足，',40,'御定全唐詩/json/270.json','["洛陽岐路信悠悠，無事辭家兩度秋。日下未馳千里足，", "說向長安親與故，誰憐歲晚尚淹留。"]'),
('yuding-35','送王明府入道','戎昱','唐','御定全唐诗','yuding','','[]','何事陶彭澤，明時又掛冠。為耽泉石趣，不憚薜蘿寒。',48,'御定全唐詩/json/270.json','["何事陶彭澤，明時又掛冠。為耽泉石趣，不憚薜蘿寒。", "輕雪籠紗帽，孤猿傍醮壇。懸懸老松下，金灶夜燒丹。"]'),
('yuding-36','秋月','戎昱','唐','御定全唐诗','yuding','','[]','江幹入夜杵聲秋，百尺疏桐掛斗牛。',32,'御定全唐詩/json/270.json','["江幹入夜杵聲秋，百尺疏桐掛斗牛。", "思苦自看明月苦，人愁不是月華愁。"]'),
('yuding-37','賦得鐵馬鞭','戎昱','唐','御定全唐诗','yuding','','[]','成器雖因匠，懷剛本自天。為憐持寸節，長擬靜三邊。',48,'御定全唐詩/json/270.json','["成器雖因匠，懷剛本自天。為憐持寸節，長擬靜三邊。", "未入英髦用，空存鐵石堅。希君剖腹取，還解抱龍泉。"]'),
('yuding-38','聞顏尚書陷賊中','戎昱','唐','御定全唐诗','yuding','','[]','聞說征南沒，那堪故吏聞。能持蘇武節，不受馬超勳。',48,'御定全唐詩/json/270.json','["聞說征南沒，那堪故吏聞。能持蘇武節，不受馬超勳。", "國破無家信，天秋有雁群。同榮不同辱，今日負將軍。"]'),
('yuding-39','送蘇參軍','戎昱','唐','御定全唐诗','yuding','','[]','憶昨青襟醉裏分，酒醒回首愴離群。舟移極浦城初掩，',40,'御定全唐詩/json/270.json','["憶昨青襟醉裏分，酒醒回首愴離群。舟移極浦城初掩，", "常歎蘇生官太屈，應緣才似鮑參軍。"]'),
('yuding-40','成都元十八侍禦','戎昱','唐','御定全唐诗','yuding','','[]','不見元生已數朝，浣花溪路去非遙。客舍早知渾寂寞，',40,'御定全唐詩/json/270.json','["不見元生已數朝，浣花溪路去非遙。客舍早知渾寂寞，", "驊驄幸自能馳驟，何惜揮鞭過柞橋。"]'),
('yuding-41','觀衛尚書九日對中使射破的','戎昱','唐','御定全唐诗','yuding','','[]','盛宴傾黃菊，殊私降紫泥。月營開射圃，霜旆拂晴霓。',72,'御定全唐詩/json/270.json','["盛宴傾黃菊，殊私降紫泥。月營開射圃，霜旆拂晴霓。", "出將三朝貴，彎弓五善齊。腕回金鏃滿，的破綠弦低。", "勇氣幹牛鬥，歡聲震鼓鼙。忠臣思報國，更欲取關西。"]'),
('yuding-42','辰州聞大駕還宮','戎昱','唐','御定全唐诗','yuding','','[]','聞道鑾輿歸魏闕，望雲西拜喜成悲。寧知隴水煙銷日，',40,'御定全唐詩/json/270.json','["聞道鑾輿歸魏闕，望雲西拜喜成悲。寧知隴水煙銷日，", "自慚出守辰州畔，不得親隨日月旗。"]'),
('yuding-43','辰州建中四年多懷','戎昱','唐','御定全唐诗','yuding','','[]','荒徼辰陽遠，窮秋瘴雨深。主恩堪灑血，邊宦更何心。',72,'御定全唐詩/json/270.json','["荒徼辰陽遠，窮秋瘴雨深。主恩堪灑血，邊宦更何心。", "海上紅旗滿，生前白髮侵。竹寒寧改節，隼靜早因禽。", "務退門多掩，愁來酒獨斟。無涯憂國淚，無日不沾襟。"]'),
('yuding-44','上桂州李大夫','戎昱','唐','御定全唐诗','yuding','','[]','今日辭門館，情將眾別殊。感深翻有淚，仁過曲憐愚。',72,'御定全唐詩/json/270.json','["今日辭門館，情將眾別殊。感深翻有淚，仁過曲憐愚。", "晚鏡傷秋鬢，晴寒切病軀。煙霞萬里闊，宇宙一身孤。", "倚馬才寧有，登龍意豈無。唯於方寸內，暗貯報恩珠。"]'),
('yuding-45','江城秋霽','戎昱','唐','御定全唐诗','yuding','','[]','霽後江城風景涼，豈堪登眺只堪傷。遠天螮蝀收殘雨，',40,'御定全唐詩/json/270.json','["霽後江城風景涼，豈堪登眺只堪傷。遠天螮蝀收殘雨，", "不知何處銷茲恨，轉覺愁隨夜夜長。"]'),
('yuding-46','上李常侍','戎昱','唐','御定全唐诗','yuding','','[]','旌旗曉過大江西，七校前驅萬隊齊。千里政聲人共喜，',40,'御定全唐詩/json/270.json','["旌旗曉過大江西，七校前驅萬隊齊。千里政聲人共喜，", "桃李不須令更種，早知門下舊成蹊。"]'),
('yuding-47','上湖南崔中丞','戎昱','唐','御定全唐诗','yuding','','[]','山上青松陌上塵，雲泥豈合得相親。舉世盡嫌良馬瘦，',40,'御定全唐詩/json/270.json','["山上青松陌上塵，雲泥豈合得相親。舉世盡嫌良馬瘦，", "莫道書生無感激，寸心還是報恩人。"]'),
('yuding-48','早春雪中','戎昱','唐','御定全唐诗','yuding','','[]','陰雲萬里晝漫漫，愁坐關心事幾般。',32,'御定全唐詩/json/270.json','["陰雲萬里晝漫漫，愁坐關心事幾般。", "為報春風休下雪，柳條初放不禁寒。"]'),
('yuding-49','雲安阻雨','戎昱','唐','御定全唐诗','yuding','','[]','日長巴峽雨濛濛，又說歸舟路未通。',32,'御定全唐詩/json/270.json','["日長巴峽雨濛濛，又說歸舟路未通。", "遊人不及西江水，先得東流到渚宮。"]'),
('yuding-50','湖南春日二首','戎昱','唐','御定全唐诗','yuding','','[]','自憐春日客長沙，江上無人轉憶家。',64,'御定全唐詩/json/270.json','["自憐春日客長沙，江上無人轉憶家。", "光景卻添鄉思苦，簷前數片落梅花。", "三湘漂寓若流萍，萬里湘鄉隔洞庭。", "羈客春來心欲碎，東風莫遣柳條青。"]'),
('yuding-51','送陸秀才歸覲省','戎昱','唐','御定全唐诗','yuding','','[]','武陵何處在，南指楚雲陰。花萼連枝近，桃源去路深。',48,'御定全唐詩/json/270.json','["武陵何處在，南指楚雲陰。花萼連枝近，桃源去路深。", "啼鶯徒寂寂，征馬已駸駸。堤上千年柳，條條掛我心。"]'),
('yuding-52','戲題秋月','戎昱','唐','御定全唐诗','yuding','','[]','秋宵月色勝春宵，萬里天涯靜寂寥。',32,'御定全唐詩/json/270.json','["秋宵月色勝春宵，萬里天涯靜寂寥。", "近來數夜飛霜重，只畏娑婆樹葉凋。"]'),
('yuding-53','宿湘江','戎昱','唐','御定全唐诗','yuding','','[]','九月湘江水漫流，沙邊唯覽月華秋。',32,'御定全唐詩/json/270.json','["九月湘江水漫流，沙邊唯覽月華秋。", "金風浦上吹黃葉，一夜紛紛滿客舟。"]'),
('yuding-54','戲贈張使君','戎昱','唐','御定全唐诗','yuding','','[]','數載蹉跎罷搢紳，五湖乘興轉迷津。',32,'御定全唐詩/json/270.json','["數載蹉跎罷搢紳，五湖乘興轉迷津。", "如今野客無家第，醉處尋常是主人。"]'),
('yuding-55','別公安賈明府','戎昱','唐','御定全唐诗','yuding','','[]','葉縣門前江水深，淺於羈客報恩心。',32,'御定全唐詩/json/270.json','["葉縣門前江水深，淺於羈客報恩心。", "把君詩卷西歸去，一度相思一度吟。"]'),
('yuding-56','霽雪','戎昱','唐','御定全唐诗','yuding','','[]','風卷寒雲暮雪晴，江煙洗盡柳條輕。',32,'御定全唐詩/json/270.json','["風卷寒雲暮雪晴，江煙洗盡柳條輕。", "簷前數片無人掃，又得書窗一夜明。"]'),
('yuding-57','漢陰吊崔員外墳','戎昱','唐','御定全唐诗','yuding','','[]','遠別望有歸，葉落望春暉。所痛泉路人，一去無還期。',84,'御定全唐詩/json/270.json','["遠別望有歸，葉落望春暉。所痛泉路人，一去無還期。", "荒墳遺漢陰，墳樹啼子規。存沒抱冤滯，孤魂意何依。", "豈無骨肉親，豈無深相知。曝露不復問，高名亦何為。", "相攜慟君罷，春日空遲遲。"]'),
('yuding-58','題槿花','戎昱','唐','御定全唐诗','yuding','','[]','自用金錢買槿栽，二年方始得花開。',32,'御定全唐詩/json/270.json','["自用金錢買槿栽，二年方始得花開。", "鮮紅未許佳人見，蝴蝶爭知早到來。"]'),
('yuding-59','題宋玉亭','戎昱','唐','御定全唐诗','yuding','','[]','宋玉亭前悲暮秋，陽臺路上雨初收。',32,'御定全唐詩/json/270.json','["宋玉亭前悲暮秋，陽臺路上雨初收。", "應緣此處人多別，松竹蕭蕭也帶愁。"]'),
('yuding-60','過東平軍','戎昱','唐','御定全唐诗','yuding','','[]','畫角初鳴殘照微，營營鞍馬往來稀。',32,'御定全唐詩/json/270.json','["畫角初鳴殘照微，營營鞍馬往來稀。", "相逢士卒皆垂淚，八座朝天何日歸。"]'),
('yuding-61','送辰州鄭使君','戎昱','唐','御定全唐诗','yuding','','[]','誰人不譴謫，君去獨堪傷。長子家無弟，慈親老在堂。',48,'御定全唐詩/json/270.json','["誰人不譴謫，君去獨堪傷。長子家無弟，慈親老在堂。", "驚魂隨驛吏，冒暑向炎方。未到猿啼處，參差已斷腸。"]'),
('yuding-62','江上柳送人','戎昱','唐','御定全唐诗','yuding','','[]','江柳斷腸色，黃絲垂未齊。人看幾重恨，鳥入一枝低。',48,'御定全唐詩/json/270.json','["江柳斷腸色，黃絲垂未齊。人看幾重恨，鳥入一枝低。", "鄉淚正堪落，與君又解攜。相思萬里道，春去夕陽西。"]'),
('yuding-63','湘南曲','戎昱','唐','御定全唐诗','yuding','','[]','虞帝南遊不復還，翠蛾幽怨水雲間。',32,'御定全唐詩/json/270.json','["虞帝南遊不復還，翠蛾幽怨水雲間。", "昨夜月明湘浦宿，閨中珂佩度空山。"]'),
('yuding-64','桂州西山登高上陸大夫','戎昱','唐','御定全唐诗','yuding','','[]','登高上山上，高處更堪愁。野菊他鄉酒，蘆花滿眼秋。',48,'御定全唐詩/json/270.json','["登高上山上，高處更堪愁。野菊他鄉酒，蘆花滿眼秋。", "風煙連楚郡，兄弟客荊州。早晚朝天去，親隨定遠侯。"]'),
('yuding-65','寄鄭煉師','戎昱','唐','御定全唐诗','yuding','','[]','平生金石友，淪落向辰州。已是二年客，那堪終日愁。',48,'御定全唐詩/json/270.json','["平生金石友，淪落向辰州。已是二年客，那堪終日愁。", "尺書渾不寄，兩鬢計應秋。今夜相思月，情人南海頭。"]'),
('yuding-66','八月十五日','戎昱','唐','御定全唐诗','yuding','','[]','憶昔千秋節，歡娛萬國同。今來六親遠，此日一悲風。',48,'御定全唐詩/json/270.json','["憶昔千秋節，歡娛萬國同。今來六親遠，此日一悲風。", "年少逢胡亂，時平似夢中。梨園幾人在，應是涕無窮。"]'),
('yuding-67','征人歸鄉','戎昱','唐','御定全唐诗','yuding','','[]','三月江城柳絮飛，五年遊客送人歸。',32,'御定全唐詩/json/270.json','["三月江城柳絮飛，五年遊客送人歸。", "故將別淚和鄉淚，今日闌幹濕汝衣。"]'),
('yuding-68','駱家亭子納涼','戎昱','唐','御定全唐诗','yuding','','[]','江湖思渺然，不離國門前。折葦魚沈藻，攀藤鳥出煙。',48,'御定全唐詩/json/270.json','["江湖思渺然，不離國門前。折葦魚沈藻，攀藤鳥出煙。", "生衣宜水竹，小酒入詩篇。莫怪侵星坐，神清不欲眠。"]'),
('yuding-69','逢隴西故人憶關中舍弟','戎昱','唐','御定全唐诗','yuding','','[]','莫話邊庭事，心摧不欲聞。數年家隴地，舍弟歿胡軍。',48,'御定全唐詩/json/270.json','["莫話邊庭事，心摧不欲聞。數年家隴地，舍弟歿胡軍。", "每念支離苦，常嗟骨肉分。急難何日見，遙哭隴西雲。"]'),
('yuding-70','秋夜梁十三廳事','戎昱','唐','御定全唐诗','yuding','','[]','今來秋已暮，還恐未成歸。夢裏家仍遠，愁中葉又飛。',48,'御定全唐詩/json/270.json','["今來秋已暮，還恐未成歸。夢裏家仍遠，愁中葉又飛。", "竹聲風度急，燈影月來微。得見梁夫子，心源有所依。"]'),
('yuding-71','成都暮雨秋','戎昱','唐','御定全唐诗','yuding','','[]','九月龜城暮，愁人閉草堂。地卑多雨潤，天暖少秋霜。',48,'御定全唐詩/json/270.json','["九月龜城暮，愁人閉草堂。地卑多雨潤，天暖少秋霜。", "縱欲傾新酒，其如憶故鄉。不知更漏意，惟向客邊長。"]'),
('yuding-72','酬梁二十','戎昱','唐','御定全唐诗','yuding','','[]','渚宮無限客，相見獨相親。長路皆同病，無言似一身。',48,'御定全唐詩/json/270.json','["渚宮無限客，相見獨相親。長路皆同病，無言似一身。", "歲寒唯愛竹，憔悴不堪春。細與知音說，攻文恐誤人。"]'),
('yuding-73','花下宴送鄭煉師','戎昱','唐','御定全唐诗','yuding','','[]','愁裏惜春深，聞幽即共尋。貴看花柳色，圖放別離心。',48,'御定全唐詩/json/270.json','["愁裏惜春深，聞幽即共尋。貴看花柳色，圖放別離心。", "客醉花能笑，詩成花伴吟。為君調綠綺，先奏鳳歸林。"]'),
('yuding-74','秋館雨後得弟兄書即事呈李明府','戎昱','唐','御定全唐诗','yuding','','[]','弟兄書忽到，一夜喜兼愁。空館複聞雨，貧家怯到秋。',48,'御定全唐詩/json/270.json','["弟兄書忽到，一夜喜兼愁。空館複聞雨，貧家怯到秋。", "坐中孤燭暗，窗外數螢流。試以他鄉事，明朝問子遊。"]'),
('yuding-75','寄梁淑','戎昱','唐','御定全唐诗','yuding','','[]','長憶江頭執別時，論文未有不相思。雁過經秋無尺素，',40,'御定全唐詩/json/270.json','["長憶江頭執別時，論文未有不相思。雁過經秋無尺素，", "悔學秦人南避地，武陵原上又征師。"]'),
('yuding-76','送張秀才之長沙','戎昱','唐','御定全唐诗','yuding','','[]','君向長沙去，長沙僕舊諳。雖之桂嶺北，終是闕庭南。',48,'御定全唐詩/json/270.json','["君向長沙去，長沙僕舊諳。雖之桂嶺北，終是闕庭南。", "山靄生朝雨，江煙作夕嵐。松醪能醉客，慎勿滯湘潭。"]'),
('yuding-77','塞下曲','戎昱','唐','御定全唐诗','yuding','','[]','漢將歸來虜塞空，旌旗初下玉關東。',32,'御定全唐詩/json/270.json','["漢將歸來虜塞空，旌旗初下玉關東。", "高蹄戰馬三千匹，落日平原秋草中。"]'),
('yuding-78','送僧法和','戎昱','唐','御定全唐诗','yuding','','[]','達士心無滯，他鄉總是家。問經翻貝葉，論法指蓮花。',48,'御定全唐詩/json/270.json','["達士心無滯，他鄉總是家。問經翻貝葉，論法指蓮花。", "欲契真空義，先開智慧芽。不知飛錫後，何外是恒沙。"]'),
('yuding-79','送嚴十五郎之長安','戎昱','唐','御定全唐诗','yuding','','[]','送客身為客，思家愴別家。暫收雙眼淚，遙想五陵花。',48,'御定全唐詩/json/270.json','["送客身為客，思家愴別家。暫收雙眼淚，遙想五陵花。", "路遠征車迥，山回劍閣斜。長安君到日，春色未應賒。"]'),
('yuding-80','冬夜宴梁十三廳','戎昱','唐','御定全唐诗','yuding','','[]','故人能愛客，秉燭會吾曹。家為朋徒罄，心緣翰墨勞。',48,'御定全唐詩/json/270.json','["故人能愛客，秉燭會吾曹。家為朋徒罄，心緣翰墨勞。", "夜寒銷臘酒，霜冷重綈袍。醉臥西窗下，時聞雁響高。"]'),
('yuding-81','收襄陽城二首','戎昱','唐','御定全唐诗','yuding','','[]','悲風慘慘雨修修，峴北山低草木愁。',64,'御定全唐詩/json/270.json','["悲風慘慘雨修修，峴北山低草木愁。", "暗發前軍連夜戰，平明旌旆入襄州。", "五營飛將擁霜戈，百里僵屍滿濜河。", "日暮歸來看劍血，將軍卻恨殺人多。"]'),
('yuding-82','出軍','戎昱','唐','御定全唐诗','yuding','','[]','龍繞旌竿獸滿旗，翻營乍似雪中移。',32,'御定全唐詩/json/270.json','["龍繞旌竿獸滿旗，翻營乍似雪中移。", "中軍一隊三千騎，儘是並州遊俠兒。"]'),
('yuding-83','和李尹種葛','戎昱','唐','御定全唐诗','yuding','','[]','弱質人皆棄，唯君手自栽。藟含霜後竹，香惹臘前梅。',48,'御定全唐詩/json/270.json','["弱質人皆棄，唯君手自栽。藟含霜後竹，香惹臘前梅。", "擬托淩雲勢，須憑接引材。清陰如可惜，黃鳥定飛來。"]'),
('yuding-84','送零陵妓','戎昱','唐','御定全唐诗','yuding','','[]','寶鈿香蛾翡翠裙，裝成掩泣欲行雲。',32,'御定全唐詩/json/270.json','["寶鈿香蛾翡翠裙，裝成掩泣欲行雲。", "殷勤好取襄王意，莫向陽臺夢使君。"]'),
('yuding-85','採蓮曲二首','戎昱','唐','御定全唐诗','yuding','','[]','雖聽採蓮曲，詎識採蓮心。漾楫愛花遠，回船愁浪深。',80,'御定全唐詩/json/270.json','["雖聽採蓮曲，詎識採蓮心。漾楫愛花遠，回船愁浪深。", "煙生極浦色，日落半江陰。同侶憐波靜，看妝墮玉簪。", "涔陽女兒花滿頭，毿毿同泛木蘭舟。", "秋風日暮南湖裏，爭唱菱歌不肯休。"]'),
('yuding-86','塞上曲','戎昱','唐','御定全唐诗','yuding','','[]','胡風略地燒連山，碎葉孤城未下關。',32,'御定全唐詩/json/270.json','["胡風略地燒連山，碎葉孤城未下關。", "山頭烽子聲聲叫，知是將軍夜獵還。"]'),
('yuding-87','寂上人禪房','戎昱','唐','御定全唐诗','yuding','','[]','俗塵浮垢閉禪關，百歲身心幾日閑。',32,'御定全唐詩/json/270.json','["俗塵浮垢閉禪關，百歲身心幾日閑。", "安得此生同草木，無營長在四時間。"]'),
('yuding-88','桂州口號','戎昱','唐','御定全唐诗','yuding','','[]','畫角三聲動客愁，曉霜如雪覆江樓。',32,'御定全唐詩/json/270.json','["畫角三聲動客愁，曉霜如雪覆江樓。", "誰道桂林風景暖，到來重著皂貂裘。"]'),
('yuding-89','紅槿花','戎昱','唐','御定全唐诗','yuding','','[]','花是深紅葉麹塵，不將桃李共爭春。',32,'御定全唐詩/json/270.json','["花是深紅葉麹塵，不將桃李共爭春。", "今日驚秋自憐客，折來持贈少年人。"]'),
('yuding-90','哭黔中薛大夫','戎昱','唐','御定全唐诗','yuding','','[]','亞相何年鎮百蠻，生涯萬事瘴雲間。',32,'御定全唐詩/json/270.json','["亞相何年鎮百蠻，生涯萬事瘴雲間。", "夜郎城外誰人哭，昨日空餘旌節還。"]'),
('yuding-91','感春','戎昱','唐','御定全唐诗','yuding','','[]','看花淚盡知春盡，魂斷看花只恨春。',32,'御定全唐詩/json/270.json','["看花淚盡知春盡，魂斷看花只恨春。", "名位未沾身欲老，詩書寧救眼前貧。"]'),
('yuding-92','途中寄李二','戎昱','唐','御定全唐诗','yuding','','[]','楊柳煙含灞岸春，年年攀折為行人。',32,'御定全唐詩/json/270.json','["楊柳煙含灞岸春，年年攀折為行人。", "好風若借低枝便，莫遣青絲掃路塵。"]'),
('yuding-93','寄許煉師','戎昱','唐','御定全唐诗','yuding','','[]','掃石焚香禮碧空，露華偏濕蕊珠宮。',32,'御定全唐詩/json/270.json','["掃石焚香禮碧空，露華偏濕蕊珠宮。", "如何說得天壇上，萬里無雲月正中。"]'),
('yuding-94','下第留辭顧侍郎','戎昱','唐','御定全唐诗','yuding','','[]','綺陌彤彤花照塵，王門侯邸盡朱輪。',32,'御定全唐詩/json/270.json','["綺陌彤彤花照塵，王門侯邸盡朱輪。", "城南舊有山村路，欲向雲霞覓主人。"]'),
('yuding-95','題雲公山房','戎昱','唐','御定全唐诗','yuding','','[]','雲公蘭若深山裏，月明松殿微風起。',32,'御定全唐詩/json/270.json','["雲公蘭若深山裏，月明松殿微風起。", "試問空門清淨心，蓮花不著秋潭水。"]'),
('yuding-96','別離作','戎昱','唐','御定全唐诗','yuding','','[]','手把杏花枝，未曾經別離。黃昏掩門後，寂寞自心知。',24,'御定全唐詩/json/270.json','["手把杏花枝，未曾經別離。黃昏掩門後，寂寞自心知。"]'),
('yuding-97','九日賈明府見訪','戎昱','唐','御定全唐诗','yuding','','[]','獨掩衡門秋景閑，洛陽才子訪柴關。莫嫌濁酒君須醉，',40,'御定全唐詩/json/270.json','["獨掩衡門秋景閑，洛陽才子訪柴關。莫嫌濁酒君須醉，", "卻笑孟嘉吹帽落，登高何必上龍山。"]'),
('yuding-98','開元觀陪杜大夫中元日觀樂','戎昱','唐','御定全唐诗','yuding','','[]','今朝歡稱玉京天，況值關東俗理年。舞態疑回紫陽女，',40,'御定全唐詩/json/270.json','["今朝歡稱玉京天，況值關東俗理年。舞態疑回紫陽女，", "落日香塵擁歸騎，□風油幕動高煙。"]'),
('yuding-99','中秋夜登樓望月寄人','戎昱','唐','御定全唐诗','yuding','','[]','西樓見月似江城，脈脈悠悠倚檻情。萬里此情同皎潔，',40,'御定全唐詩/json/270.json','["西樓見月似江城，脈脈悠悠倚檻情。萬里此情同皎潔，", "知稱玉人臨水見，可憐光彩有餘清。"]'),
('yuding-100','贈宜陽張使君','戎昱','唐','御定全唐诗','yuding','','[]','暫作宜陽客，深知太守賢。政移千里俗，人戴兩重天。',48,'御定全唐詩/json/270.json','["暫作宜陽客，深知太守賢。政移千里俗，人戴兩重天。", "舊郭多新室，閑坡盡辟田。倘令黃霸在，今日恥同年。"]'),
('yuding-101','移家別樹','戎昱','唐','御定全唐诗','yuding','','[]','千種庭前樹，人移樹不移。看花愁作別，不及未栽時。',24,'御定全唐詩/json/270.json','["千種庭前樹，人移樹不移。看花愁作別，不及未栽時。"]'),
('yuding-102','成都送嚴十五之江東','戎昱','唐','御定全唐诗','yuding','','[]','江東萬里外，別後幾淒淒。峽路花應發，津亭柳正齊。',48,'御定全唐詩/json/270.json','["江東萬里外，別後幾淒淒。峽路花應發，津亭柳正齊。", "酒傾遲日暮，川闊遠天低。心系征帆上，隨君到剡溪。"]'),
('yuding-103','送李參軍','戎昱','唐','御定全唐诗','yuding','','[]','好住好住王司戶，珍重珍重李參軍。一東一西如別鶴，',40,'御定全唐詩/json/270.json','["好住好住王司戶，珍重珍重李參軍。一東一西如別鶴，", "別易會難今古事，非是餘今獨與君。"]'),
('yuding-104','題嚴氏竹亭','戎昱','唐','御定全唐诗','yuding','','[]','子陵棲遁處，堪系野人心。溪水浸山影，嵐煙向竹陰。',48,'御定全唐詩/json/270.json','["子陵棲遁處，堪系野人心。溪水浸山影，嵐煙向竹陰。", "忘機看白日，留客醉瑤琴。愛此多詩興，歸來步步吟。"]'),
('yuding-105','送王端公之太原歸覲相公','戎昱','唐','御定全唐诗','yuding','','[]','柱史今何適，西行詠陟岡。也知人惜別，終美雁成行。',48,'御定全唐詩/json/270.json','["柱史今何適，西行詠陟岡。也知人惜別，終美雁成行。", "春雨桃花靜，離尊竹葉香。到時丞相閣，應喜棣華芳。"]'),
('yuding-106','旅次寄湖南張郎中','戎昱','唐','御定全唐诗','yuding','','[]','寒江近戶漫流聲，竹影臨窗亂月明。',32,'御定全唐詩/json/270.json','["寒江近戶漫流聲，竹影臨窗亂月明。", "歸夢不知湖水闊，夜來還到洛陽城。"]'),
('yuding-107','晚次荊江','戎昱','唐','御定全唐诗','yuding','','[]','孤舟大江水，水涉無昏曙。雨暗迷津時，雲生望鄉處。',72,'御定全唐詩/json/270.json','["孤舟大江水，水涉無昏曙。雨暗迷津時，雲生望鄉處。", "漁翁閑自樂，樵客紛多慮。秋色湖上山，歸心日邊樹。", "徒稱竹箭美，未得楓林趣。向夕垂釣還，吾從落潮去。"]'),
('yuding-108','同辛兗州巢父虛副端岳相思獻酬之作因紓歸懷兼呈辛魏二院長楊長寧','戎昱','唐','御定全唐诗','yuding','','[]','暮角發高城，情人坐中起。臨觴不及醉，分散秋風裏。',84,'御定全唐詩/json/270.json','["暮角發高城，情人坐中起。臨觴不及醉，分散秋風裏。", "雖有明月期，離心若千里。前歡反惆悵，後會還如此。", "焉得夜淹留，一回終宴喜。羈遊複牽役，館至重湖水。", "早晚泛歸舟，吾從數君子。"]'),
('yuding-109','撫州處士湖泛舟送北回兩指此南昌縣查溪蘭若別','戎昱','唐','御定全唐诗','yuding','','[]','移樽鋪山曲，祖帳查溪陰。鋪山即遠道，查溪非故林。',72,'御定全唐詩/json/270.json','["移樽鋪山曲，祖帳查溪陰。鋪山即遠道，查溪非故林。", "淒然誦新詩，落淚沾素襟。郡政我何有，別情君獨深。", "禪庭古樹秋，宿雨清沉沉。揮袂故里遠，悲傷去住心。"]'),
('yuding-110','耒陽溪夜行','戎昱','唐','御定全唐诗','yuding','','[]','乘夕棹歸舟，緣源二轉幽。月明看嶺樹，風靜聽溪流。',48,'御定全唐詩/json/270.json','["乘夕棹歸舟，緣源二轉幽。月明看嶺樹，風靜聽溪流。", "嵐氣船間入，霜華衣上浮。猿聲雖此夜，不是別家愁。"]'),
('yuding-111','桂城早秋','戎昱','唐','御定全唐诗','yuding','','[]','遠客驚秋早，江天夜露新。滿庭惟有月，空館更何人。',48,'御定全唐詩/json/270.json','["遠客驚秋早，江天夜露新。滿庭惟有月，空館更何人。", "蔔命知身賤，傷寒舞劍頻。猿啼曾下淚，可是為憂貧。"]'),
('yuding-112','桂州歲暮','戎昱','唐','御定全唐诗','yuding','','[]','歲暮天涯客，寒窗欲曉時。君恩空自感，鄉思夢先知。',48,'御定全唐詩/json/270.json','["歲暮天涯客，寒窗欲曉時。君恩空自感，鄉思夢先知。", "重誼人愁別，驚棲鵲戀枝。不堪樓上角，南向海風吹。"]'),
('yuding-113','宿桂州江亭呈康端公','戎昱','唐','御定全唐诗','yuding','','[]','獨向東亭坐，三更待月開。螢光入竹去，水影過江來。',48,'御定全唐詩/json/270.json','["獨向東亭坐，三更待月開。螢光入竹去，水影過江來。", "露滴千家靜，年流一葉催。龍鍾萬里客，正合故人哀。"]'),
('yuding-0','寒食日恩賜火','竇叔向','唐','御定全唐诗','yuding','','[]','恩光及小臣，華燭忽驚春。電影隨中使，星輝拂路人。',36,'御定全唐詩/json/271.json','["恩光及小臣，華燭忽驚春。電影隨中使，星輝拂路人。", "幸因榆柳暖，一照草茅貧。"]'),
('yuding-1','端午日恩賜百索','竇叔向','唐','御定全唐诗','yuding','','[]','仙宮長命縷，端午降殊私。事盛蛟龍見，恩深犬馬知。',36,'御定全唐詩/json/271.json','["仙宮長命縷，端午降殊私。事盛蛟龍見，恩深犬馬知。", "餘生倘可續，終冀答明時。"]'),
('yuding-2','貞懿皇后挽歌三首','竇叔向','唐','御定全唐诗','yuding','','[]','二陵恭婦道，六寢盛皇情。禮遜生前貴，恩追歿後榮。',96,'御定全唐詩/json/271.json','["二陵恭婦道，六寢盛皇情。禮遜生前貴，恩追歿後榮。", "幼王親捧土，愛女複邊塋。東望長如在，誰雲向玉京。", "後庭攀畫柳，上陌咽清笳。命婦羞蘋葉，都人插柰花。", "壽宮星月異，仙路往來賒。縱有迎仙術，終悲隔絳紗。"]'),
('yuding-3','秋砧送邑大夫','竇叔向','唐','御定全唐诗','yuding','','[]','斷續長門下，清泠逆旅秋。征夫應待信，寒女不勝愁。',48,'御定全唐詩/json/271.json','["斷續長門下，清泠逆旅秋。征夫應待信，寒女不勝愁。", "帶月飛城上，因風散陌頭。離居偏入聽，況複送歸舟。"]'),
('yuding-4','過擔石湖','竇叔向','唐','御定全唐诗','yuding','','[]','曉發漁門戍，晴看擔石湖。日銜高浪出，天入四空無。',48,'御定全唐詩/json/271.json','["曉發漁門戍，晴看擔石湖。日銜高浪出，天入四空無。", "尺寸分洲島，纖毫指舳艫。渺然從此去，誰念客帆孤。"]'),
('yuding-5','春日早朝應制','竇叔向','唐','御定全唐诗','yuding','','[]','紫殿俯千官，春松應合歡。禦爐香焰暖，馳道玉聲寒。',48,'御定全唐詩/json/271.json','["紫殿俯千官，春松應合歡。禦爐香焰暖，馳道玉聲寒。", "乳燕翻珠綴，祥烏集露盤。宮花一萬樹，不敢舉頭看。"]'),
('yuding-6','酬李袁州嘉佑','竇叔向','唐','御定全唐诗','yuding','','[]','少年輕會複輕離，老大關心總是悲。強說前程聊自慰，',40,'御定全唐詩/json/271.json','["少年輕會複輕離，老大關心總是悲。強說前程聊自慰，", "想到長安誦佳句，滿朝誰不念瓊枝。"]'),
('yuding-7','夏夜宿表兄話舊','竇叔向','唐','御定全唐诗','yuding','','[]','夜合花開香滿庭，夜深微雨醉初醒。遠書珍重何曾達，',40,'御定全唐詩/json/271.json','["夜合花開香滿庭，夜深微雨醉初醒。遠書珍重何曾達，", "明朝又是孤舟別，愁見河橋酒幔青。"]'),
('yuding-8','句','竇叔向','唐','御定全唐诗','yuding','','[]','禁兵環素帟，宮女哭寒雲。',13,'御定全唐詩/json/271.json','["禁兵環素帟，宮女哭寒雲。", "。"]'),
('yuding-9','晚次方山精舍卻寄張薦員外','竇常','唐','御定全唐诗','yuding','','[]','楚臘還無雪，江春又足風。馬羸三徑外，人病四愁中。',48,'御定全唐詩/json/271.json','["楚臘還無雪，江春又足風。馬羸三徑外，人病四愁中。", "西塞波濤闊，南朝寺舍空。猶銜步兵酒，宿醉在除東。"]'),
('yuding-10','和裴端公樞蕪城秋夕簡遠近親知','竇常','唐','御定全唐诗','yuding','','[]','歲積登朝戀，秋加陋巷貧。宿酲因夜歇，佳句得愁新。',48,'御定全唐詩/json/271.json','["歲積登朝戀，秋加陋巷貧。宿酲因夜歇，佳句得愁新。", "盡日憑幽幾，何時上軟輪。漢廷風憲在，應念匪躬人。"]'),
('yuding-11','項亭懷古','竇常','唐','御定全唐诗','yuding','','[]','力取誠多難，天亡路亦窮。有心裁帳下，無面到江東。',48,'御定全唐詩/json/271.json','["力取誠多難，天亡路亦窮。有心裁帳下，無面到江東。", "命厄留騅處，年銷逐鹿中。漢家神器在，須廢拔山功。"]'),
('yuding-12','奉使西還早發小澗館寄盧滁州邁','竇常','唐','御定全唐诗','yuding','','[]','野棠花覆地，山館夜來陰。馬跡穿雲去，雞聲出澗深。',48,'御定全唐詩/json/271.json','["野棠花覆地，山館夜來陰。馬跡穿雲去，雞聲出澗深。", "清風時偃草，久旱或為霖。試與惸嫠話，猶堅借寇心。"]'),
('yuding-13','早發金鉤店寄奚十唐大二茂才','竇常','唐','御定全唐诗','yuding','','[]','出門山未曙，風葉暗蕭蕭。月影臨荒柵，泉聲近廢橋。',48,'御定全唐詩/json/271.json','["出門山未曙，風葉暗蕭蕭。月影臨荒柵，泉聲近廢橋。", "歲經秋後役，程在洛中遙。寄謝金門侶，弓旌誤見招。"]'),
('yuding-14','途中立春寄楊郇伯','竇常','唐','御定全唐诗','yuding','','[]','浪跡終年客，驚心此地春。風前獨去馬，澤畔耦耕人。',48,'御定全唐詩/json/271.json','["浪跡終年客，驚心此地春。風前獨去馬，澤畔耦耕人。", "老大交情重，悲涼外物親。子雲今在宅，應見柳條新。"]'),
('yuding-15','故秘監丹陽郡公延陵包公挽歌詞','竇常','唐','御定全唐诗','yuding','','[]','卓絕明時第，孤貞貴後貧。郤詵為胄子，季劄是鄉人。',48,'御定全唐詩/json/271.json','["卓絕明時第，孤貞貴後貧。郤詵為胄子，季劄是鄉人。", "筆下調金石，花開領搢紳。那堪歸葬日，哭渡柳楊津。"]'),
('yuding-16','涼國惠康公主挽歌','竇常','唐','御定全唐诗','yuding','','[]','玉立分堯緒，笄年下相門。早加於氏對，偏占館陶恩。',48,'御定全唐詩/json/271.json','["玉立分堯緒，笄年下相門。早加於氏對，偏占館陶恩。", "淚有潛成血，香無卻返魂。共知何駙馬，垂白抱天孫。"]'),
('yuding-17','哭張倉曹南史','竇常','唐','御定全唐诗','yuding','','[]','萬事竟蹉跎，重泉恨若何。官臨環衛小，身逐轉蓬多。',48,'御定全唐詩/json/271.json','["萬事竟蹉跎，重泉恨若何。官臨環衛小，身逐轉蓬多。", "麗藻嘗專席，閒情欲爛柯。春風宛陵路，丹旐在滄波。"]'),
('yuding-18','北固晚眺','竇常','唐','御定全唐诗','yuding','','[]','水國芒種後，梅天風雨涼。露蠶開晚簇，江燕繞危檣。',48,'御定全唐詩/json/271.json','["水國芒種後，梅天風雨涼。露蠶開晚簇，江燕繞危檣。", "山趾北來固，潮頭西去長。年年此登眺，人事幾銷亡。"]'),
('yuding-19','謁三閭廟','竇常','唐','御定全唐诗','yuding','','[]','君非三諫寤，禮許一身逃。自樹終天戚，何裨事主勞。',48,'御定全唐詩/json/271.json','["君非三諫寤，禮許一身逃。自樹終天戚，何裨事主勞。", "眾魚應餌骨，多士盡餔糟。有客椒漿奠，文衰不繼騷。"]'),
('yuding-20','茅山贈梁尊師','竇常','唐','御定全唐诗','yuding','','[]','雲屋何年客，青山白日長。種花春掃雪，看籙夜焚香。',48,'御定全唐詩/json/271.json','["雲屋何年客，青山白日長。種花春掃雪，看籙夜焚香。", "上象壺中闊，平生醉裏忙。幸承仙籍後，乞取大還方。"]'),
('yuding-21','謁諸葛武侯廟','竇常','唐','御定全唐诗','yuding','','[]','永安宮外有祠堂，魚水恩深祚不長。角立一方初退舍，',40,'御定全唐詩/json/271.json','["永安宮外有祠堂，魚水恩深祚不長。角立一方初退舍，", "歸蜀降吳竟何事，為陵為穀共蒼蒼。"]'),
('yuding-22','奉賀太保岐公承恩致政','竇常','唐','御定全唐诗','yuding','','[]','君為宮保及清時，冠蓋初閑拜武遲。五色詔中宣九德，',40,'御定全唐詩/json/271.json','["君為宮保及清時，冠蓋初閑拜武遲。五色詔中宣九德，", "不學鑄金思範蠡，乞言猶許上丹墀。"]'),
('yuding-23','之任武陵，寒食日途次松滋渡，先寄劉員外禹錫','竇常','唐','御定全唐诗','yuding','','[]','杏花榆莢曉風前，雲際離離上峽船。江轉數程淹驛騎，',40,'御定全唐詩/json/271.json','["杏花榆莢曉風前，雲際離離上峽船。江轉數程淹驛騎，", "幸得柱山當郡舍，在朝長詠卜居篇。"]'),
('yuding-24','奉寄辰州房使君郎中','竇常','唐','御定全唐诗','yuding','','[]','漢代文明今盛明，猶將賈傅暫專城。何妨密旨先符竹，',40,'御定全唐詩/json/271.json','["漢代文明今盛明，猶將賈傅暫專城。何妨密旨先符竹，", "新年只可三十二，卻笑潘郎白髮生。"]'),
('yuding-25','立春後言懷招汴州李匡衙推','竇常','唐','御定全唐诗','yuding','','[]','閑齋夜擊唾壺歌，試望夷門奈遠何。每聽寒笳離夢斷，',40,'御定全唐詩/json/271.json','["閑齋夜擊唾壺歌，試望夷門奈遠何。每聽寒笳離夢斷，", "海內故人君最老，花開鞭馬更相過。"]'),
('yuding-26','奉送職方崔員外攝中丞新羅冊使','竇常','唐','御定全唐诗','yuding','','[]','帝命海東使，人行天一涯。辨方知木德，開國有金家。',96,'御定全唐詩/json/271.json','["帝命海東使，人行天一涯。辨方知木德，開國有金家。", "冊拜申恩重，留歡作限賒。順風鯨浪熱，初日錦帆斜。", "夜色潛然火，秋期獨往槎。慰安皆喻旨，忠信自無瑕。", "發美童年髻，簪香子月花。便隨琛贐入，正朔在中華。"]'),
('yuding-27','酬舍弟牟秋日洛陽官舍寄懷十韻','竇常','唐','御定全唐诗','yuding','','[]','幼為逃難者，才省用兵初。去國三苗外，全生四紀餘。',120,'御定全唐詩/json/271.json','["幼為逃難者，才省用兵初。去國三苗外，全生四紀餘。", "老頭親帝裏，歸處失吾廬。逝水猶嗚咽，祥雲自卷舒。", "正郎曾首拜，亞尹未平除。幾變陶家柳，空傳魏闕書。", "思淩天際鶴，言甚轍中魚。玉立知求己，金聲乍起予。", "在朝魚水分，多病雪霜居。忽報陽春曲，縱橫恨不如。"]'),
('yuding-28','求自試','竇常','唐','御定全唐诗','yuding','','[]','仙禁祥雲合，高梧彩鳳遊。沈冥求自試，通鑒果蒙收。',72,'御定全唐詩/json/271.json','["仙禁祥雲合，高梧彩鳳遊。沈冥求自試，通鑒果蒙收。", "文墨悲無位，詩書誤白頭。陳王抗表日，毛遂請行秋。", "雙劍曾埋獄，司空問鬥牛。希垂拂拭惠，感激願相投。"]'),
('yuding-29','花發上林','竇常','唐','御定全唐诗','yuding','','[]','上苑曉沉沉，花枝亂綴陰。色浮雙闕近，春入九門深。',72,'御定全唐詩/json/271.json','["上苑曉沉沉，花枝亂綴陰。色浮雙闕近，春入九門深。", "向暖風初扇，餘寒雪尚侵。豔回秦女目，愁處越人心。", "繞繞時縈蝶，關關乍引禽。甯知幽谷羽，一舉欲依林。"]'),
('yuding-30','過宋氏五女舊居','竇常','唐','御定全唐诗','yuding','','[]','謝庭風韻婕妤才，天縱斯文去不回。',32,'御定全唐詩/json/271.json','["謝庭風韻婕妤才，天縱斯文去不回。", "一宅柳花今似雪，鄉人擬築望仙台。"]'),
('yuding-31','還京樂歌詞','竇常','唐','御定全唐诗','yuding','','[]','百戰初休十萬師，國人西望翠華時。',32,'御定全唐詩/json/271.json','["百戰初休十萬師，國人西望翠華時。", "家家盡唱升平曲，帝幸梨園親制詞。"]'),
('yuding-32','商山祠堂即事','竇常','唐','御定全唐诗','yuding','','[]','奪嫡心萌事可憂，四賢西笑暫安劉。',32,'御定全唐詩/json/271.json','["奪嫡心萌事可憂，四賢西笑暫安劉。", "後王不敢論珪組，土偶人前枳樹秋。"]'),
('yuding-33','七夕','竇常','唐','御定全唐诗','yuding','','[]','露盤花水望三星，仿佛虛無為降靈。',32,'御定全唐詩/json/271.json','["露盤花水望三星，仿佛虛無為降靈。", "斜漢沒時人不寐，幾條蛛網下風庭。"]'),
('yuding-34','杏山館聽子規','竇常','唐','御定全唐诗','yuding','','[]','楚塞餘春聽漸稀，斷猿今夕讓沾衣。',32,'御定全唐詩/json/271.json','["楚塞餘春聽漸稀，斷猿今夕讓沾衣。", "雲埋老樹空山裏，仿佛千聲一度飛。"]'),
('yuding-35','史館候別蔣拾遺不遇','竇牟','唐','御定全唐诗','yuding','','[]','千門萬戶迷，佇立月華西。畫戟晨光動，春松宿露低。',48,'御定全唐詩/json/271.json','["千門萬戶迷，佇立月華西。畫戟晨光動，春松宿露低。", "主文親玉扆，通籍入金閨。肯念從戎去，風沙事鼓鼙。"]'),
('yuding-36','早赴臨台立馬待漏口號寄弟群','竇牟','唐','御定全唐诗','yuding','','[]','上陌行初盡，嚴城立未開。人疑早朝去，客是遠方來。',48,'御定全唐詩/json/271.json','["上陌行初盡，嚴城立未開。人疑早朝去，客是遠方來。", "伏奏徒將命，周行自引才。可憐霄漢曙，鴛鷺正徘徊。"]'),
('yuding-37','緱氏拜陵回道中呈李舍人少尹','竇牟','唐','御定全唐诗','yuding','','[]','忽忝諸卿位，仍陪長者車。禮容皆若舊，名籍自憑虛。',48,'御定全唐詩/json/271.json','["忽忝諸卿位，仍陪長者車。禮容皆若舊，名籍自憑虛。", "上路花偏早，空山雲甚餘。卻愁新詠發，酬和不相如。"]'),
('yuding-38','陪韓院長韋河南同尋劉師不遇','竇牟','唐','御定全唐诗','yuding','','[]','仙客誠難訪，吾人豈易同。獨游應駐景，相顧且吟風。',48,'御定全唐詩/json/271.json','["仙客誠難訪，吾人豈易同。獨游應駐景，相顧且吟風。", "藥畹瓊枝秀，齋軒粉壁空。不題三五字，何以達壺公。"]'),
('yuding-39','送東光呂少府之官連帥奏授','竇牟','唐','御定全唐诗','yuding','','[]','遠愛東光縣，平臨若木津。一城先見日，百里早驚春。',48,'御定全唐詩/json/271.json','["遠愛東光縣，平臨若木津。一城先見日，百里早驚春。", "德禮邀才重，恩輝拜命新。幾時裁尺素，滄海有枯鱗。"]'),
('yuding-40','送劉公達判官赴天德軍幕','竇牟','唐','御定全唐诗','yuding','','[]','特建青油幕，量分紫禁師。自然知召子，不用問從誰。',48,'御定全唐詩/json/271.json','["特建青油幕，量分紫禁師。自然知召子，不用問從誰。", "文武輕車少，腥膻左衽衰。北風如有寄，畫取受降時。"]'),
('yuding-41','故秘監丹陽郡公延陵包公挽歌','竇牟','唐','御定全唐诗','yuding','','[]','台鼎嘗虛位，夔龍莫致堯。德音冥秘府，風韻散清朝。',48,'御定全唐詩/json/271.json','["台鼎嘗虛位，夔龍莫致堯。德音冥秘府，風韻散清朝。", "天上文星落，林端玉樹凋。有吳君子墓，返葬故山遙。"]'),
('yuding-42','望終南','竇牟','唐','御定全唐诗','yuding','','[]','日愛南山好，時逢夏景殘。白雲兼似雪，清晝乍生寒。',48,'御定全唐詩/json/271.json','["日愛南山好，時逢夏景殘。白雲兼似雪，清晝乍生寒。", "九陌峰如墜，千門翠可團。欲知形勝盡，都在紫宸看。"]'),
('yuding-43','秋夕閒居對雨贈別盧七侍禦坦','竇牟','唐','御定全唐诗','yuding','','[]','燕燕辭巢蟬蛻枝，窮居積雨壞藩籬。夜長簷溜寒無寢，',40,'御定全唐詩/json/271.json','["燕燕辭巢蟬蛻枝，窮居積雨壞藩籬。夜長簷溜寒無寢，", "故人驄馬朝天使，洛下秋聲恐要知。"]'),
('yuding-44','晚過敷水驛卻寄華州使院張鄭二侍禦','竇牟','唐','御定全唐诗','yuding','','[]','春雨如煙又若絲，曉來昏處晚晴時。仙人掌上芙蓉沼，',40,'御定全唐詩/json/271.json','["春雨如煙又若絲，曉來昏處晚晴時。仙人掌上芙蓉沼，", "回瞻二妙非吾侶，日對三峰自有期。"]'),
('yuding-45','洛下閒居夜晴觀雪寄四遠諸兄弟','竇牟','唐','御定全唐诗','yuding','','[]','雪月相輝雲四開，終風助凍不揚埃。萬重瓊樹宮中接，',40,'御定全唐詩/json/271.json','["雪月相輝雲四開，終風助凍不揚埃。萬重瓊樹宮中接，", "強題縑素無顏色，鴻雁南飛早晚回。"]'),
('yuding-46','天津曉望因寄呈分司一二省郎','竇牟','唐','御定全唐诗','yuding','','[]','萬乘西都去，千門正位虛。鑿龍橫碧落，提象出華胥。',72,'御定全唐詩/json/271.json','["萬乘西都去，千門正位虛。鑿龍橫碧落，提象出華胥。", "望幸宮嬪老，迎春海燕初。保厘才半仗，容衛盡空廬。", "要自詞難擬，繇來畫不如。散郎無所屬，聊事穆清居。"]'),
('yuding-47','早入朝書事','竇牟','唐','御定全唐诗','yuding','','[]','紫陌紛如畫，彤庭鬱未晨。列星沈騎火，殘月暗車塵。',72,'御定全唐詩/json/271.json','["紫陌紛如畫，彤庭鬱未晨。列星沈騎火，殘月暗車塵。", "隱軫排霄翰，差池跨海鱗。玉聲繁似樂，香澤散成春。", "歎息驅羸馬，分明識故人。一生三不遇，今作老郎身。"]'),
('yuding-48','元日喜聞大禮寄上翰林四學士中書六舍人二十韻','竇牟','唐','御定全唐诗','yuding','','[]','有事郊壇畢，無私日月臨。歲華春更早，天瑞雪猶深。',241,'御定全唐詩/json/271.json','["有事郊壇畢，無私日月臨。歲華春更早，天瑞雪猶深。", "玉輦回時令，金門降德音。翰飛鴛別侶，叢植桂為林。", "粉澤資鴻筆，熏和本素琴。禮成戎器下，恩徹鬼方沈。", "麟爵來稱紀，官師退絕箴。道風黃閣靜，祥景紫垣陰。", "壽酒朝時獻，農書夜直尋。國香煴翠幄，庭燎赩紅衾。", "漢魏文章盛，堯湯雨露霃。密辭投水石，精義出沙金。", "宸扆親唯敬，鈞衡近匪侵。疾驅千里駿，清唳九霄禽。", "慶賜迎新服，齋莊棄舊簪。忽思班女怨，遙聽越人吟。", "末路甘貧病，流年苦滯淫。夢中青瑣闥，歸處碧山岑。", "竊抃聞韶濩，觀光想韎任。大哉環海晏，不運算元牟心。"]'),
('yuding-49','奉使至邢州贈李八使君','竇牟','唐','御定全唐诗','yuding','','[]','獨佔龍岡部，深持虎節居。盡心敷吏術，含笑掩兵書。',96,'御定全唐詩/json/271.json','["獨佔龍岡部，深持虎節居。盡心敷吏術，含笑掩兵書。", "禮飾華纓重，才牽雅制餘。茂陰延驛路，溫液逗官渠。", "南畝行春罷，西樓待客初。甕頭開綠蟻，砧下落紅魚。", "牧伯風流足，輶軒若澀虛。今宵鈴閣內，醉舞複何如。"]'),
('yuding-50','秋日洛陽官舍寄上水部家兄','竇牟','唐','御定全唐诗','yuding','','[]','洛陽歸老日，此縣忽為君。白髮兄仍見，丹誠帝豈聞。',120,'御定全唐詩/json/271.json','["洛陽歸老日，此縣忽為君。白髮兄仍見，丹誠帝豈聞。", "九衢橫逝水，二室散浮雲。屈指豪家盡，傷心要地分。", "禁中周幾鼎，源上漢諸墳。貔虎今無半，狐狸宿有群。", "威聲慚北部，仁化樂南熏。野檗饑來食，天香靜處焚。", "壯年唯喜酒，幼學便訶文。及爾空衰暮，離憂詎可聞。"]'),
('yuding-51','李舍人少尹惠家醞一小榼立書絕句','竇牟','唐','御定全唐诗','yuding','','[]','禁瑣天漿嫩，虞行夜月寒。一瓢那可醉，應遣試嘗看。',24,'御定全唐詩/json/271.json','["禁瑣天漿嫩，虞行夜月寒。一瓢那可醉，應遣試嘗看。"]'),
('yuding-52','酬舍弟庠罷舉從州辟書','竇牟','唐','御定全唐诗','yuding','','[]','之荊且願依劉表，折桂終慚見郤詵。',32,'御定全唐詩/json/271.json','["之荊且願依劉表，折桂終慚見郤詵。", "舍弟未應絲作鬢，園公不用印隨身。"]'),
('yuding-53','奉酬楊侍郎十兄見贈之作','竇牟','唐','御定全唐诗','yuding','','[]','翠羽雕蟲日日新，翰林工部欲何神。',32,'御定全唐詩/json/271.json','["翠羽雕蟲日日新，翰林工部欲何神。", "自悲由瑟無彈處，今作關西門下人。"]'),
('yuding-54','杏園渡','竇牟','唐','御定全唐诗','yuding','','[]','衛郊多壘少人家，南渡天寒日又斜。',32,'御定全唐詩/json/271.json','["衛郊多壘少人家，南渡天寒日又斜。", "君子素風悲已矣，杏園無複一枝花。"]'),
('yuding-55','奉誠園聞笛','竇牟','唐','御定全唐诗','yuding','','[]','曾絕朱纓吐錦茵，欲披荒草訪遺塵。',32,'御定全唐詩/json/271.json','["曾絕朱纓吐錦茵，欲披荒草訪遺塵。", "秋風忽灑西園淚，滿目山陽笛裏人。"]'),
('yuding-56','雪中遇直','竇群','唐','御定全唐诗','yuding','','[]','寒光凝雪彩，限直居粉闈。恍疑白雲上，乍覺金印非。',48,'御定全唐詩/json/271.json','["寒光凝雪彩，限直居粉闈。恍疑白雲上，乍覺金印非。", "樹色靄虛空，琴聲諧素徽。明晨阻通籍，獨臥掛朝衣。"]'),
('yuding-57','東山月下懷友人','竇群','唐','御定全唐诗','yuding','','[]','東山多喬木，月午始蒼蒼。雖殊碧海狀，愛此青苔光。',96,'御定全唐詩/json/271.json','["東山多喬木，月午始蒼蒼。雖殊碧海狀，愛此青苔光。", "高下滅華燭，參差啟洞房。佳人夢餘思，寶瑟愁應商。", "皎潔殊未已，沈吟限一方。宦情哂雞口，世路倦羊腸。", "彼美金石分，眷言蘭桂芳。清暉詎同夕，耿耿但相望。"]'),
('yuding-58','時興','竇群','唐','御定全唐诗','yuding','','[]','夙心曠何許，日暮依林薄。流水不待人，孤雲時映鶴。',48,'御定全唐詩/json/271.json','["夙心曠何許，日暮依林薄。流水不待人，孤雲時映鶴。", "濛濛千萬花，曷為神仙藥。不遇爛柯叟，報非舊城郭。"]'),
('yuding-59','題劍','竇群','唐','御定全唐诗','yuding','','[]','丈夫得寶劍，束發曾書紳。嗟籲一朝遇，願言千載鄰。',48,'御定全唐詩/json/271.json','["丈夫得寶劍，束發曾書紳。嗟籲一朝遇，願言千載鄰。", "心許留家樹，辭直斷佞臣。焉能為繞指，拂拭試時人。"]'),
('yuding-60','黔中書事','竇群','唐','御定全唐诗','yuding','','[]','萬事非京國，千山擁麗譙。佩刀看日曬，賜馬傍江調。',48,'御定全唐詩/json/271.json','["萬事非京國，千山擁麗譙。佩刀看日曬，賜馬傍江調。", "言語多重譯，壺觴每獨謠。沿流如著翅，不敢問歸橈。"]'),
('yuding-61','冬日曉思寄楊二十七煉師','竇群','唐','御定全唐诗','yuding','','[]','雨霜地如雪，松桂青參差。鶴警晨光上，步出南軒時。',48,'御定全唐詩/json/271.json','["雨霜地如雪，松桂青參差。鶴警晨光上，步出南軒時。", "所遇各有適，我懷亦自怡。願言緘素封，昨夜夢瓊枝。"]'),
('yuding-62','貞元末東院嘗接事今西川武相公于茲三周謬領中憲徘徊廳宇多獲文篇夏日即事因寄四韻','竇群','唐','御定全唐诗','yuding','','[]','重軒深似谷，列柏鎮含煙。境絕蒼蠅到，風生白雪前。',48,'御定全唐詩/json/271.json','["重軒深似谷，列柏鎮含煙。境絕蒼蠅到，風生白雪前。", "彈冠驚跡近，專席感恩偏。霄漢朝來下，油幢路幾千。"]'),
('yuding-63','北地','竇群','唐','御定全唐诗','yuding','','[]','何事到容州，臨池照白頭。興隨年已往，愁與水長流。',48,'御定全唐詩/json/271.json','["何事到容州，臨池照白頭。興隨年已往，愁與水長流。", "黽勉思逋客，辛勤悔飯牛。詩人亦何意，樹草欲忘憂。"]'),
('yuding-64','雨後月下寄懷羊二十七資州','竇群','唐','御定全唐诗','yuding','','[]','夕霽涼飆至，翛然心賞諧。清光松上月，虛白郡中齋。',48,'御定全唐詩/json/271.json','["夕霽涼飆至，翛然心賞諧。清光松上月，虛白郡中齋。", "置酒平生在，開衿願見乖。殷勤寄雙鯉，夢想入君懷。"]'),
('yuding-65','奉酬西川武相公晨興贈友見示之作','竇群','唐','御定全唐诗','yuding','','[]','碧樹分曉色，宿雨弄清光。猶聞子規啼，獨念一聲長。',96,'御定全唐詩/json/271.json','["碧樹分曉色，宿雨弄清光。猶聞子規啼，獨念一聲長。", "眷眷軫芳思，依依寄遠方。情同如蘭臭，惠比返魂香。", "新什驚變雅，古瑟代沈湘。殷勤見知己，掩抑繞中腸。", "隙駟不我待，路人易相忘。孤老空許國，幽報期蒼蒼。"]'),
('yuding-66','晨游昌師院','竇群','唐','御定全唐诗','yuding','','[]','深庭芳草濃，曉井山泉溢。林馥亂沈煙，石潤侵經室。',72,'御定全唐詩/json/271.json','["深庭芳草濃，曉井山泉溢。林馥亂沈煙，石潤侵經室。", "幽岩鳥飛靜，晴嶺雲歸密。壁蘚凝蒼華，竹陰滿晴日。", "生期半宵夢，憂緒仍非一。若無高世心，安能此終畢。"]'),
('yuding-67','同王晦伯朱遐景宿慧山寺','竇群','唐','御定全唐诗','yuding','','[]','共訪青山寺，曾隱南朝人。問古松桂老，開襟言笑新。',72,'御定全唐詩/json/271.json','["共訪青山寺，曾隱南朝人。問古松桂老，開襟言笑新。", "步移月亦出，水映石磷磷。予洗腸中酒，君濯纓上塵。", "皓彩入幽抱，清氣逼蒼旻。信此澹忘歸，淹留冰玉鄰。"]'),
('yuding-68','草堂夜坐','竇群','唐','御定全唐诗','yuding','','[]','匣中三尺劍，天上少微星。勿謂相去遠，壯心曾不停。',24,'御定全唐詩/json/271.json','["匣中三尺劍，天上少微星。勿謂相去遠，壯心曾不停。"]'),
('yuding-69','經潼關贈宇文十','竇群','唐','御定全唐诗','yuding','','[]','古有弓旌禮，今征草澤臣。方同白衣見，不是棄繻人。',24,'御定全唐詩/json/271.json','["古有弓旌禮，今征草澤臣。方同白衣見，不是棄繻人。"]'),
('yuding-70','觀畫鶴','竇群','唐','御定全唐诗','yuding','','[]','華亭不相識，衛國複誰知。悵望沖天羽，甘心任畫師。',24,'御定全唐詩/json/271.json','["華亭不相識，衛國複誰知。悵望沖天羽，甘心任畫師。"]'),
('yuding-71','晚自台中歸永甯裏南望山色悵然有懷呈上右司十一兄','竇群','唐','御定全唐诗','yuding','','[]','白髮侵侵生有涯，青襟曾愛紫河車。',32,'御定全唐詩/json/271.json','["白髮侵侵生有涯，青襟曾愛紫河車。", "自憐悟主難歸去，馬上看山恐到家。"]'),
('yuding-72','中牟縣經魯公廟','竇群','唐','御定全唐诗','yuding','','[]','青史編名在篋中，故林遺廟揖仁風。',32,'御定全唐詩/json/271.json','["青史編名在篋中，故林遺廟揖仁風。", "還將文字如顏色，暫下蒲車為魯公。"]'),
('yuding-73','初入諫司喜家室至','竇群','唐','御定全唐诗','yuding','','[]','一旦悲歡見孟光，十年辛苦伴滄浪。',32,'御定全唐詩/json/271.json','["一旦悲歡見孟光，十年辛苦伴滄浪。", "不知筆硯緣封事，猶問傭書日幾行。"]'),
('yuding-74','春雨','竇群','唐','御定全唐诗','yuding','','[]','昨日偷閒看花了，今朝多雨奈人何。',32,'御定全唐詩/json/271.json','["昨日偷閒看花了，今朝多雨奈人何。", "人間盡似逢花雨，莫愛芳菲濕綺羅。"]'),
('yuding-75','送內弟袁德師','竇群','唐','御定全唐诗','yuding','','[]','南渡登舟即水仙，西垣有客思悠然。',32,'御定全唐詩/json/271.json','["南渡登舟即水仙，西垣有客思悠然。", "因君相問為官意，不賣毗陵負郭田。"]'),
('yuding-76','贈劉大兄院長','竇群','唐','御定全唐诗','yuding','','[]','萬年枝下昔同趨，三事行中半已無。',32,'御定全唐詩/json/271.json','["萬年枝下昔同趨，三事行中半已無。", "路自長沙忽相見，共驚雙鬢別來殊。"]'),
('yuding-77','假日尋花','竇群','唐','御定全唐诗','yuding','','[]','武陵緣源不可到，河陽帶縣詎堪誇。',32,'御定全唐詩/json/271.json','["武陵緣源不可到，河陽帶縣詎堪誇。", "枝枝如雪南關外，一日休閒盡屬花。"]'),
('yuding-78','自京將赴黔南','竇群','唐','御定全唐诗','yuding','','[]','風雨荊州二月天，問人初雇峽中船。',32,'御定全唐詩/json/271.json','["風雨荊州二月天，問人初雇峽中船。", "西南一望雲和水，猶道黔南有四千。"]'),
('yuding-79','留守府酬皇甫曙侍禦彈琴之什','竇庠','唐','御定全唐诗','yuding','','[]','青瑣晝無塵，碧梧陰似水。高張朱弦琴，靜舉白玉指。',120,'御定全唐詩/json/271.json','["青瑣晝無塵，碧梧陰似水。高張朱弦琴，靜舉白玉指。", "洞簫又奏繁，寒磬一聲起。鶴警風露中，泉飛雪雲裏。", "泠泠分雅鄭，析析諧宮征。座客無俗心，巢禽亦傾耳。", "衛國知有人，齊竽偶相齒。有時趨絳紗，盡日隨朱履。", "那令雜繁手，出假求焦尾。幾載遺正音，今朝自君始。"]'),
('yuding-80','金山行','竇庠','唐','御定全唐诗','yuding','','[]','西江中㵢波四截，湧出一峰青堞㙞。外如削成中缺裂，',168,'御定全唐詩/json/271.json','["西江中㵢波四截，湧出一峰青堞㙞。外如削成中缺裂，", "夜色晨光相蕩沃，積翠流霞滿坑穀。龍泓徹底沙布金，", "斡流倒景不可窺，萬仞千崖生跬步。日華重重上金榜，", "瓊樓菌閣紛明媚，曲檻回軒深且邃。海鳥夜上珊瑚枝，", "不知水上有樓臺，卻就波中看閉啟。舟人忘卻江水深，", "居人相顧非人間，如到日宮經月窟。信知靈境長有靈，", "何如此處靈山宅，清涼不與囂塵隔。曾到金山處處行，"]'),
('yuding-81','于闐鐘歌送靈徹上人歸越','竇庠','唐','御定全唐诗','yuding','','[]','海中有國傾神功，烹金化成九乳鐘。精氣激射聲沖瀜，',96,'御定全唐詩/json/271.json','["海中有國傾神功，烹金化成九乳鐘。精氣激射聲沖瀜，", "不知飛在靈嘉寺，一國之人皆若狂。東南之美天下傳，", "有時清秋日正中，繁霜滿地天無風。一聲洞徹八音盡，", "大鳴小鳴須在君，不擊不考終不聞。高僧訪古稽山曲，"]'),
('yuding-82','太原送穆質南游','竇庠','唐','御定全唐诗','yuding','','[]','今朝天景清，秋入晉陽城。露葉離披處，風蟬三數聲。',48,'御定全唐詩/json/271.json','["今朝天景清，秋入晉陽城。露葉離披處，風蟬三數聲。", "那言苦行役，值此遠徂征。莫話心中事，相看氣不平。"]'),
('yuding-83','四皓驛聽琴送王師簡歸湖南使幕','竇庠','唐','御定全唐诗','yuding','','[]','朱弦韻正調，清夜似聞韶。山館月猶在，松枝雪未消。',48,'御定全唐詩/json/271.json','["朱弦韻正調，清夜似聞韶。山館月猶在，松枝雪未消。", "城笳三奏曉，別鶴一聲遙。明日思君處，春泉翻寂寥。"]'),
('yuding-84','夜行古戰場','竇庠','唐','御定全唐诗','yuding','','[]','山斷塞初平，人言古戰庭。泉冰聲更咽，陰火焰偏青。',48,'御定全唐詩/json/271.json','["山斷塞初平，人言古戰庭。泉冰聲更咽，陰火焰偏青。", "月落雲沙黑，風回草木腥。不知秦與漢，徒欲吊英靈。"]'),
('yuding-85','奉和王侍郎春日喜李侍郎崔給諫張舍人韋諫議見訪因命觴觀樂之什','竇庠','唐','御定全唐诗','yuding','','[]','華館遲嘉賓，逢迎淑景新。錦筵開絳帳，玉佩下朱輪。',48,'御定全唐詩/json/271.json','["華館遲嘉賓，逢迎淑景新。錦筵開絳帳，玉佩下朱輪。", "曲裏三仙會，風前百囀春。欲知忘味處，共仰在齊人。"]'),
('yuding-86','酬謝韋卿二十五兄俯贈輒敢書情','竇庠','唐','御定全唐诗','yuding','','[]','大賢持贈一明璫，蓬蓽初驚滿室光。埋沒劍中生紫氣，',40,'御定全唐詩/json/271.json','["大賢持贈一明璫，蓬蓽初驚滿室光。埋沒劍中生紫氣，", "莫恨伏轅身未老，會將筋力是王良。"]'),
('yuding-87','奉酬侍禦家兄東洛閒居夜晴觀雪之什','竇庠','唐','御定全唐诗','yuding','','[]','洛陽宮觀與天齊，雪淨雲消月未西。清淺乍分銀漢近，',40,'御定全唐詩/json/271.json','["洛陽宮觀與天齊，雪淨雲消月未西。清淺乍分銀漢近，", "應念武關山斷處，空愁簿領候晨雞。"]'),
('yuding-88','敕目至家兄蒙淮南僕射杜公奏授秘校兼節度參謀同書寄上','竇庠','唐','御定全唐诗','yuding','','[]','朝市三千里，園廬二十春。步兵終日飲，原憲四時貧。',96,'御定全唐詩/json/271.json','["朝市三千里，園廬二十春。步兵終日飲，原憲四時貧。", "桂樹留人久，蓬山入夢新。鶴書承處重，鵲語喜時頻。", "草奏才偏委，嘉謀事最親。榻因徐孺解，醴為穆生陳。", "衛國今多士，荊州好寄身。煙霄定從此，非假問陶鈞。"]'),
('yuding-89','酬韓愈侍郎登岳陽樓見贈','竇庠','唐','御定全唐诗','yuding','','[]','巨浸連空闊，危樓在杳冥。稍分巴子國，欲近老人星。',240,'御定全唐詩/json/271.json','["巨浸連空闊，危樓在杳冥。稍分巴子國，欲近老人星。", "昏旦呈新候，川原按舊經。地圖封七澤，天限鎖重扃。", "萬象皆歸掌，三光豈遁形。月車才碾浪，日禦已翻溟。", "落照金成柱，餘霞翠擁屏。夜光疑漢曲，寒韻辨湘靈。", "山晚雲常碧，湖春草遍青。軒黃曾舉樂，範蠡幾揚舲。", "有客初留鷁，貪程尚數蓂。自當徐孺榻，不是謝公亭。", "雅論冰生水，雄材刃發硎。座中瓊玉潤，名下茝蘭馨。", "假手誠知拙，齋心匪暫寧。每慚公府粟，卻憶故山苓。", "苦調當三歎，知音願一聽。自悲由也瑟，敢墜孔悝銘。", "野杏初成雪，松醪正滿瓶。莫辭今日醉，長恨古人醒。"]'),
('yuding-90','東都嘉量亭獻留守韓僕射','竇庠','唐','御定全唐诗','yuding','','[]','蔔築三川上，儀刑萬井中。度材垂後儉，選勝掩前功。',168,'御定全唐詩/json/271.json','["蔔築三川上，儀刑萬井中。度材垂後儉，選勝掩前功。", "雲構中央起，煙波四面通。乍疑遊汗漫，稍似入崆峒。", "廛閈高低盡，山河表裏窮。峰巒從地碧，宮觀倚天紅。", "靈檻如朝蜃，飛橋狀晚虹。曙霞晴錯落，夕靄濕蔥蘢。", "庾亮樓何厄，陳蕃榻更崇。有時閑講德，永日靜觀風。", "玉斝飛無算，金鐃奏未終。重筵開玳瑁，上客集鵷鴻。", "接武空慚蹇，修文敢並雄。豈須登峴首，然後奉羊公。"]'),
('yuding-91','段都尉別業','竇庠','唐','御定全唐诗','yuding','','[]','曾識將軍段匹磾，幾場花下醉如泥。',32,'御定全唐詩/json/271.json','["曾識將軍段匹磾，幾場花下醉如泥。", "春來欲問林園主，桃李無言鳥自啼。"]'),
('yuding-92','靈台鎮贈丘岑中丞','竇庠','唐','御定全唐诗','yuding','','[]','曉日天山雪半晴，紅旗遙識漢家營。',32,'御定全唐詩/json/271.json','["曉日天山雪半晴，紅旗遙識漢家營。", "近來胡騎休南牧，羊馬城邊春草生。"]'),
('yuding-93','贈道芬上人','竇庠','唐','御定全唐诗','yuding','','[]','雲濕煙封不可窺，畫時唯有鬼神知。',32,'御定全唐詩/json/271.json','["雲濕煙封不可窺，畫時唯有鬼神知。", "幾回逢著天臺客，認得岩西最老枝。"]'),
('yuding-94','金山寺','竇庠','唐','御定全唐诗','yuding','','[]','一點青螺白浪中，全依水府與天通。',32,'御定全唐詩/json/271.json','["一點青螺白浪中，全依水府與天通。", "晴江萬里雲飛盡，鼇背參差日氣紅。"]'),
('yuding-95','冬夜寓懷寄王翰林','竇庠','唐','御定全唐诗','yuding','','[]','滿地霜蕪葉下枝，幾回吟斷四愁詩。',32,'御定全唐詩/json/271.json','["滿地霜蕪葉下枝，幾回吟斷四愁詩。", "漢家若欲論封禪，須及相如未病時。"]'),
('yuding-96','醉中贈符載','竇庠','唐','御定全唐诗','yuding','','[]','白社會中嘗共醉，青雲路上未相逢。',32,'御定全唐詩/json/271.json','["白社會中嘗共醉，青雲路上未相逢。", "時人莫小池中水，淺處無妨有臥龍。"]'),
('yuding-97','龍門看花','竇庠','唐','御定全唐诗','yuding','','[]','無葉無枝不見空，連天撲地徑才通。',32,'御定全唐詩/json/271.json','["無葉無枝不見空，連天撲地徑才通。", "山鶯驚起酒醒處，火焰燒人雪噴風。"]'),
('yuding-98','陪留守韓僕射巡內至上陽宮感興二首','竇庠','唐','御定全唐诗','yuding','','[]','翠輦西歸七十春，玉堂珠綴儼埃塵。',64,'御定全唐詩/json/271.json','["翠輦西歸七十春，玉堂珠綴儼埃塵。", "武皇弓劍埋何處，泣問上陽宮裏人。", "愁雲漠漠草離離，太乙句陳處處疑。", "薄暮毀垣春雨裏，殘花猶發萬年枝。"]'),
('yuding-99','老將行','竇鞏','唐','御定全唐诗','yuding','','[]','烽煙猶未盡，年鬢暗相催。輕敵心空在，彎弓手不開。',48,'御定全唐詩/json/271.json','["烽煙猶未盡，年鬢暗相催。輕敵心空在，彎弓手不開。", "馬依秋草病，柳傍故營摧。唯有酬恩客，時聽說劍來。"]'),
('yuding-100','贈蕭都官','竇鞏','唐','御定全唐诗','yuding','','[]','蕭郎自小賢，愛客不言錢。有酒輕寒夜，無愁倚少年。',48,'御定全唐詩/json/271.json','["蕭郎自小賢，愛客不言錢。有酒輕寒夜，無愁倚少年。", "閑尋織錦字，醉上看花船。好是關身事，從人道性偏。"]'),
('yuding-101','忝職武昌，初至夏口，書事獻府主相公','竇鞏','唐','御定全唐诗','yuding','','[]','白髮放櫜鞬，梁王愛舊全。竹籬江畔宅，梅雨病中天。',48,'御定全唐詩/json/271.json','["白髮放櫜鞬，梁王愛舊全。竹籬江畔宅，梅雨病中天。", "時奉登樓宴，閑修上水船。邑人興謗易，莫遣鶴支錢。"]'),
('yuding-102','早秋江行','竇鞏','唐','御定全唐诗','yuding','','[]','回望湓城遠，西風吹荻花。暮潮江勢闊，秋雨雁行斜。',48,'御定全唐詩/json/271.json','["回望湓城遠，西風吹荻花。暮潮江勢闊，秋雨雁行斜。", "多醉渾無夢，頻愁欲到家。漸驚雲樹轉，數點是晨鴉。"]'),
('yuding-103','題任處士幽居','竇鞏','唐','御定全唐诗','yuding','','[]','紅葉江村夕，孤煙草舍貧。水清魚識釣，林靜犬隨人。',48,'御定全唐詩/json/271.json','["紅葉江村夕，孤煙草舍貧。水清魚識釣，林靜犬隨人。", "采掇山無主，扶持藥有神。客來唯勸酒，蝴蝶是前身。"]'),
('yuding-104','漢陰驛與宇文十相遇，旋歸西川，因以贈別','竇鞏','唐','御定全唐诗','yuding','','[]','吳蜀何年別，相逢漢水頭。望鄉心共醉，握手淚先流。',48,'御定全唐詩/json/271.json','["吳蜀何年別，相逢漢水頭。望鄉心共醉，握手淚先流。", "宿霧千山曉，春霖一夜愁。離情方浩蕩，莫說去刀州。"]'),
('yuding-105','早春松江野望','竇鞏','唐','御定全唐诗','yuding','','[]','江村風雪霽，曉望忽驚春。耕地人來早，營巢鵲語頻。',48,'御定全唐詩/json/271.json','["江村風雪霽，曉望忽驚春。耕地人來早，營巢鵲語頻。", "帶花移樹小，插槿作籬新。何事勝無事，窮通任此身。"]'),
('yuding-106','少婦詞','竇鞏','唐','御定全唐诗','yuding','','[]','坐惜年光變，遼陽信未通。燕迷新畫屋，春識舊花叢。',48,'御定全唐詩/json/271.json','["坐惜年光變，遼陽信未通。燕迷新畫屋，春識舊花叢。", "夢繞天山外，愁翻錦字中。昨來誰是伴，鸚鵡在簾櫳。"]'),
('yuding-107','歲晚喜遠兄弟至書情','竇鞏','唐','御定全唐诗','yuding','','[]','幾年滄海別，相見竟多違。鬢髮緣愁白，音書為懶稀。',48,'御定全唐詩/json/271.json','["幾年滄海別，相見竟多違。鬢髮緣愁白，音書為懶稀。", "新詩徒有贈，故國未同歸。人事那堪問，無言是與非。"]'),
('yuding-108','登玉鉤亭奉獻淮南李相公','竇鞏','唐','御定全唐诗','yuding','','[]','西南城上高高處，望月分明似玉鉤。朱檻入雲看鳥滅，',40,'御定全唐詩/json/271.json','["西南城上高高處，望月分明似玉鉤。朱檻入雲看鳥滅，", "今日捲簾天氣好，不勞騎馬看揚州。"]'),
('yuding-109','南陽道中作','竇鞏','唐','御定全唐诗','yuding','','[]','東風雨洗順陽川，蜀錦花開綠草田。彩雉鬥時頻駐馬，',40,'御定全唐詩/json/271.json','["東風雨洗順陽川，蜀錦花開綠草田。彩雉鬥時頻駐馬，", "早晚到家春欲盡，今年寒食月初圓。"]'),
('yuding-110','哭呂衡州八郎中','竇鞏','唐','御定全唐诗','yuding','','[]','今朝血淚問蒼蒼，不分先悲旅館喪。人送劍來歸隴上，',40,'御定全唐詩/json/271.json','["今朝血淚問蒼蒼，不分先悲旅館喪。人送劍來歸隴上，", "望盡素車秋草外，欲將身贖返魂香。"]'),
('yuding-111','江陵遇元九李六二侍禦紀事書情呈十二韻','竇鞏','唐','御定全唐诗','yuding','','[]','自見人相愛，如君愛我稀。好閑容問道，攻短每言非。',144,'御定全唐詩/json/271.json','["自見人相愛，如君愛我稀。好閑容問道，攻短每言非。", "夢想何曾間，追歡未省違。看花憐後到，避酒許先歸。", "柳寺春堤遠，津橋曙月微。漁翁隨去處，禪客共因依。", "蓬閣初疑義，霜台晚畏威。學深通古字，心直觸危機。", "肯滯荊州掾，猶香柏署衣。山連巫峽秀，田傍渚宮肥。", "美玉方齊價，遷鶯尚怯飛。佇看霄漢上，連步侍彤闈。"]'),
('yuding-112','遊仙詞','竇鞏','唐','御定全唐诗','yuding','','[]','海上神山綠，溪邊杏樹紅。不知何處去，月照玉樓空。',24,'御定全唐詩/json/271.json','["海上神山綠，溪邊杏樹紅。不知何處去，月照玉樓空。"]'),
('yuding-113','贈阿史那都尉','竇鞏','唐','御定全唐诗','yuding','','[]','較獵燕山經幾春，雕弓白羽不離身。',32,'御定全唐詩/json/271.json','["較獵燕山經幾春，雕弓白羽不離身。", "年來馬上渾無力，望見飛鴻指似人。"]'),
('yuding-114','陝府賓堂覽房杜二公仁壽年中題紀手跡','竇鞏','唐','御定全唐诗','yuding','','[]','仁壽元和二百年，蒙籠水墨淡如煙。',32,'御定全唐詩/json/271.json','["仁壽元和二百年，蒙籠水墨淡如煙。", "當時憔悴題名日，漢祖龍潛未上天。"]'),
('yuding-115','早春送宇文十歸吳','竇鞏','唐','御定全唐诗','yuding','','[]','春遲不省似今年，二月無花雪滿天。',32,'御定全唐詩/json/271.json','["春遲不省似今年，二月無花雪滿天。", "村店閉門何處宿，夜深遙喚渡江船。"]'),
('yuding-116','經竇車騎故城','竇鞏','唐','御定全唐诗','yuding','','[]','荒陂古堞欲千年，名振圖書劍在泉。',32,'御定全唐詩/json/271.json','["荒陂古堞欲千年，名振圖書劍在泉。", "今日諸孫拜墳樹，愧無文字續燕然。"]'),
('yuding-117','贈王氏小兒','竇鞏','唐','御定全唐诗','yuding','','[]','竹林會裏偏憐小，淮水清時最覺賢。',32,'御定全唐詩/json/271.json','["竹林會裏偏憐小，淮水清時最覺賢。", "莫倚兒童輕歲月，丈人曾共爾同年。"]'),
('yuding-118','唐州東途作','竇鞏','唐','御定全唐诗','yuding','','[]','綠林兵起結愁雲，白羽飛書未解紛。',32,'御定全唐詩/json/271.json','["綠林兵起結愁雲，白羽飛書未解紛。", "天子欲開三面網，莫將弓箭射官軍。"]'),
('yuding-119','新羅進白鷹','竇鞏','唐','御定全唐诗','yuding','','[]','禦馬新騎禁苑秋，白鷹來自海東頭。',32,'御定全唐詩/json/271.json','["禦馬新騎禁苑秋，白鷹來自海東頭。", "漢皇無事須遊獵，雪亂爭飛錦臂鞲。"]'),
('yuding-120','秋夕','竇鞏','唐','御定全唐诗','yuding','','[]','護霜雲映月朦朧，烏鵲爭飛井上桐。',32,'御定全唐詩/json/271.json','["護霜雲映月朦朧，烏鵲爭飛井上桐。", "夜半酒醒人不覺，滿池荷葉動秋風。"]'),
('yuding-121','襄陽寒食寄宇文籍','竇鞏','唐','御定全唐诗','yuding','','[]','煙水初銷見萬家，東風吹柳萬條斜。',32,'御定全唐詩/json/271.json','["煙水初銷見萬家，東風吹柳萬條斜。", "大堤欲上誰相伴，馬踏春泥半是花。"]'),
('yuding-122','奉使薊門','竇鞏','唐','御定全唐诗','yuding','','[]','自從身屬富人侯，蟬噪槐花已四秋。',32,'御定全唐詩/json/271.json','["自從身屬富人侯，蟬噪槐花已四秋。", "今日一莖新白髮，懶騎官馬到幽州。"]'),
('yuding-123','送劉禹錫','竇鞏','唐','御定全唐诗','yuding','','[]','十年憔悴武陵溪，鶴病深林玉在泥。',32,'御定全唐詩/json/271.json','["十年憔悴武陵溪，鶴病深林玉在泥。", "今日太行平似砥，九霄初倚入雲梯。"]'),
('yuding-124','送元稹西歸','竇鞏','唐','御定全唐诗','yuding','','[]','南州風土滯龍媒，黃紙初飛敕字來。',32,'御定全唐詩/json/271.json','["南州風土滯龍媒，黃紙初飛敕字來。", "二月曲江連舊宅，阿婆情熟牡丹開。"]'),
('yuding-125','過驪山','竇鞏','唐','御定全唐诗','yuding','','[]','翠輦紅旌去不回，蒼蒼宮樹鎖青苔。',32,'御定全唐詩/json/271.json','["翠輦紅旌去不回，蒼蒼宮樹鎖青苔。", "有人說得當時事，曾見長生玉殿開。"]'),
('yuding-126','洛中即事','竇鞏','唐','御定全唐诗','yuding','','[]','高梧葉盡鳥巢空，洛水潺湲夕照中。',32,'御定全唐詩/json/271.json','["高梧葉盡鳥巢空，洛水潺湲夕照中。", "寂寂天橋車馬絕，寒鴉飛入上陽宮。"]'),
('yuding-127','尋道者所隱不遇','竇鞏','唐','御定全唐诗','yuding','','[]','籬外涓涓澗水流，槿花半點夕陽收。',32,'御定全唐詩/json/271.json','["籬外涓涓澗水流，槿花半點夕陽收。", "欲題名字知相訪，又恐芭蕉不奈秋。"]'),
('yuding-128','寄南游兄弟','竇鞏','唐','御定全唐诗','yuding','','[]','書來未報幾時還，知在三湘五嶺間。',32,'御定全唐詩/json/271.json','["書來未報幾時還，知在三湘五嶺間。", "獨立衡門秋水闊，寒鴉飛去日銜山。"]'),
('yuding-129','宮人斜','竇鞏','唐','御定全唐诗','yuding','','[]','離宮路遠北原斜，生死恩深不到家。',32,'御定全唐詩/json/271.json','["離宮路遠北原斜，生死恩深不到家。", "雲雨今歸何處去，黃鸝飛上野棠花。"]'),
('yuding-130','代鄰叟','竇鞏','唐','御定全唐诗','yuding','','[]','年來七十罷耕桑，就暖支羸強下床。',32,'御定全唐詩/json/271.json','["年來七十罷耕桑，就暖支羸強下床。", "滿眼兒孫身外事，閑梳白髮對殘陽。"]'),
('yuding-131','新營別墅寄家兄','竇鞏','唐','御定全唐诗','yuding','','[]','懶性如今成野人，行藏由興不由身。',32,'御定全唐詩/json/271.json','["懶性如今成野人，行藏由興不由身。", "莫驚此度歸來晚，買得西山正值春。"]'),
('yuding-132','南遊感興','竇鞏','唐','御定全唐诗','yuding','','[]','傷心欲問前朝事，惟見江流去不回。',32,'御定全唐詩/json/271.json','["傷心欲問前朝事，惟見江流去不回。", "日暮東風春草綠，鷓鴣飛上越王台。"]'),
('yuding-133','題劍津','竇鞏','唐','御定全唐诗','yuding','','[]','風前推折千年劍，岩下澄空萬古潭。',32,'御定全唐詩/json/271.json','["風前推折千年劍，岩下澄空萬古潭。", "雙劍變成龍化去，兩溪相並水歸南。"]'),
('yuding-134','放魚','竇鞏','唐','御定全唐诗','yuding','','[]','金錢贖得免刀痕，聞道禽魚亦感恩。',32,'御定全唐詩/json/271.json','["金錢贖得免刀痕，聞道禽魚亦感恩。", "好去長江千萬里，不須辛苦上龍門。"]'),
('yuding-135','永寧小園寄接近校書','竇鞏','唐','御定全唐诗','yuding','','[]','故里心期奈別何，手栽芳樹憶庭柯。',32,'御定全唐詩/json/271.json','["故里心期奈別何，手栽芳樹憶庭柯。", "東皋黍熟君應醉，梨葉初紅白露多。"]'),
('yuding-136','從軍別家','竇鞏','唐','御定全唐诗','yuding','','[]','自笑儒生著戰袍，書齋壁上掛弓刀。',32,'御定全唐詩/json/271.json','["自笑儒生著戰袍，書齋壁上掛弓刀。", "如今便是征人婦，好織回文寄竇滔。"]'),
('yuding-137','悼妓東東','竇鞏','唐','御定全唐诗','yuding','','[]','芳菲美豔不禁風，未到春殘已墜紅。',32,'御定全唐詩/json/271.json','["芳菲美豔不禁風，未到春殘已墜紅。", "惟有側輪車上鐸，耳邊長似叫東東。"]'),
('yuding-0','木蘭歌','韋元甫','唐','御定全唐诗','yuding','','[]','木蘭抱杼嗟，借問複為誰。欲聞所戚戚，感激強其顏。',186,'御定全唐詩/json/272.json','["木蘭抱杼嗟，借問複為誰。欲聞所戚戚，感激強其顏。", "老父隸兵籍，氣力日衰耗。豈足萬里行，有子複尚少。", "胡沙沒馬足，朔風裂人膚。老父舊羸病，何以強自扶。", "木蘭代父去，秣馬備戎行。易卻紈綺裳，洗卻鉛粉妝。", "馳馬赴軍幕，慷慨攜幹將。朝屯雪山下，暮宿青海傍。", "夜襲燕支虜，更攜於闐羌。將軍得勝歸，士卒還故鄉。", "父母見木蘭，喜極成悲傷。木蘭能承父母顏，", "親戚持酒賀父母，始知生女與男同。門前舊軍都，"]'),
('yuding-1','登越王樓見喬公詩偶題','王鋌','唐','御定全唐诗','yuding','','[]','雲架重樓出郡城，虹梁雅韻仲宣情。越王空置千年跡，',40,'御定全唐詩/json/272.json','["雲架重樓出郡城，虹梁雅韻仲宣情。越王空置千年跡，", "謬將蹇步尋高躅，魚目驪珠豈繼明。"]'),
('yuding-2','清如玉壺冰','潘炎','唐','御定全唐诗','yuding','','[]','琰玉性惟堅，成壺體更圓。虛心含景象，應物受寒泉。',96,'御定全唐詩/json/272.json','["琰玉性惟堅，成壺體更圓。虛心含景象，應物受寒泉。", "溫潤資天質，清貞稟自然。日融光乍散，雪照色逾鮮。", "至鑒功寧宰，無私照豈偏。明將冰鏡對，白與粉花連。", "拂拭終為美，提攜佇見傳。勿令毫髮累，遺恨鮑公篇。"]'),
('yuding-3','長至日上公獻壽','張叔良','唐','御定全唐诗','yuding','','[]','鳳闕晴鐘動，雞人曉漏長。九重初啟鑰，三事正稱觴。',72,'御定全唐詩/json/272.json','["鳳闕晴鐘動，雞人曉漏長。九重初啟鑰，三事正稱觴。", "日至龍顏近，天旋聖曆昌。休光連雪淨，瑞氣雜爐香。", "化被君臣洽，恩沾士庶康。不因稽舊典，誰得紀朝章。"]'),
('yuding-4','涇渭揚清濁','呂牧','唐','御定全唐诗','yuding','','[]','涇渭橫秦野，逶迤近帝城。二渠通作潤，萬戶映皆清。',72,'御定全唐詩/json/272.json','["涇渭橫秦野，逶迤近帝城。二渠通作潤，萬戶映皆清。", "明晦看殊色，潺湲聽一聲。岸虛深草掩，波動曉煙輕。", "禦獵思投釣，漁歌好濯纓。合流知禹力，同共到滄瀛。"]'),
('yuding-5','別張賈','韋夏卿','唐','御定全唐诗','yuding','','[]','束簡下高閣，買符驅短轅。故人惜分袂，結念醉芳樽。',48,'御定全唐詩/json/272.json','["束簡下高閣，買符驅短轅。故人惜分袂，結念醉芳樽。", "切切別思纏，蕭蕭征騎煩。臨歸無限意，相視卻忘言。"]'),
('yuding-6','送顧況歸茅山','韋夏卿','唐','御定全唐诗','yuding','','[]','聖代為遷客，虛皇作近臣。法尊稱大洞，學淺忝初真。',48,'御定全唐詩/json/272.json','["聖代為遷客，虛皇作近臣。法尊稱大洞，學淺忝初真。", "鸞鳳文章麗，煙霞翰墨新。羨君尋句曲，白鵠是三神。"]'),
('yuding-7','和丘員外題湛長史舊居','韋夏卿','唐','御定全唐诗','yuding','','[]','道勝物能齊，累輕身易退。苟安一丘上，何必三山外。',72,'御定全唐詩/json/272.json','["道勝物能齊，累輕身易退。苟安一丘上，何必三山外。", "雲霞長若綺，松石常如黛。徒有昔王過，竟遺青史載。", "詩因野寺詠，酒向山椒酹。異時逢爾知，茲辰駐餘旆。"]'),
('yuding-8','同韋夏卿送顧況歸茅山','綦毋誠','唐','御定全唐诗','yuding','','[]','謫宦聞嘗賦，遊仙便作詩。白銀雙闕戀，青竹一龍騎。',48,'御定全唐詩/json/272.json','["謫宦聞嘗賦，遊仙便作詩。白銀雙闕戀，青竹一龍騎。", "先入茅君洞，旋過葛稚陂。無然列禦寇，五日有還期。"]'),
('yuding-9','感秋','姚倫','唐','御定全唐诗','yuding','','[]','試向疏林望，方知節候殊。亂聲千葉下，寒影一巢孤。',48,'御定全唐詩/json/272.json','["試向疏林望，方知節候殊。亂聲千葉下，寒影一巢孤。", "不蔽秋天雁，驚飛夜月烏。霜風與春日，幾度遣榮枯。"]'),
('yuding-10','過章秀才洛陽客舍','姚倫','唐','御定全唐诗','yuding','','[]','達人心自適，旅舍當閒居。不出來時徑，重看讀了書。',48,'御定全唐詩/json/272.json','["達人心自適，旅舍當閒居。不出來時徑，重看讀了書。", "晚山嵐色近，斜日樹陰疏。儘是忘言客，聽君誦子虛。"]'),
('yuding-11','賦得生芻一束','於結','唐','御定全唐诗','yuding','','[]','比玉人應重，為芻物自輕。向風傾弱葉，裛露示纖莖。',73,'御定全唐詩/json/272.json','["比玉人應重，為芻物自輕。向風傾弱葉，裛露示纖莖。", "蒨練宜春景，芊綿對雨情。每慚蘋藻用，多謝vK蘭榮。", "孺子才雖遠，公孫策未行。諮詢如不棄，終冀及微生。"]'),
('yuding-12','賦得生芻一束','鄭孺華','唐','御定全唐诗','yuding','','[]','孫弘期射策，長倩贈生芻。至潔心將比，忘憂道不孤。',72,'御定全唐詩/json/272.json','["孫弘期射策，長倩贈生芻。至潔心將比，忘憂道不孤。", "芝蘭方入室，蕭艾莫同途。馥馥香猶在，青青色更殊。", "芳寧九春歇，熏豈十年無。葑菲如堪采，山苗自可逾。"]'),
('yuding-13','空靈岸','張叔卿','唐','御定全唐诗','yuding','','[]','寒盡鴻先去，江回客未歸。早知名是幻，不敢繡為衣。',48,'御定全唐詩/json/272.json','["寒盡鴻先去，江回客未歸。早知名是幻，不敢繡為衣。", "霧積川原暗，山多郡縣稀。今朝下湘岸，更逐鷓鴣飛。"]'),
('yuding-14','流桂州','張叔卿','唐','御定全唐诗','yuding','','[]','莫問蒼梧遠，而今世路難。胡塵不到處，即是小長安。',24,'御定全唐詩/json/272.json','["莫問蒼梧遠，而今世路難。胡塵不到處，即是小長安。"]'),
('yuding-15','酬竇大閒居見寄','房孺複','唐','御定全唐诗','yuding','','[]','來自三湘到五溪，青楓無樹不猿啼。名慚竹使宦情少，',40,'御定全唐詩/json/272.json','["來自三湘到五溪，青楓無樹不猿啼。名慚竹使宦情少，", "煩君強著潘年比，騎省風流詎可齊。"]'),
('yuding-16','送妓人出家','楊郇伯','唐','御定全唐诗','yuding','','[]','盡出花鈿與四鄰，雲鬟剪落厭殘春。暫驚風燭難留世，',40,'御定全唐詩/json/272.json','["盡出花鈿與四鄰，雲鬟剪落厭殘春。暫驚風燭難留世，", "從今豔色歸空後，湘浦應無解佩人。"]'),
('yuding-17','宿北樂館','陳潤','唐','御定全唐诗','yuding','','[]','欲眠不眠夜深淺，越鳥一聲空山遠。庭木蕭蕭落葉時，',40,'御定全唐詩/json/272.json','["欲眠不眠夜深淺，越鳥一聲空山遠。庭木蕭蕭落葉時，", "棟裏不知渾是雲，曉來但覺衣裳濕。"]'),
('yuding-18','東都所居寒食下作','陳潤','唐','御定全唐诗','yuding','','[]','江南寒食早，二月杜鵑鳴。日暖山初綠，春寒雨欲晴。',48,'御定全唐詩/json/272.json','["江南寒食早，二月杜鵑鳴。日暖山初綠，春寒雨欲晴。", "浴蠶當社日，改火待清明。更喜瓜田好，令人憶邵平。"]'),
('yuding-19','登西靈塔','陳潤','唐','御定全唐诗','yuding','','[]','塔廟出招提，登臨碧海西。不知人意遠，漸覺鳥飛低。',48,'御定全唐詩/json/272.json','["塔廟出招提，登臨碧海西。不知人意遠，漸覺鳥飛低。", "稍與雲霞近，如將日月齊。遷喬未得意，徒欲躡雲梯。"]'),
('yuding-20','送駱征君','陳潤','唐','御定全唐诗','yuding','','[]','野人膺辟命，溪上掩柴扉。黃卷猶將去，青山豈更歸。',48,'御定全唐詩/json/272.json','["野人膺辟命，溪上掩柴扉。黃卷猶將去，青山豈更歸。", "馬留苔蘚跡，人脫薜蘿衣。他日相思處，天邊望少微。"]'),
('yuding-21','賦得浦外虹送人','陳潤','唐','御定全唐诗','yuding','','[]','日影化為虹，彎彎出浦東。一條微雨後，五色片雲中。',48,'御定全唐詩/json/272.json','["日影化為虹，彎彎出浦東。一條微雨後，五色片雲中。", "輪勢隨天度，橋形跨海通。還將飲水處，持送使車雄。"]'),
('yuding-22','賦得秋河曙耿耿','陳潤','唐','御定全唐诗','yuding','','[]','晚望秋高夜，微明欲曙河。橋成鵲已去，機罷女應過。',48,'御定全唐詩/json/272.json','["晚望秋高夜，微明欲曙河。橋成鵲已去，機罷女應過。", "月上殊開練，雲行類動波。尋源不可到，耿耿複如何。"]'),
('yuding-23','賦得池塘生春草','陳潤','唐','御定全唐诗','yuding','','[]','謝公遺詠處，池水夾通津。古往人何在，年來草自春。',48,'御定全唐詩/json/272.json','["謝公遺詠處，池水夾通津。古往人何在，年來草自春。", "色宜波際綠，香愛雨中新。今日青青意，空悲行路人。"]'),
('yuding-24','闕題','陳潤','唐','御定全唐诗','yuding','','[]','丈夫不感恩，感恩寧有淚。心頭感恩血，一滴染天地。',24,'御定全唐詩/json/272.json','["丈夫不感恩，感恩寧有淚。心頭感恩血，一滴染天地。"]'),
('yuding-25','哭長孫侍郎','杜誦','唐','御定全唐诗','yuding','','[]','道為詩書重，名因賦頌雄。禮闈曾擢桂，憲府既乘驄。',48,'御定全唐詩/json/272.json','["道為詩書重，名因賦頌雄。禮闈曾擢桂，憲府既乘驄。", "流水生涯盡，浮雲世事空。唯餘舊台柏，蕭瑟九原中。"]'),
('yuding-26','明皇帝挽歌','鄭丹','唐','御定全唐诗','yuding','','[]','律曆千年會，車書萬里同。固期常戴日，豈意厭觀風。',48,'御定全唐詩/json/272.json','["律曆千年會，車書萬里同。固期常戴日，豈意厭觀風。", "地慘新疆理，城摧舊戰功。山河萬古壯，今夕盡歸空。"]'),
('yuding-27','肅宗挽歌','鄭丹','唐','御定全唐诗','yuding','','[]','國以重明受，天從諒闇移。諸侯方北面，白日忽西馳。',48,'御定全唐詩/json/272.json','["國以重明受，天從諒闇移。諸侯方北面，白日忽西馳。", "龍影當泉落，鴻名向廟垂。永言青史上，還見戴無為。"]'),
('yuding-28','落花','鄭昈','唐','御定全唐诗','yuding','','[]','早春見花枝，朝朝恨發遲。直看花落盡，卻意未開時。',48,'御定全唐詩/json/272.json','["早春見花枝，朝朝恨發遲。直看花落盡，卻意未開時。", "以此方人世，彌令感盛衰。始知山簡繞，頻向習家池。"]'),
('yuding-29','宿新安江深渡館寄鄭州王使君','朱長文','唐','御定全唐诗','yuding','','[]','霜飛十月中，搖落眾山空。孤館閉寒木，大江生夜風。',36,'御定全唐詩/json/272.json','["霜飛十月中，搖落眾山空。孤館閉寒木，大江生夜風。", "賦詩忙有意，沈約在關東。"]'),
('yuding-30','春眺揚州西上崗寄徐員外','朱長文','唐','御定全唐诗','yuding','','[]','蕪城西眺極蒼流，漠漠春煙間曙樓。瓜步早潮吞建業，',24,'御定全唐詩/json/272.json','["蕪城西眺極蒼流，漠漠春煙間曙樓。瓜步早潮吞建業，"]'),
('yuding-31','送李司直歸浙東幕兼寄鮑將軍','朱長文','唐','御定全唐诗','yuding','','[]','翩翩書記早曾聞，二十年來願見君。今日相逢悲白髮，',40,'御定全唐詩/json/272.json','["翩翩書記早曾聞，二十年來願見君。今日相逢悲白髮，", "會作王門曳裾客，為余前謝鮑將軍。"]'),
('yuding-32','望中有懷','朱長文','唐','御定全唐诗','yuding','','[]','龍向洞中銜雨出，鳥從花裏帶香飛。',32,'御定全唐詩/json/272.json','["龍向洞中銜雨出，鳥從花裏帶香飛。", "白雲斷處見明月，黃葉落時聞擣衣。"]'),
('yuding-33','題虎丘山西寺','朱長文','唐','御定全唐诗','yuding','','[]','王氏家山昔在茲，陸機為賦陸雲詩。',32,'御定全唐詩/json/272.json','["王氏家山昔在茲，陸機為賦陸雲詩。", "青蓮香匝東西宇，日月與僧無盡時。"]'),
('yuding-34','吳興送梁補闕歸朝賦得荻花','朱長文','唐','御定全唐诗','yuding','','[]','柳家汀洲孟冬月，雲寒水清荻花發。',32,'御定全唐詩/json/272.json','["柳家汀洲孟冬月，雲寒水清荻花發。", "一枝持贈朝天人，願比蓬萊殿前雪。"]'),
('yuding-35','句','朱長文','唐','御定全唐诗','yuding','','[]','夜靜忽疑身是夢，更聞寒雨滴芭蕉。',17,'御定全唐詩/json/272.json','["夜靜忽疑身是夢，更聞寒雨滴芭蕉。", "。"]'),
('yuding-0','獨不見','戴叔倫','唐','御定全唐诗','yuding','','[]','前宮路非遠，舊苑春將遍。玉戶看早梅，雕梁數飛燕。',60,'御定全唐詩/json/273.json','["前宮路非遠，舊苑春將遍。玉戶看早梅，雕梁數飛燕。", "身輕逐舞袖，香暖傳歌扇。自和秋風詞，長侍昭陽殿。", "誰信後庭人，年年獨不見。"]'),
('yuding-1','去婦怨','戴叔倫','唐','御定全唐诗','yuding','','[]','出戶不敢啼，風悲日淒淒。心知恩義絕，誰忍分明別。',72,'御定全唐詩/json/273.json','["出戶不敢啼，風悲日淒淒。心知恩義絕，誰忍分明別。", "下阪車轔轔，畏逢鄉里親。空持床前幔，卻寄家中人。", "忽辭王吉去，為是秋胡死。若比今日情，煩冤不相似。"]'),
('yuding-2','古意','戴叔倫','唐','御定全唐诗','yuding','','[]','悠悠南山雲，濯濯東流水。念我平生歡，托居在東裏。',72,'御定全唐詩/json/273.json','["悠悠南山雲，濯濯東流水。念我平生歡，托居在東裏。", "失既不足憂，得亦不為喜。安貧固其然，處賤寧獨恥。", "雲閑虛我心，水清澹吾味。雲水俱無心，斯可長伉儷。"]'),
('yuding-3','南野','戴叔倫','唐','御定全唐诗','yuding','','[]','治田長山下，引流坦溪曲。東山有遺塋，南野起新築。',120,'御定全唐詩/json/273.json','["治田長山下，引流坦溪曲。東山有遺塋，南野起新築。", "家世素業儒，子孫鄙食祿。披雲朝出耕，帶月夜歸讀。", "身勩竟亡疲，團團欣在目。野芳綠可采，泉美清可掬。", "茂樹延晚涼，早田候秋熟。茶烹松火紅，酒吸荷杯綠。", "解佩臨清池，撫琴看修竹。此懷誰與同，此樂君所獨。"]'),
('yuding-4','曾游','戴叔倫','唐','御定全唐诗','yuding','','[]','泊舟古城下，高閣快登眺。大江會彭蠡，群峰豁玄嶠。',72,'御定全唐詩/json/273.json','["泊舟古城下，高閣快登眺。大江會彭蠡，群峰豁玄嶠。", "清影涵空明，黛色凝遠照。碑留太史書，詞刻長公調。", "絕粒感楚囚，丹衷猶照耀。懷哉不可招，憑闌一悲嘯。"]'),
('yuding-5','江行','戴叔倫','唐','御定全唐诗','yuding','','[]','漾舟晴川裏，掛席候風生。臨泛何容與，愛此江水清。',72,'御定全唐詩/json/273.json','["漾舟晴川裏，掛席候風生。臨泛何容與，愛此江水清。", "蘆洲隱遙嶂，露日映孤城。自顧疏野性，屢忘鷗鳥情。", "聊複于時顧，暫欲解塵纓。驅馳非吾願，虛懷浩已盈。"]'),
('yuding-6','孤鴻篇','戴叔倫','唐','御定全唐诗','yuding','','[]','江上雙飛鴻，飲啄行相隨。翔風一何厲，中道傷其雌。',120,'御定全唐詩/json/273.json','["江上雙飛鴻，飲啄行相隨。翔風一何厲，中道傷其雌。", "顧影明月下，哀鳴聲正悲。已無矰繳患，豈乏稻粱資。", "嗈嗈慕儔匹，遠集清江湄。中有孤文鵷，翩翩好容儀。", "共欣相知遇，畢志同棲遲。野田鴟鴞鳥，相妒複相疑。", "鴻志不汝較，奮翼起高飛。焉隨腐鼠欲，負此雲霄期。"]'),
('yuding-7','感懷二首','戴叔倫','唐','御定全唐诗','yuding','','[]','尺帛無長裁，淺水無長流。水淺易成枯，帛短誰人收。',144,'御定全唐詩/json/273.json','["尺帛無長裁，淺水無長流。水淺易成枯，帛短誰人收。", "人生取捨間，趨競固非優。舊交跡雖疏，中心自雲稠。", "新交意雖密，中道生怨尤。踟躕複踟躕，世路今悠悠。", "主人飲君酒，勸君弗相違。但當盡弘量，觴至無複辭。", "人生百年中，會合能幾時。不見枝上花，昨滿今漸稀。", "花落還再開，人老無少期。古來賢達士，飲酒不復疑。"]'),
('yuding-8','喜雨','戴叔倫','唐','御定全唐诗','yuding','','[]','閒居倦時燠，開軒俯平林。雷聲殷遙空，雲氣布層陰。',84,'御定全唐詩/json/273.json','["閒居倦時燠，開軒俯平林。雷聲殷遙空，雲氣布層陰。", "川上風雨來，灑然滌煩襟。田家共歡笑，溝澮亦已深。", "團團聚鄰曲，鬥酒相與斟。樵歌野田中，漁釣滄江潯。", "蒼天暨有念，悠悠終我心。"]'),
('yuding-9','歎葵花','戴叔倫','唐','御定全唐诗','yuding','','[]','今日見花落，明日見花開。花開能向日，花落委蒼苔。',36,'御定全唐詩/json/273.json','["今日見花落，明日見花開。花開能向日，花落委蒼苔。", "自不同凡卉，看時幾日回。"]'),
('yuding-10','從軍行','戴叔倫','唐','御定全唐诗','yuding','','[]','丈夫四方志，結髮事遠遊。遠遊歷燕薊，獨戍邊城陬。',96,'御定全唐詩/json/273.json','["丈夫四方志，結髮事遠遊。遠遊歷燕薊，獨戍邊城陬。", "西風壟水寒，明月關山悠。酬恩仗孤劍，十年弊貂裘。", "封侯屬何人，蹉跎雪盈頭。老馬思故櫪，窮鱗憶深流。", "彈鋏動深慨，浩歌氣橫秋。報國期努力，功名良見收。"]'),
('yuding-11','九日與敬處士左學士同賦采菊上東山便為首句','戴叔倫','唐','御定全唐诗','yuding','','[]','采菊上東山，山高路非遠。江湖乍遼夐，城郭亦在眼。',108,'御定全唐詩/json/273.json','["采菊上東山，山高路非遠。江湖乍遼夐，城郭亦在眼。", "晝日市井喧，閏年禾稼晚。開尊會佳客，長嘯臨絕巘。", "戲鶴唳且閑，斷雲輕不卷。鄉心各萬里，醉話時一展。", "喬木列遙天，殘陽貫平阪。徒憂征車重，自笑謀慮淺。", "卻顧郡齋中，寄傲與君同。"]'),
('yuding-12','奉天酬別鄭諫議雲逵、盧拾遺景亮見別之作','戴叔倫','唐','御定全唐诗','yuding','','[]','巨孽盜都城，傳聞天下驚。陪臣九江畔，走馬來赴難。',372,'御定全唐詩/json/273.json','["巨孽盜都城，傳聞天下驚。陪臣九江畔，走馬來赴難。", "伏奏見龍顏，旋持手詔還。單車不可駐，朱檻未遑攀。", "故人出相餞，共悲行路難。臨岐荷贈言，對酒獨傷魂。", "世故山川險，憂多思慮昏。重陰蔽芳月，疊嶺明舊雪。", "泥積轍更深，木冰花不發。鄭君間世賢，忠孝乃雙全。", "大義棄妻子，至淳易生死。知心三四人，越境千餘裏。", "駿馬帳前發，驚塵路傍起。樓頭俯首看，莫敢相留止。", "拜闕奏良圖，留中沃聖謨。洗兵救衛郡，誘敵討幽都。", "名亞典屬國，良選諫大夫。從容九霄上，談笑授陰符。", "盧生富才術，特立居近密。采掇獻吾君，朝廷視聽新。", "寬饒狂自比，汲黯直為鄰。就列繼三事，主文當七人。", "可憐長守道，不覺五逢春。昔去城南陌，各為天際客。", "關河煙霧深，寸步音塵隔。羈旅忽相遇，別離又茲夕。", "前悲涕未幹，後喜心已戚。而我方老大，頗為風眩迫。", "夫君並少年，何爾鬢須白。惆悵語不盡，裴回情轉劇。", "一尊自共持，以慰長相憶。"]'),
('yuding-13','梧桐','戴叔倫','唐','御定全唐诗','yuding','','[]','亭亭南軒外，貞幹修且直。廣葉結青陰，繁花連素色。',36,'御定全唐詩/json/273.json','["亭亭南軒外，貞幹修且直。廣葉結青陰，繁花連素色。", "天資韶雅性，不愧知音識。"]'),
('yuding-14','孤石','戴叔倫','唐','御定全唐诗','yuding','','[]','迥若千仞峰，孤危不盈尺。早晚他山來，猶帶煙雨跡。',36,'御定全唐詩/json/273.json','["迥若千仞峰，孤危不盈尺。早晚他山來，猶帶煙雨跡。", "貞堅自有分，不亂和氏璧。"]'),
('yuding-15','花','戴叔倫','唐','御定全唐诗','yuding','','[]','花發炎景中，芳春獨能久。因風任開落，向日無先後。',36,'御定全唐詩/json/273.json','["花發炎景中，芳春獨能久。因風任開落，向日無先後。", "若待秋霜來，蘭蓀共何有。"]'),
('yuding-16','竹','戴叔倫','唐','御定全唐诗','yuding','','[]','卷籜正離披，新枝複蒙密。翛翛月下聞，褭褭林際出。',36,'御定全唐詩/json/273.json','["卷籜正離披，新枝複蒙密。翛翛月下聞，褭褭林際出。", "豈獨對芳菲，終年色如一。"]'),
('yuding-17','懷素上人草書歌','戴叔倫','唐','御定全唐诗','yuding','','[]','楚僧懷素工草書，古法盡能新有餘。神清骨竦意真率，',64,'御定全唐詩/json/273.json','["楚僧懷素工草書，古法盡能新有餘。神清骨竦意真率，", "忽為壯麗就枯澀，龍蛇騰盤獸屹立。馳毫驟墨劇奔駟，", "人人細問此中妙，懷素自言初不知。"]'),
('yuding-18','女耕田行','戴叔倫','唐','御定全唐诗','yuding','','[]','乳燕入巢筍成竹，誰家二女種新穀。無人無牛不及犁，',72,'御定全唐詩/json/273.json','["乳燕入巢筍成竹，誰家二女種新穀。無人無牛不及犁，", "去年災疫牛囤空，截絹買刀都市中。頭巾掩面畏人識，", "疏通畦隴防亂苗，整頓溝塍待時雨。日正南岡下餉歸，"]'),
('yuding-19','柳花歌送客往桂陽','戴叔倫','唐','御定全唐诗','yuding','','[]','滄浪渡頭柳花發，斷續因風飛不絕。搖煙拂水積翠間，',48,'御定全唐詩/json/273.json','["滄浪渡頭柳花發，斷續因風飛不絕。搖煙拂水積翠間，", "移家深入桂水源，種柳新成花更繁。定知別後消散盡，"]'),
('yuding-20','邊城曲','戴叔倫','唐','御定全唐诗','yuding','','[]','人生莫作遠行客，遠行莫戍黃沙磧。黃沙磧下八月時，',48,'御定全唐詩/json/273.json','["人生莫作遠行客，遠行莫戍黃沙磧。黃沙磧下八月時，", "胡笳聽徹雙淚流，羈魂慘慘生邊愁。原頭獵火夜相向，"]'),
('yuding-21','屯田詞','戴叔倫','唐','御定全唐诗','yuding','','[]','春來耕田遍沙磧，老稚欣欣種禾麥。麥苗漸長天苦晴，',64,'御定全唐詩/json/273.json','["春來耕田遍沙磧，老稚欣欣種禾麥。麥苗漸長天苦晴，", "捕蝗歸來守空屋，囊無寸帛瓶無粟。十月移屯來向城，", "艱辛歷盡誰得知，望斷天南淚如雨。"]'),
('yuding-22','巫山高','戴叔倫','唐','御定全唐诗','yuding','','[]','巫山峨峨高插天，危峰十二淩紫煙。瞿塘嘈嘈急如弦，',50,'御定全唐詩/json/273.json','["巫山峨峨高插天，危峰十二淩紫煙。瞿塘嘈嘈急如弦，", "陸行巉岩水不前。灑淚向流水，淚歸東海邊。含愁對明月，"]'),
('yuding-23','早春曲','戴叔倫','唐','御定全唐诗','yuding','','[]','青樓昨夜東風轉，錦帳凝寒覺春淺。垂楊搖絲鶯亂啼，',48,'御定全唐詩/json/273.json','["青樓昨夜東風轉，錦帳凝寒覺春淺。垂楊搖絲鶯亂啼，", "玉頰啼紅夢初醒，羞見青鸞鏡中影。儂家少年愛游逸，"]'),
('yuding-24','白苧詞','戴叔倫','唐','御定全唐诗','yuding','','[]','館娃宮中露華冷，月落啼鴉散金井。吳王扶頭酒初醒，',72,'御定全唐詩/json/273.json','["館娃宮中露華冷，月落啼鴉散金井。吳王扶頭酒初醒，", "新裁白苧勝紅綃，玉佩珠纓金步搖。回鸞轉鳳意自嬌，", "東風吹花落庭樹，春色催人等閒去。大家為歡莫延佇，"]'),
('yuding-25','行路難','戴叔倫','唐','御定全唐诗','yuding','','[]','出門行路難，富貴安可期。淮陰不免惡少辱，',68,'御定全唐詩/json/273.json','["出門行路難，富貴安可期。淮陰不免惡少辱，", "長安車馬隨輕肥，青雲賓從紛交馳。白眼向人多意氣，", "揚雄閉門空讀書，門前碧草春離離。不如拂衣且歸去，"]'),
('yuding-26','相思曲','戴叔倫','唐','御定全唐诗','yuding','','[]','高樓重重閉明月，腸斷仙郎來年別。紫蕭橫笛寂無聲，',72,'御定全唐詩/json/273.json','["高樓重重閉明月，腸斷仙郎來年別。紫蕭橫笛寂無聲，", "恨滿牙床翡翠衾，怨折金釵鳳凰股。井深轆轤嗟綆短，", "落紅亂逐東流水，一點芳心為君死。妾身願作巫山雲，"]'),
('yuding-27','送別錢起','戴叔倫','唐','御定全唐诗','yuding','','[]','陽關多古調，無奈醉中聞。歸夢吳山遠，離情楚水分。',48,'御定全唐詩/json/273.json','["陽關多古調，無奈醉中聞。歸夢吳山遠，離情楚水分。", "孤舟經暮雨，征路入秋雲。後夜同明月，山窗定憶君。"]'),
('yuding-28','送張南史','戴叔倫','唐','御定全唐诗','yuding','','[]','陋巷無車轍，煙蘿總是春。賈生獨未達，原憲竟忘貧。',48,'御定全唐詩/json/273.json','["陋巷無車轍，煙蘿總是春。賈生獨未達，原憲竟忘貧。", "草座留山月，荷衣遠洛塵。最憐知己在，林下訪閒人。"]'),
('yuding-29','春日早朝應制','戴叔倫','唐','御定全唐诗','yuding','','[]','仙仗肅朝官，承平聖主歡。月沈宮漏靜，雨濕禁花寒。',48,'御定全唐詩/json/273.json','["仙仗肅朝官，承平聖主歡。月沈宮漏靜，雨濕禁花寒。", "丹荔來金闕，朱櫻貢玉盤。六龍扶禦日，只許近臣看。"]'),
('yuding-30','早行寄朱山人放','戴叔倫','唐','御定全唐诗','yuding','','[]','山曉旅人去，天高秋氣悲。明河川上沒，芳草露中衰。',48,'御定全唐詩/json/273.json','["山曉旅人去，天高秋氣悲。明河川上沒，芳草露中衰。", "此別又千里，少年能幾時。心知剡溪路，聊且寄前期。"]'),
('yuding-31','除夜宿石頭驛','戴叔倫','唐','御定全唐诗','yuding','','[]','旅館誰相問，寒燈獨可親。一年將盡夜，萬里未歸人。',48,'御定全唐詩/json/273.json','["旅館誰相問，寒燈獨可親。一年將盡夜，萬里未歸人。", "寥落悲前事，支離笑此身。愁顏與衰鬢，明日又逢春。"]'),
('yuding-32','吳明府自遠而來留宿','戴叔倫','唐','御定全唐诗','yuding','','[]','出門逢故友，衣服滿塵埃。歲月不可問，山川何處來。',48,'御定全唐詩/json/273.json','["出門逢故友，衣服滿塵埃。歲月不可問，山川何處來。", "綺城容弊宅，散職寄靈台。自此留君醉，相歡得幾回。"]'),
('yuding-33','客夜與故人偶集','戴叔倫','唐','御定全唐诗','yuding','','[]','天秋月又滿，城闕夜千重。還作江南會，翻疑夢裏逢。',48,'御定全唐詩/json/273.json','["天秋月又滿，城闕夜千重。還作江南會，翻疑夢裏逢。", "風枝驚暗鵲，露草覆寒蛩。羈旅長堪醉，相留畏曉鐘。"]'),
('yuding-34','送友人東歸','戴叔倫','唐','御定全唐诗','yuding','','[]','萬里楊柳色，出關送故人。輕煙拂流水，落日照行塵。',48,'御定全唐詩/json/273.json','["萬里楊柳色，出關送故人。輕煙拂流水，落日照行塵。", "積夢江湖闊，憶家兄弟貧。裴回灞亭上，不語自傷春。"]'),
('yuding-35','江上別張歡','戴叔倫','唐','御定全唐诗','yuding','','[]','年年五湖上，厭見五湖春。長醉非關酒，多愁不為貧。',48,'御定全唐詩/json/273.json','["年年五湖上，厭見五湖春。長醉非關酒，多愁不為貧。", "山川迷道路，伊洛困風塵。今日扁舟別，俱為滄海人。"]'),
('yuding-36','廣陵送趙主簿自蜀歸絳州甯覲','戴叔倫','唐','御定全唐诗','yuding','','[]','將歸汾水上，遠省錦城來。已泛西江盡，仍隨北雁回。',48,'御定全唐詩/json/273.json','["將歸汾水上，遠省錦城來。已泛西江盡，仍隨北雁回。", "暮雲征馬速，曉月故關開。漸向庭闈近，留君醉一杯。"]'),
('yuding-37','別友人','戴叔倫','唐','御定全唐诗','yuding','','[]','擾擾倦行役，相逢陳蔡間。如何百年內，不見一人閑。',48,'御定全唐詩/json/273.json','["擾擾倦行役，相逢陳蔡間。如何百年內，不見一人閑。", "對酒惜餘景，問程愁亂山。秋風萬里道，又出穆陵關。"]'),
('yuding-38','宿城南盛本道懷皇甫冉','戴叔倫','唐','御定全唐诗','yuding','','[]','暑夜宿南城，懷人夢不成。高樓邀落月，疊鼓送殘更。',48,'御定全唐詩/json/273.json','["暑夜宿南城，懷人夢不成。高樓邀落月，疊鼓送殘更。", "隔浦雲林近，滿川風露清。東碕不可見，矯首若為情。"]'),
('yuding-39','暉上人獨坐亭','戴叔倫','唐','御定全唐诗','yuding','','[]','蕭條心境外，兀坐獨參禪。蘿月明磐石，松風落澗泉。',48,'御定全唐詩/json/273.json','["蕭條心境外，兀坐獨參禪。蘿月明磐石，松風落澗泉。", "性空長入定，心悟自通玄。去住渾無跡，青山謝世緣。"]'),
('yuding-40','送崔融','戴叔倫','唐','御定全唐诗','yuding','','[]','王者應無敵，天兵動遠征。建牙連朔漠，飛騎入胡城。',48,'御定全唐詩/json/273.json','["王者應無敵，天兵動遠征。建牙連朔漠，飛騎入胡城。", "夜月邊塵影，秋風隴水聲。陳琳能草檄，含笑出長平。"]'),
('yuding-41','游少林寺','戴叔倫','唐','御定全唐诗','yuding','','[]','步入招提路，因之訪道林。石龕苔蘚積，香徑白雲深。',48,'御定全唐詩/json/273.json','["步入招提路，因之訪道林。石龕苔蘚積，香徑白雲深。", "雙樹含秋色，孤峰起夕陰。屟廊行欲遍，回首一長吟。"]'),
('yuding-42','崇德道中','戴叔倫','唐','御定全唐诗','yuding','','[]','暖日菜心稠，晴煙麥穗抽。客心雙去翼，歸夢一扁舟。',48,'御定全唐詩/json/273.json','["暖日菜心稠，晴煙麥穗抽。客心雙去翼，歸夢一扁舟。", "廢塔巢雙鶴，長波漾白鷗。關山明月到，愴惻十年遊。"]'),
('yuding-43','雨','戴叔倫','唐','御定全唐诗','yuding','','[]','歷歷愁心亂，迢迢獨夜長。春帆江上雨，曉鏡鬢邊霜。',48,'御定全唐詩/json/273.json','["歷歷愁心亂，迢迢獨夜長。春帆江上雨，曉鏡鬢邊霜。", "啼鳥雲山靜，落花溪水香。家人亦念我，與汝黯相忘。"]'),
('yuding-44','過賈誼宅','戴叔倫','唐','御定全唐诗','yuding','','[]','一謫長沙地，三年歎逐臣。上書憂漢室，作賦吊靈均。',48,'御定全唐詩/json/273.json','["一謫長沙地，三年歎逐臣。上書憂漢室，作賦吊靈均。", "舊宅秋荒草，西風客薦蘋。淒涼回首處，不見洛陽人。"]'),
('yuding-45','冬日有懷李賀長吉','戴叔倫','唐','御定全唐诗','yuding','','[]','歲晚齋居寂，情人動我思。每因一尊酒，重和百篇詩。',48,'御定全唐詩/json/273.json','["歲晚齋居寂，情人動我思。每因一尊酒，重和百篇詩。", "月冷猿啼慘，天高雁去遲。夜郎流落久，何日是歸期。"]'),
('yuding-46','送郎士元','戴叔倫','唐','御定全唐诗','yuding','','[]','白髮金陵客，懷歸不暫留。交情分兩地，行色載孤舟。',48,'御定全唐詩/json/273.json','["白髮金陵客，懷歸不暫留。交情分兩地，行色載孤舟。", "黃葉蟬吟晚，滄江雁送秋。何年重會此，詩酒複追遊。"]'),
('yuding-47','春江獨釣','戴叔倫','唐','御定全唐诗','yuding','','[]','獨釣春江上，春江引趣長。斷煙棲草碧，流水帶花香。',48,'御定全唐詩/json/273.json','["獨釣春江上，春江引趣長。斷煙棲草碧，流水帶花香。", "心事同沙鳥，浮生寄野航。荷衣塵不染，何用濯滄浪。"]'),
('yuding-48','山居即事','戴叔倫','唐','御定全唐诗','yuding','','[]','岩雲掩竹扉，去鳥帶餘暉。地僻生涯薄，山深俗事稀。',48,'御定全唐詩/json/273.json','["岩雲掩竹扉，去鳥帶餘暉。地僻生涯薄，山深俗事稀。", "養花分宿雨，剪葉補秋衣。野渡逢漁子，同舟蕩月歸。"]'),
('yuding-49','賦得長亭柳','戴叔倫','唐','御定全唐诗','yuding','','[]','濯濯長亭柳，陰連灞水流。雨搓金縷細，煙褭翠絲柔。',48,'御定全唐詩/json/273.json','["濯濯長亭柳，陰連灞水流。雨搓金縷細，煙褭翠絲柔。", "送客添新恨，聽鶯憶舊遊。贈行多折取，那得到深秋。"]'),
('yuding-50','客中言懷','戴叔倫','唐','御定全唐诗','yuding','','[]','白髮照烏紗，逢人只自嗟。官閑如致仕，客久似無家。',48,'御定全唐詩/json/273.json','["白髮照烏紗，逢人只自嗟。官閑如致仕，客久似無家。", "夜雨孤燈夢，春風幾度花。故園歸有日，詩酒老生涯。"]'),
('yuding-51','山行','戴叔倫','唐','御定全唐诗','yuding','','[]','山行分曙色，一路見人稀。野鳥啼還歇，林花墮不飛。',48,'御定全唐詩/json/273.json','["山行分曙色，一路見人稀。野鳥啼還歇，林花墮不飛。", "雲迷棲鶴寺，水澀釣魚磯。回首天將暝，逢僧話未歸。"]'),
('yuding-52','春日訪山人','戴叔倫','唐','御定全唐诗','yuding','','[]','遠訪山中客，分泉謾煮茶。相攜林下坐，共惜鬢邊華。',48,'御定全唐詩/json/273.json','["遠訪山中客，分泉謾煮茶。相攜林下坐，共惜鬢邊華。", "歸路逢殘雨，沿溪見落花。候門童子問，遊樂到誰家。"]'),
('yuding-53','臥病','戴叔倫','唐','御定全唐诗','yuding','','[]','門掩青山臥，莓苔積雨深。病多知藥性，客久見人心。',48,'御定全唐詩/json/273.json','["門掩青山臥，莓苔積雨深。病多知藥性，客久見人心。", "眾鳥趨林健，孤蟬抱葉吟。滄洲詩社散，無夢盍朋簪。"]'),
('yuding-54','贈月溪羽士','戴叔倫','唐','御定全唐诗','yuding','','[]','月明溪水上，誰識步虛聲。夜靜金波冷，風微玉練平。',48,'御定全唐詩/json/273.json','["月明溪水上，誰識步虛聲。夜靜金波冷，風微玉練平。", "自知塵夢遠，一洗道心清。更弄瑤笙罷，秋空鶴又鳴。"]'),
('yuding-55','贈行腳僧','戴叔倫','唐','御定全唐诗','yuding','','[]','補衲隨緣住，難違塵外蹤。木杯能渡水，鐵缽肯降龍。',48,'御定全唐詩/json/273.json','["補衲隨緣住，難違塵外蹤。木杯能渡水，鐵缽肯降龍。", "到處棲雲榻，何年臥雪峰。知師歸日近，應偃舊房松。"]'),
('yuding-56','重遊長真寺','戴叔倫','唐','御定全唐诗','yuding','','[]','同到長真寺，青山四面同。鳥啼花竹暗，人散戶庭空。',48,'御定全唐詩/json/273.json','["同到長真寺，青山四面同。鳥啼花竹暗，人散戶庭空。", "蒲澗千年雨，松門午夜風。舊遊悲往日，回首各西東。"]'),
('yuding-57','晚望','戴叔倫','唐','御定全唐诗','yuding','','[]','山氣碧氤氳，深林帶夕曛。人歸孤嶂晚，犬吠隔溪雲。',48,'御定全唐詩/json/273.json','["山氣碧氤氳，深林帶夕曛。人歸孤嶂晚，犬吠隔溪雲。", "杉竹何年種，煙塵此地分。桃源寧異此，猶恐世間聞。"]'),
('yuding-58','寄贈翠岩奉上人','戴叔倫','唐','御定全唐诗','yuding','','[]','蘭若倚西岡，年深松桂長。似聞葛洪井，還近贊公房。',48,'御定全唐詩/json/273.json','["蘭若倚西岡，年深松桂長。似聞葛洪井，還近贊公房。", "掛衲雲林淨，翻經石榻涼。下方一回首，煙露日蒼蒼。"]'),
('yuding-59','過龍灣五王閣訪友人不遇','戴叔倫','唐','御定全唐诗','yuding','','[]','野橋秋水落，江閣暝煙微。白日又欲午，高人猶未歸。',48,'御定全唐詩/json/273.json','["野橋秋水落，江閣暝煙微。白日又欲午，高人猶未歸。", "青林依古塔，虛館靜柴扉。坐久思題字，翻憐柿葉稀。"]'),
('yuding-60','與友人過山寺','戴叔倫','唐','御定全唐诗','yuding','','[]','共有春山興，幽尋此日同。談詩訪靈徹，入社愧陶公。',48,'御定全唐詩/json/273.json','["共有春山興，幽尋此日同。談詩訪靈徹，入社愧陶公。", "竹暗閒房雨，茶香別院風。誰知塵境外，路與白雲通。"]'),
('yuding-61','賦得古井送王明府','戴叔倫','唐','御定全唐诗','yuding','','[]','古井庇幽亭，涓涓一竇明。仙源通海水，靈液孕山精。',48,'御定全唐詩/json/273.json','["古井庇幽亭，涓涓一竇明。仙源通海水，靈液孕山精。", "久旱寧同涸，長年只自清。欲彰貞白操，酌獻使君行。"]'),
('yuding-62','送耿十三湋複往遼海','戴叔倫','唐','御定全唐诗','yuding','','[]','仗劍萬里去，孤城遼海東。旌旗愁落日，鼓角壯悲風。',48,'御定全唐詩/json/273.json','["仗劍萬里去，孤城遼海東。旌旗愁落日，鼓角壯悲風。", "野迥邊塵息，烽消戍壘空。轅門正休暇，投策拜元戎。"]'),
('yuding-63','寄禪師寺華上人次韻三首','戴叔倫','唐','御定全唐诗','yuding','','[]','百年渾是客，白髮總盈顛。佛國三秋別，雲台五色連。',144,'御定全唐詩/json/273.json','["百年渾是客，白髮總盈顛。佛國三秋別，雲台五色連。", "朝盤香積飯，夜甕落花泉。遙憶談玄地，月高人未眠。", "禪心如落葉，不逐曉風顛。猊坐翻蕭瑟，皋比喜接連。", "芙蓉開紫霧，湘玉映清泉。白晝談經罷，閑從石上眠。", "德士名難避，風流學濟顛。禮羅加璧至，薦鶚與雲連。", "塵世休飛錫，松林且枕泉。近聞離講席，聽雨半山眠。"]'),
('yuding-64','獨坐','戴叔倫','唐','御定全唐诗','yuding','','[]','白髮懷閩嶠，丹心戀薊門。官閑勝道院，宅遠類荒村。',48,'御定全唐詩/json/273.json','["白髮懷閩嶠，丹心戀薊門。官閑勝道院，宅遠類荒村。", "二月霜花薄，群山雨氣昏。東菑春事及，好向野人論。"]'),
('yuding-65','李大夫見贈因之有呈','戴叔倫','唐','御定全唐诗','yuding','','[]','何言訪衰疾，旌旆重淹留。謝禮誠難答，裁詩豈易酬。',48,'御定全唐詩/json/273.json','["何言訪衰疾，旌旆重淹留。謝禮誠難答，裁詩豈易酬。", "江清寒照動，山迥野雲秋。一醉龍沙上，終歡勝舊遊。"]'),
('yuding-66','長沙送梁副端歸京','戴叔倫','唐','御定全唐诗','yuding','','[]','奏書歸闕下，祖帳出湘東。滿座他鄉別，何年此會同。',48,'御定全唐詩/json/273.json','["奏書歸闕下，祖帳出湘東。滿座他鄉別，何年此會同。", "藉芳憐岸草，聞笛怨江風。且莫乘流去，心期在醉中。"]'),
('yuding-67','和尉遲侍郎夏杪聞蟬','戴叔倫','唐','御定全唐诗','yuding','','[]','楚人方苦熱，柱史獨聞蟬。晴日暮江上，驚風一葉前。',48,'御定全唐詩/json/273.json','["楚人方苦熱，柱史獨聞蟬。晴日暮江上，驚風一葉前。", "蕩搖清管雜，幽咽野風傳。旅舍聞君聽，無由更晝眠。"]'),
('yuding-68','和李相公勉晦日蓬池遊宴','戴叔倫','唐','御定全唐诗','yuding','','[]','高會吹台中，新年月桂空。貂蟬臨野水，旌旆引春風。',48,'御定全唐詩/json/273.json','["高會吹台中，新年月桂空。貂蟬臨野水，旌旆引春風。", "細草縈斜岸，纖條出故叢。微文複看獵，甯與解神同。"]'),
('yuding-69','彭婆館逢韋判官使還','戴叔倫','唐','御定全唐诗','yuding','','[]','受辭分路遠，會府見君稀。雨雪經年去，軒車此日歸。',48,'御定全唐詩/json/273.json','["受辭分路遠，會府見君稀。雨雪經年去，軒車此日歸。", "暮春愁見別，久客順相依。寂寞伊川上，楊花空自飛。"]'),
('yuding-70','酬別劉九郎評事傳經同泉字','戴叔倫','唐','御定全唐诗','yuding','','[]','舉袂掩離弦，枉君愁思篇。忽驚池上鷺，下嚥隴頭泉。',48,'御定全唐詩/json/273.json','["舉袂掩離弦，枉君愁思篇。忽驚池上鷺，下嚥隴頭泉。", "對牖牆陰滿，臨扉日影圓。賴聞黃太守，章句此中傳。"]'),
('yuding-71','漢南遇方評事','戴叔倫','唐','御定全唐诗','yuding','','[]','移家住漢陰，不復問華簪。貰酒宜城近，燒田夢澤深。',48,'御定全唐詩/json/273.json','["移家住漢陰，不復問華簪。貰酒宜城近，燒田夢澤深。", "暮山逢鳥入，寒水見魚沈。與物皆無累，終年愜本心。"]'),
('yuding-72','湘中懷古','戴叔倫','唐','御定全唐诗','yuding','','[]','昔人從逝水，有客吊秋風。何意千年隔，論心一日同。',48,'御定全唐詩/json/273.json','["昔人從逝水，有客吊秋風。何意千年隔，論心一日同。", "楚亭方作亂，漢律正酬功。倏忽桑田變，讒言亦已空。"]'),
('yuding-73','京口懷古','戴叔倫','唐','御定全唐诗','yuding','','[]','大江橫萬里，古渡渺千秋。浩浩波聲險，蒼蒼天色愁。',48,'御定全唐詩/json/273.json','["大江橫萬里，古渡渺千秋。浩浩波聲險，蒼蒼天色愁。", "三方歸漢鼎，一水限吳州。霸國今何在，清泉長自流。"]'),
('yuding-74','逢友生言懷','戴叔倫','唐','御定全唐诗','yuding','','[]','安親非避地，羈旅十餘年。道長時流許，家貧故舊憐。',48,'御定全唐詩/json/273.json','["安親非避地，羈旅十餘年。道長時流許，家貧故舊憐。", "相逢今歲暮，遠別一方偏。去住俱難說，江湖正渺然。"]'),
('yuding-75','長門怨','戴叔倫','唐','御定全唐诗','yuding','','[]','自憶專房寵，曾居第一流。移恩向他處，暫妒不容收。',48,'御定全唐詩/json/273.json','["自憶專房寵，曾居第一流。移恩向他處，暫妒不容收。", "夜靜管弦絕，月明宮殿秋。空將舊時意，長望鳳凰樓。"]'),
('yuding-76','郊園即事寄蕭侍郎','戴叔倫','唐','御定全唐诗','yuding','','[]','衰鬢辭餘秩，秋風入故園。結茅成暖室，汲井及清源。',48,'御定全唐詩/json/273.json','["衰鬢辭餘秩，秋風入故園。結茅成暖室，汲井及清源。", "鄰里桑麻接，兒童笑語喧。終朝非役役，聊寄遠人言。"]'),
('yuding-77','贈韋評事攢','戴叔倫','唐','御定全唐诗','yuding','','[]','與道共浮沈，人間歲月深。是非園吏夢，憂喜塞翁心。',48,'御定全唐詩/json/273.json','["與道共浮沈，人間歲月深。是非園吏夢，憂喜塞翁心。", "細草誰開徑，芳條自結陰。由來居物外，無事可抽簪。"]'),
('yuding-78','送少微上人入蜀','戴叔倫','唐','御定全唐诗','yuding','','[]','十方俱是夢，一念偶尋山。望刹經巴寺，持瓶向蜀關。',48,'御定全唐詩/json/273.json','["十方俱是夢，一念偶尋山。望刹經巴寺，持瓶向蜀關。", "亂猿心本定，流水性長閑。世俗多離別，王城幾日還。"]'),
('yuding-79','送道虔上人游方','戴叔倫','唐','御定全唐诗','yuding','','[]','律儀通外學，詩思入禪關。煙景隨緣到，風姿與道閑。',48,'御定全唐詩/json/273.json','["律儀通外學，詩思入禪關。煙景隨緣到，風姿與道閑。", "貫花留靜室，咒水度空山。誰識浮雲意，悠悠天地間。"]'),
('yuding-80','送嵩律師頭陀寺','戴叔倫','唐','御定全唐诗','yuding','','[]','相傳五部學，更有一人成。此日靈山去，何方半座迎。',48,'御定全唐詩/json/273.json','["相傳五部學，更有一人成。此日靈山去，何方半座迎。", "麻衣逢雪暖，草履躡雲輕。若見中林石，應知第四生。"]'),
('yuding-81','舟中見雨','戴叔倫','唐','御定全唐诗','yuding','','[]','今夜初聽雨，江南杜若青。功名何鹵莽，兄弟總凋零。',48,'御定全唐詩/json/273.json','["今夜初聽雨，江南杜若青。功名何鹵莽，兄弟總凋零。", "夢遠愁蝴蝶，情深愧鶺鴒。撫孤終日意，身世尚流萍。"]'),
('yuding-82','送僧南歸','戴叔倫','唐','御定全唐诗','yuding','','[]','兵塵猶澒洞，僧舍亦徵求。師向江南去，予方轂下留。',48,'御定全唐詩/json/273.json','["兵塵猶澒洞，僧舍亦徵求。師向江南去，予方轂下留。", "風霜兩足白，宇宙一身浮。歸及梅花發，題詩寄隴頭。"]'),
('yuding-83','江幹','戴叔倫','唐','御定全唐诗','yuding','','[]','江幹望不極，樓閣影繽紛。水氣多為雨，人煙遠是雲。',48,'御定全唐詩/json/273.json','["江幹望不極，樓閣影繽紛。水氣多為雨，人煙遠是雲。", "予生何濩落，客路轉辛勤。楊柳牽愁思，和春上翠裙。"]'),
('yuding-84','過友人隱居','戴叔倫','唐','御定全唐诗','yuding','','[]','瀟灑絕塵喧，清溪流繞門。水聲鳴石瀨，蘿影到林軒。',48,'御定全唐詩/json/273.json','["瀟灑絕塵喧，清溪流繞門。水聲鳴石瀨，蘿影到林軒。", "地靜留眠鹿，庭虛下飲猿。春花正夾岸，何必問桃源。"]'),
('yuding-85','宿天竺寺曉發羅源','戴叔倫','唐','御定全唐诗','yuding','','[]','黃昏投古寺，深院一燈明。水砌長杉列，風廊敗葉鳴。',48,'御定全唐詩/json/273.json','["黃昏投古寺，深院一燈明。水砌長杉列，風廊敗葉鳴。", "山雲留別偈，王事速歸程。迢遞羅源路，輕輿候曉行。"]'),
('yuding-86','留宿羅源西峰寺示輝上人','戴叔倫','唐','御定全唐诗','yuding','','[]','一宿西峰寺，塵煩暫覺清。遠林生夕籟，高閣起鐘聲。',48,'御定全唐詩/json/273.json','["一宿西峰寺，塵煩暫覺清。遠林生夕籟，高閣起鐘聲。", "山寂僧初定，廊深火自明。雖雲殊出處，聊與說無生。"]'),
('yuding-87','題橫山寺','戴叔倫','唐','御定全唐诗','yuding','','[]','偶入橫山寺，湖山景最幽。露涵松翠濕，風湧浪花浮。',48,'御定全唐詩/json/273.json','["偶入橫山寺，湖山景最幽。露涵松翠濕，風湧浪花浮。", "老衲供茶碗，斜陽送客舟。自緣歸思促，不得更遲留。"]'),
('yuding-88','泛舟','戴叔倫','唐','御定全唐诗','yuding','','[]','風軟扁舟穩，行依綠水堤。孤尊秋露滑，短棹晚煙迷。',48,'御定全唐詩/json/273.json','["風軟扁舟穩，行依綠水堤。孤尊秋露滑，短棹晚煙迷。", "夜靜月初上，江空天更低。飄飄信流去，誤過子猷溪。"]'),
('yuding-89','宿靈岩寺','戴叔倫','唐','御定全唐诗','yuding','','[]','馬疲盤道峻，投宿入招提。雨急山溪漲，雲迷嶺樹低。',48,'御定全唐詩/json/273.json','["馬疲盤道峻，投宿入招提。雨急山溪漲，雲迷嶺樹低。", "涼風來殿角，赤日下天西。偃腹虛簷外，林空鳥恣啼。"]'),
('yuding-90','江上別劉駕','戴叔倫','唐','御定全唐诗','yuding','','[]','天涯芳草遍，江路又逢春。海月留人醉，山花笑客貧。',48,'御定全唐詩/json/273.json','["天涯芳草遍，江路又逢春。海月留人醉，山花笑客貧。", "離杯傾祖帳，征騎逐行塵。回首風流地，登臨少一人。"]'),
('yuding-91','南軒','戴叔倫','唐','御定全唐诗','yuding','','[]','野居何處是，軒外一橫塘。座納熏風細，簾垂白日長。',48,'御定全唐詩/json/273.json','["野居何處是，軒外一橫塘。座納熏風細，簾垂白日長。", "面山如對畫，臨水坐流觴。更愛閑花木，欣欣得向陽。"]'),
('yuding-92','泊雁','戴叔倫','唐','御定全唐诗','yuding','','[]','泊雁鳴深渚，收霞落晚川。柝隨風斂陣，樓映月低弦。',48,'御定全唐詩/json/273.json','["泊雁鳴深渚，收霞落晚川。柝隨風斂陣，樓映月低弦。", "漠漠汀帆轉，幽幽岸火然。壑危通細路，溝曲繞平田。"]'),
('yuding-93','巡諸州漸次空靈戍','戴叔倫','唐','御定全唐诗','yuding','','[]','寒盡鴻先至，春回客未歸。蚤知名是病，不敢繡為衣。',48,'御定全唐詩/json/273.json','["寒盡鴻先至，春回客未歸。蚤知名是病，不敢繡為衣。", "霧積川原暗，山多郡縣稀。明朝下湘岸，更逐鷓鴣飛。"]'),
('yuding-94','潭州使院書情寄江夏賀蘭副端','戴叔倫','唐','御定全唐诗','yuding','','[]','雲雨一蕭散，悠悠關複河。俱從泛舟役，近隔洞庭波。',48,'御定全唐詩/json/273.json','["雲雨一蕭散，悠悠關複河。俱從泛舟役，近隔洞庭波。", "楚水去不盡，秋風今又過。無因得相見，卻恨寄書多。"]'),
('yuding-95','過柳州','戴叔倫','唐','御定全唐诗','yuding','','[]','地盡江南戍，山分桂北林。火雲三月合，石路九疑深。',48,'御定全唐詩/json/273.json','["地盡江南戍，山分桂北林。火雲三月合，石路九疑深。", "暗穀隨風過，危橋共鳥尋。羈魂愁似絕，不復待猿吟。"]'),
('yuding-96','經巴東嶺','戴叔倫','唐','御定全唐诗','yuding','','[]','巴山不可上，徒馭亦裴回。舊棧歌難度，朝雲濕未開。',48,'御定全唐詩/json/273.json','["巴山不可上，徒馭亦裴回。舊棧歌難度，朝雲濕未開。", "瀑泉飛雪雨，驚獸走風雷。此去無停候，征人幾日回。"]'),
('yuding-97','過申州','戴叔倫','唐','御定全唐诗','yuding','','[]','萬人曾戰死，幾處見休兵。井邑初安堵，兒童未長成。',48,'御定全唐詩/json/273.json','["萬人曾戰死，幾處見休兵。井邑初安堵，兒童未長成。", "涼風吹古木，野火入殘營。牢落千餘裏，山空水複清。"]'),
('yuding-98','次下牢韻','戴叔倫','唐','御定全唐诗','yuding','','[]','獨立荒亭上，蕭蕭對晚風。天高吳塞闊，日落楚山空。',48,'御定全唐詩/json/273.json','["獨立荒亭上，蕭蕭對晚風。天高吳塞闊，日落楚山空。", "猿叫三聲斷，江流一水通。前程千萬里，一夕宿巴東。"]'),
('yuding-99','潘處士宅會別','戴叔倫','唐','御定全唐诗','yuding','','[]','相邀寒影晚，惜別故山空。鄰里疏林在，池塘野水通。',48,'御定全唐詩/json/273.json','["相邀寒影晚，惜別故山空。鄰里疏林在，池塘野水通。", "十年難遇後，一醉幾人同。複此悲行子，蕭蕭逐轉蓬。"]'),
('yuding-100','暮春沐發晦日書懷寄韋功曹渢李錄事從訓王少府純','戴叔倫','唐','御定全唐诗','yuding','','[]','朝沐敞南闈，盤跚待日晞。持梳發更落，覽鏡意多違。',48,'御定全唐詩/json/273.json','["朝沐敞南闈，盤跚待日晞。持梳發更落，覽鏡意多違。", "吾友見嘗少，春風去不歸。登高取一醉，猶可及芳菲。"]'),
('yuding-101','長安早春贈萬評事','戴叔倫','唐','御定全唐诗','yuding','','[]','春風歸戚裏，曉日上花枝。清管新鶯發，重門細柳垂。',48,'御定全唐詩/json/273.json','["春風歸戚裏，曉日上花枝。清管新鶯發，重門細柳垂。", "經過千騎客，調笑五陵兒。何事靈台客，狂歌自不知。"]'),
('yuding-102','留別宋處士','戴叔倫','唐','御定全唐诗','yuding','','[]','留歡方繼燭，此會豈他人。鄉里游從舊，兒童內外親。',48,'御定全唐詩/json/273.json','["留歡方繼燭，此會豈他人。鄉里游從舊，兒童內外親。", "夜深愁不醉，老去別何頻。莫折園中柳，相看惜暮春。"]'),
('yuding-103','留別道州李使君圻','戴叔倫','唐','御定全唐诗','yuding','','[]','瀧路下丹徼，郵童揮畫橈。山回千騎隱，雲斷兩鄉遙。',48,'御定全唐詩/json/273.json','["瀧路下丹徼，郵童揮畫橈。山回千騎隱，雲斷兩鄉遙。", "漁滬擁寒溜，佘田落遠燒。維舟更相憶，惆悵坐空宵。"]'),
('yuding-104','將遊東都留別包諫議','戴叔倫','唐','御定全唐诗','yuding','','[]','衰客慚墨綬，素舸逐秋風。雲雨恩難報，江湖意已終。',48,'御定全唐詩/json/273.json','["衰客慚墨綬，素舸逐秋風。雲雨恩難報，江湖意已終。", "縣當仙洞口，路出故園東。唯有新離恨，長留夢寐中。"]'),
('yuding-105','灞岸別友','戴叔倫','唐','御定全唐诗','yuding','','[]','車馬去遲遲，離言未盡時。看花一醉別，會面幾年期。',48,'御定全唐詩/json/273.json','["車馬去遲遲，離言未盡時。看花一醉別，會面幾年期。", "樵路高山館，漁洲楚帝祠。南登回首處，猶得望京師。"]'),
('yuding-106','臨川從事還別崔法曹','戴叔倫','唐','御定全唐诗','yuding','','[]','謬官辭獲免，濫獄會平反。遠與故人別，龍鍾望所言。',48,'御定全唐詩/json/273.json','["謬官辭獲免，濫獄會平反。遠與故人別，龍鍾望所言。", "陰天寒不雨，古木夜多猿。老病北歸去，餘年學灌園。"]'),
('yuding-107','海上別薛舟','戴叔倫','唐','御定全唐诗','yuding','','[]','行旅悲搖落，風波厭別離。客程秋草遠，心事故人知。',48,'御定全唐詩/json/273.json','["行旅悲搖落，風波厭別離。客程秋草遠，心事故人知。", "暮鳥翻江岸，征徒起路岐。自應無定所，還似欲相隨。"]'),
('yuding-108','婺州路別錄事','戴叔倫','唐','御定全唐诗','yuding','','[]','府中相見少，江上獨行遙。會日起離恨，新年別舊僚。',48,'御定全唐詩/json/273.json','["府中相見少，江上獨行遙。會日起離恨，新年別舊僚。", "春雲猶伴雪，寒渚未通潮。回首群山暝，思君轉寂寥。"]'),
('yuding-109','建中癸亥歲奉天除夜宿武當山北茅平村','戴叔倫','唐','御定全唐诗','yuding','','[]','歲除日又暮，山險路仍新。驅傳迷深谷，瞻星記北辰。',48,'御定全唐詩/json/273.json','["歲除日又暮，山險路仍新。驅傳迷深谷，瞻星記北辰。", "古亭聊假寐，中夜忽逢人。相問皆嗚咽，傷心不待春。"]'),
('yuding-110','京口送皇甫司馬副端曾舒州辭滿歸去東都','戴叔倫','唐','御定全唐诗','yuding','','[]','潮水忽複過，雲帆儼欲飛。故園雙闕下，左宦十年歸。',48,'御定全唐詩/json/273.json','["潮水忽複過，雲帆儼欲飛。故園雙闕下，左宦十年歸。", "晚景照華髮，涼風吹繡衣。淹留更一醉，老去莫相違。"]'),
('yuding-111','送李審之桂州謁中丞叔','戴叔倫','唐','御定全唐诗','yuding','','[]','知音不可遇，才子向天涯。遠水下山急，孤舟上路賒。',48,'御定全唐詩/json/273.json','["知音不可遇，才子向天涯。遠水下山急，孤舟上路賒。", "亂雲收暮雨，雜樹落疏花。到日應文會，風流勝阮家。"]'),
('yuding-112','送王翁信及第歸江東舊隱','戴叔倫','唐','御定全唐诗','yuding','','[]','南行無俗侶，秋雁與寒雲。野趣自多愜，名香日總聞。',48,'御定全唐詩/json/273.json','["南行無俗侶，秋雁與寒雲。野趣自多愜，名香日總聞。", "吳山中路斷，浙水半江分。此地登臨慣，含情一送君。"]'),
('yuding-113','送李明府之任','戴叔倫','唐','御定全唐诗','yuding','','[]','身為百里長，家寵五諸侯。含笑聽猿狖，搖鞭望鬥牛。',48,'御定全唐詩/json/273.json','["身為百里長，家寵五諸侯。含笑聽猿狖，搖鞭望鬥牛。", "梅花堪比雪，芳草不知秋。別後南風起，相思夢嶺頭。"]'),
('yuding-114','送郭太祝中孚歸江東','戴叔倫','唐','御定全唐诗','yuding','','[]','鄉人去欲盡，北雁又南飛。京洛風塵久，江湖音信稀。',48,'御定全唐詩/json/273.json','["鄉人去欲盡，北雁又南飛。京洛風塵久，江湖音信稀。", "舊山知獨往，一醉莫相違。未得辭羈旅，無勞問是非。"]'),
('yuding-115','新秋夜寄江右友人','戴叔倫','唐','御定全唐诗','yuding','','[]','遙夜獨不寐，寂寥蓬戶中。河明五陵上，月滿九門東。',48,'御定全唐詩/json/273.json','["遙夜獨不寐，寂寥蓬戶中。河明五陵上，月滿九門東。", "舊知親友散，故園江海空。懷歸正南望，此夕起秋風。"]'),
('yuding-116','清明日送鄧芮二子還鄉','戴叔倫','唐','御定全唐诗','yuding','','[]','鐘鼓喧離日，車徒促夜裝。曉廚新變火，輕柳暗翻霜。',48,'御定全唐詩/json/273.json','["鐘鼓喧離日，車徒促夜裝。曉廚新變火，輕柳暗翻霜。", "傳鏡看華髮，持杯話故鄉。每嫌兒女淚，今日自沾裳。"]'),
('yuding-117','送謝夷甫宰餘姚縣','戴叔倫','唐','御定全唐诗','yuding','','[]','君去方為宰，干戈尚未銷。邑中殘老小，亂後少官僚。',48,'御定全唐詩/json/273.json','["君去方為宰，干戈尚未銷。邑中殘老小，亂後少官僚。", "廨宇經兵火，公田沒海潮。到時應變俗，新政滿餘姚。"]'),
('yuding-118','送柳道時餘北還','戴叔倫','唐','御定全唐诗','yuding','','[]','征役各異路，煙波同旅愁。輕橈上桂水，大艑下揚州。',48,'御定全唐詩/json/273.json','["征役各異路，煙波同旅愁。輕橈上桂水，大艑下揚州。", "何處成後會，今朝分舊遊。離心比楊柳，蕭颯不勝秋。"]'),
('yuding-119','送萬戶曹之任揚州便歸舊隱','戴叔倫','唐','御定全唐诗','yuding','','[]','擬歸雲壑去，聊寄宦名中。俸祿資生事，文章實國風。',48,'御定全唐詩/json/273.json','["擬歸雲壑去，聊寄宦名中。俸祿資生事，文章實國風。", "聽潮回楚浪，看月照隋宮。儻有登樓望，還應伴庾公。"]'),
('yuding-120','送李長史縱之任常州','戴叔倫','唐','御定全唐诗','yuding','','[]','不與名利隔，且為江漢遊。吳山本佳麗，謝客舊淹留。',48,'御定全唐詩/json/273.json','["不與名利隔，且為江漢遊。吳山本佳麗，謝客舊淹留。", "狹道通陵口，貧家住蔣州。思歸複怨別，寥落詎關秋。"]'),
('yuding-121','南賓送蔡侍禦游蜀','戴叔倫','唐','御定全唐诗','yuding','','[]','巴江秋欲盡，遠別更淒然。月照高唐峽，人隨賈客船。',48,'御定全唐詩/json/273.json','["巴江秋欲盡，遠別更淒然。月照高唐峽，人隨賈客船。", "積雲藏嶮路，流水促行年。不料相逢日，空悲尊酒前。"]'),
('yuding-122','送崔拾遺峒江淮訪圖書','戴叔倫','唐','御定全唐诗','yuding','','[]','九門思諫議，萬里采風謠。關外逢秋月，天涯過晚潮。',48,'御定全唐詩/json/273.json','["九門思諫議，萬里采風謠。關外逢秋月，天涯過晚潮。", "雁來雲杳杳，木落浦蕭蕭。空怨他鄉別，回舟暮寂寥。"]'),
('yuding-123','九日送洛陽李丞之任','戴叔倫','唐','御定全唐诗','yuding','','[]','為文通絕境，從宦及良辰。洛下知名早，腰邊結綬新。',48,'御定全唐詩/json/273.json','["為文通絕境，從宦及良辰。洛下知名早，腰邊結綬新。", "且傾浮菊酒，聊拂染衣塵。獨恨滄波侶，秋來別故人。"]'),
('yuding-124','奉陪李大夫九日宴龍沙','戴叔倫','唐','御定全唐诗','yuding','','[]','邦君采菊地，近接旅人居。一命招衰疾，清光照裏閭。',48,'御定全唐詩/json/273.json','["邦君采菊地，近接旅人居。一命招衰疾，清光照裏閭。", "去官慚比謝，下榻貴同徐。莫怪沙邊倒，偏沾杯酌餘。"]'),
('yuding-125','送車參軍江陵','戴叔倫','唐','御定全唐诗','yuding','','[]','槐花落盡柳陰清，蕭索涼天楚客情。海上舊山無的信，',40,'御定全唐詩/json/273.json','["槐花落盡柳陰清，蕭索涼天楚客情。海上舊山無的信，", "公子道存知不棄，欲依劉表住南荊。"]'),
('yuding-126','游清溪蘭若','戴叔倫','唐','御定全唐诗','yuding','','[]','西看疊嶂幾千重，秀色孤標此一峰。丹灶久閑荒宿草，',40,'御定全唐詩/json/273.json','["西看疊嶂幾千重，秀色孤標此一峰。丹灶久閑荒宿草，", "遠對白雲幽隱在，年年不離舊杉松。"]'),
('yuding-127','贈史開府','戴叔倫','唐','御定全唐诗','yuding','','[]','南天胡馬獨悲嘶，白首相逢話鼓鼙。野戰頻年沙朔外，',40,'御定全唐詩/json/273.json','["南天胡馬獨悲嘶，白首相逢話鼓鼙。野戰頻年沙朔外，", "早晚瑤階歸伏奏，獨能畫地取關西。"]'),
('yuding-128','登樓望月寄鳳翔李少尹','戴叔倫','唐','御定全唐诗','yuding','','[]','陌上涼風槐葉凋，夕陽清露濕寒條。登樓望月楚山迥，',40,'御定全唐詩/json/273.json','["陌上涼風槐葉凋，夕陽清露濕寒條。登樓望月楚山迥，", "軒轅不重無名客，此地還能訪寂寥。"]'),
('yuding-129','和汴州李相公勉人日喜春','戴叔倫','唐','御定全唐诗','yuding','','[]','年來日日春光好，今日春光好更新。獨獻菜羹憐應節，',40,'御定全唐詩/json/273.json','["年來日日春光好，今日春光好更新。獨獻菜羹憐應節，", "東合此時聞一曲，翻令和者不勝春。"]'),
('yuding-130','奉酬盧端公飲後贈諸公見示之作','戴叔倫','唐','御定全唐诗','yuding','','[]','佐幕臨戎旌旆間，五營無事萬家閑。風吹楊柳漸拂地，',40,'御定全唐詩/json/273.json','["佐幕臨戎旌旆間，五營無事萬家閑。風吹楊柳漸拂地，", "當時不敢辭先醉，誤逐群公倒載還。"]'),
('yuding-131','贈司空拾遺','戴叔倫','唐','御定全唐诗','yuding','','[]','侍臣何事辭雲陛，江上彈冠見雪花。望闕未承丹鳳詔，',40,'御定全唐詩/json/273.json','["侍臣何事辭雲陛，江上彈冠見雪花。望闕未承丹鳳詔，", "高館更容塵外客，仍令歸去待瓊華。"]'),
('yuding-132','越溪村居','戴叔倫','唐','御定全唐诗','yuding','','[]','年來橈客寄禪扉，多話貧居在翠微。黃雀數聲催柳變，',40,'御定全唐詩/json/273.json','["年來橈客寄禪扉，多話貧居在翠微。黃雀數聲催柳變，", "負米到家春未盡，風蘿閑掃釣魚磯。"]'),
('yuding-133','贈韓道士','戴叔倫','唐','御定全唐诗','yuding','','[]','日暮秋風吹野花，上清歸客意無涯。桃源寂寂煙霞閉，',40,'御定全唐詩/json/273.json','["日暮秋風吹野花，上清歸客意無涯。桃源寂寂煙霞閉，", "東城南陌頻相見，應是壺中別有家。"]'),
('yuding-134','寄萬德躬故居','戴叔倫','唐','御定全唐诗','yuding','','[]','日暮山風吹女蘿，故人舟楫定如何。呂仙祠下寒砧急，',40,'御定全唐詩/json/273.json','["日暮山風吹女蘿，故人舟楫定如何。呂仙祠下寒砧急，", "何時醉把黃花酒，聽爾南征長短歌。"]'),
('yuding-135','寄司空曙','戴叔倫','唐','御定全唐诗','yuding','','[]','細雨柴門生遠愁，向來詩句若為酬。林花落處頻中酒，',40,'御定全唐詩/json/273.json','["細雨柴門生遠愁，向來詩句若為酬。林花落處頻中酒，", "可能相別還相憶，莫遣楊花笑白頭。"]'),
('yuding-136','過故人陳羽山居','戴叔倫','唐','御定全唐诗','yuding','','[]','向來攜酒共追攀，此日看雲獨未還。不見山中人半載，',40,'御定全唐詩/json/273.json','["向來攜酒共追攀，此日看雲獨未還。不見山中人半載，", "卻望夏洋懷二妙，滿崖霜樹曉斑斑。"]'),
('yuding-137','吊暢當','戴叔倫','唐','御定全唐诗','yuding','','[]','萬里江南一布衣，早將佳句動京畿。徒聞子敬遺琴在，',40,'御定全唐詩/json/273.json','["萬里江南一布衣，早將佳句動京畿。徒聞子敬遺琴在，", "玉堂知己能銘述，猶得精魂慰所依。"]'),
('yuding-138','寄劉禹錫','戴叔倫','唐','御定全唐诗','yuding','','[]','謝相園西石徑斜，知君習隱暫為家。有時出郭行芳草，',40,'御定全唐詩/json/273.json','["謝相園西石徑斜，知君習隱暫為家。有時出郭行芳草，", "五年不見西山色，悵望浮雲隱落霞。"]'),
('yuding-139','寄孟郊','戴叔倫','唐','御定全唐诗','yuding','','[]','亂餘城郭怕經過，到處閑門長薜蘿。用世空悲聞道淺，',40,'御定全唐詩/json/273.json','["亂餘城郭怕經過，到處閑門長薜蘿。用世空悲聞道淺，", "石上幽期春又暮，何時載酒聽高歌。"]'),
('yuding-140','贈徐山人','戴叔倫','唐','御定全唐诗','yuding','','[]','亂餘山水半凋殘，江上逢君春正闌。針自指南天窅窅，',40,'御定全唐詩/json/273.json','["亂餘山水半凋殘，江上逢君春正闌。針自指南天窅窅，", "回首風塵千裏外，故園煙雨五峰寒。"]'),
('yuding-141','過賈誼舊居','戴叔倫','唐','御定全唐诗','yuding','','[]','楚鄉卑濕歎殊方，鵩賦人非宅已荒。謾有長書憂漢室，',40,'御定全唐詩/json/273.json','["楚鄉卑濕歎殊方，鵩賦人非宅已荒。謾有長書憂漢室，", "過客不須頻太息，咸陽宮殿亦淒涼。"]'),
('yuding-142','宮詞','戴叔倫','唐','御定全唐诗','yuding','','[]','紫禁迢迢宮漏鳴，夜深無語獨含情。春風鸞鏡愁中影，',40,'御定全唐詩/json/273.json','["紫禁迢迢宮漏鳴，夜深無語獨含情。春風鸞鏡愁中影，", "貞心一任蛾眉妒，買賦何須問馬卿。"]'),
('yuding-143','漢宮人入道','戴叔倫','唐','御定全唐诗','yuding','','[]','蕭蕭白髮出宮門，羽服星冠道意存。霄漢九重辭鳳闕，',40,'御定全唐詩/json/273.json','["蕭蕭白髮出宮門，羽服星冠道意存。霄漢九重辭鳳闕，", "回首吹簫天上伴，上陽花落共誰言。"]'),
('yuding-144','二靈寺守歲','戴叔倫','唐','御定全唐诗','yuding','','[]','守歲山房迥絕緣，燈光香灺共蕭然。無人更獻椒花頌，',40,'御定全唐詩/json/273.json','["守歲山房迥絕緣，燈光香灺共蕭然。無人更獻椒花頌，", "憂心悄悄渾忘寐，坐待扶桑日麗天。"]'),
('yuding-145','暮春感懷','戴叔倫','唐','御定全唐诗','yuding','','[]','杜宇聲聲喚客愁，故園何處此登樓。落花飛絮成春夢，',80,'御定全唐詩/json/273.json','["杜宇聲聲喚客愁，故園何處此登樓。落花飛絮成春夢，", "東皇去後韶華盡，老圃寒香別有秋。", "四十無聞懶慢身，放情丘壑任天真。悠悠往事杯中物，", "山花水鳥皆知己，百遍相過不厭貧。"]'),
('yuding-146','哭朱放','戴叔倫','唐','御定全唐诗','yuding','','[]','幾年湖海挹餘芳，豈料蘭摧一夜霜。人世空傳名耿耿，',40,'御定全唐詩/json/273.json','["幾年湖海挹餘芳，豈料蘭摧一夜霜。人世空傳名耿耿，", "最是不堪回首處，九泉煙冷樹蒼蒼。"]'),
('yuding-147','酬盩厔耿少府湋見寄','戴叔倫','唐','御定全唐诗','yuding','','[]','方丈蕭蕭落葉中，暮天深巷起悲風。流年不盡人自老，',40,'御定全唐詩/json/273.json','["方丈蕭蕭落葉中，暮天深巷起悲風。流年不盡人自老，", "遙聞相訪頻逢雪，一醉寒宵誰與同。"]'),
('yuding-148','贈慧上人','戴叔倫','唐','御定全唐诗','yuding','','[]','仙槎江口槎溪寺，幾度停舟訪未能。自恨頻年為遠客，',40,'御定全唐詩/json/273.json','["仙槎江口槎溪寺，幾度停舟訪未能。自恨頻年為遠客，", "何日卻飛真錫返，故人丘木翳寒藤。"]'),
('yuding-149','漸至涪州先寄王員外使君縱','戴叔倫','唐','御定全唐诗','yuding','','[]','文教通夷俗，均輸問火田。江分巴字水，樹入夜郎煙。',72,'御定全唐詩/json/273.json','["文教通夷俗，均輸問火田。江分巴字水，樹入夜郎煙。", "毒瘴含秋氣，陰崖蔽曙天。路難空計日，身老不由年。", "將命寧知遠，歸心詎可傳。星郎複何意，出守五溪邊。"]'),
('yuding-150','和河南羅主簿送校書兄歸江南','戴叔倫','唐','御定全唐诗','yuding','','[]','兄弟泣殊方，天涯指故鄉。斷雲無定處，歸雁不成行。',96,'御定全唐詩/json/273.json','["兄弟泣殊方，天涯指故鄉。斷雲無定處，歸雁不成行。", "草莽人煙少，風波水驛長。上虞親渤澥，東楚隔瀟湘。", "古戍陰傳火，寒蕪曉帶霜。海門潮灩灩，沙岸荻蒼蒼。", "京輦辭芸閣，蘅芳憶草堂。知君始寧隱，還緝舊荷裳。"]'),
('yuding-151','曉聞長樂鐘聲','戴叔倫','唐','御定全唐诗','yuding','','[]','漢苑鐘聲早，秦郊曙色分。霜淩萬戶徹，風散一城聞。',72,'御定全唐詩/json/273.json','["漢苑鐘聲早，秦郊曙色分。霜淩萬戶徹，風散一城聞。", "已啟蓬萊殿，初朝鴛鷺群。虛心方應物，大扣欲幹雲。", "近雜雞人唱，新傳鳧氏文。能令翰苑客，流聽思氛氳。"]'),
('yuding-152','聽霜鐘','戴叔倫','唐','御定全唐诗','yuding','','[]','渺渺飛霜夜，寥寥遠岫鐘。出雲疑斷續，入戶乍舂容。',72,'御定全唐詩/json/273.json','["渺渺飛霜夜，寥寥遠岫鐘。出雲疑斷續，入戶乍舂容。", "度枕頻驚夢，隨風幾韻松。悠揚來不已，杳靄去何從。", "仿佛煙嵐隔，依稀岩嶠重。此時聊一聽，餘響繞千峰。"]'),
('yuding-153','同前','戴叔倫','唐','御定全唐诗','yuding','','[]','寥亮來豐嶺，分明辨古鐘。應霜如自擊，中節每相從。',72,'御定全唐詩/json/273.json','["寥亮來豐嶺，分明辨古鐘。應霜如自擊，中節每相從。", "靜聽非閑扣，潛應蘊聖蹤。風間時斷續，雲外更舂容。", "虛警和清籟，雄鳴隔亂峰。因知諭知己，感激更難逢。"]'),
('yuding-0','酬崔法曹遺劍','戴叔倫','唐','御定全唐诗','yuding','','[]','臨風脫佩劍，相勸靜胡塵。自料無筋力，何由答故人。',24,'御定全唐詩/json/274.json','["臨風脫佩劍，相勸靜胡塵。自料無筋力，何由答故人。"]'),
('yuding-1','敬報孫常州二首','戴叔倫','唐','御定全唐诗','yuding','','[]','衰病苦奔走，未嘗追舊遊。何言問憔悴，此日駐方舟。',48,'御定全唐詩/json/274.json','["衰病苦奔走，未嘗追舊遊。何言問憔悴，此日駐方舟。", "遠道曳故屐，餘春會高齋。因言別離久，得盡平生懷。"]'),
('yuding-2','將赴東陽留上包諫議','戴叔倫','唐','御定全唐诗','yuding','','[]','敝邑連山遠，仙舟數刻同。多慚屢回首，前路在泥中。',24,'御定全唐詩/json/274.json','["敝邑連山遠，仙舟數刻同。多慚屢回首，前路在泥中。"]'),
('yuding-3','答崔法曹','戴叔倫','唐','御定全唐诗','yuding','','[]','後會知不遠，今歡亦願留。江天梅雨散，況在月中樓。',24,'御定全唐詩/json/274.json','["後會知不遠，今歡亦願留。江天梅雨散，況在月中樓。"]'),
('yuding-4','問嚴居士易','戴叔倫','唐','御定全唐诗','yuding','','[]','自公來問易，不復待加年。更有垂簾會，遙知續草玄。',24,'御定全唐詩/json/274.json','["自公來問易，不復待加年。更有垂簾會，遙知續草玄。"]'),
('yuding-5','新年第二夜答處上人宿玉芝觀見寄','戴叔倫','唐','御定全唐诗','yuding','','[]','陽春已三日，會友聞昨夜。可愛剡溪僧，獨尋陶景舍。',24,'御定全唐詩/json/274.json','["陽春已三日，會友聞昨夜。可愛剡溪僧，獨尋陶景舍。"]'),
('yuding-6','赴撫州對酬崔法曹夜雨滴空階五首','戴叔倫','唐','御定全唐诗','yuding','','[]','雨落濕孤客，心驚比棲鳥。空階夜滴繁，相亂應到曉。',120,'御定全唐詩/json/274.json','["雨落濕孤客，心驚比棲鳥。空階夜滴繁，相亂應到曉。", "高會棗樹宅，清言蓮社僧。兩鄉同夜雨，旅館又無燈。", "謗議不自辨，親朋那得知。雨中驅馬去，非是獨傷離。", "離室雨初晦，客程雲陡暗。方為對吏人，敢望郵童探。", "縱酒常擲盞，狂歌時入室。離群怨雨聲，幽抑方成疾。"]'),
('yuding-7','又酬曉燈離暗室五首','戴叔倫','唐','御定全唐诗','yuding','','[]','知疑奸叟謗，閑與情人話。猶是別時燈，不眠同此夜。',120,'御定全唐詩/json/274.json','["知疑奸叟謗，閑與情人話。猶是別時燈，不眠同此夜。", "寒燈揚曉焰，重屋驚春雨。應想遠行人，路逢泥濘阻。", "燈光照虛屋，雨影懸空壁。一向簷下聲，遠來愁處滴。", "楚僧話寂滅，俗慮比虛空。賴有殘燈喻，相傳昏暗中。", "雨聲亂燈影，明滅在空階。並枉五言贈，知同萬里懷。"]'),
('yuding-8','同賦龍沙墅','戴叔倫','唐','御定全唐诗','yuding','','[]','回轉沙岸近，欹斜林嶺重。因君訪遺跡，此日見真龍。',24,'御定全唐詩/json/274.json','["回轉沙岸近，欹斜林嶺重。因君訪遺跡，此日見真龍。"]'),
('yuding-9','昭君詞','戴叔倫','唐','御定全唐诗','yuding','','[]','漢宮若遠近，路在寒沙上。到死不得歸，何人共南望。',24,'御定全唐詩/json/274.json','["漢宮若遠近，路在寒沙上。到死不得歸，何人共南望。"]'),
('yuding-10','勸陸三飲酒','戴叔倫','唐','御定全唐诗','yuding','','[]','寒郊好天氣，勸酒莫辭頻。擾擾鐘陵市，無窮不醉人。',24,'御定全唐詩/json/274.json','["寒郊好天氣，勸酒莫辭頻。擾擾鐘陵市，無窮不醉人。"]'),
('yuding-11','關山月二首','戴叔倫','唐','御定全唐诗','yuding','','[]','月出照關山，秋風人未還。清光無遠近，鄉淚半書間。',48,'御定全唐詩/json/274.json','["月出照關山，秋風人未還。清光無遠近，鄉淚半書間。", "一雁過連營，繁霜覆古城。胡笳在何處，半夜起邊聲。"]'),
('yuding-12','送王司直','戴叔倫','唐','御定全唐诗','yuding','','[]','西塞雲山遠，東風道路長。人心勝潮水，相送過潯陽。',24,'御定全唐詩/json/274.json','["西塞雲山遠，東風道路長。人心勝潮水，相送過潯陽。"]'),
('yuding-13','宿無可上人房','戴叔倫','唐','御定全唐诗','yuding','','[]','偶來人境外，何處染囂塵。倘許棲林下，僧中老此身。',24,'御定全唐詩/json/274.json','["偶來人境外，何處染囂塵。倘許棲林下，僧中老此身。"]'),
('yuding-14','山居','戴叔倫','唐','御定全唐诗','yuding','','[]','麋鹿自成群，何人到白雲。山中無外事，終日醉醺醺。',24,'御定全唐詩/json/274.json','["麋鹿自成群，何人到白雲。山中無外事，終日醉醺醺。"]'),
('yuding-15','口號','戴叔倫','唐','御定全唐诗','yuding','','[]','白髮千莖雪，寒窗懶著書。最憐吟苜蓿，不及向桑榆。',24,'御定全唐詩/json/274.json','["白髮千莖雪，寒窗懶著書。最憐吟苜蓿，不及向桑榆。"]'),
('yuding-16','夜坐','戴叔倫','唐','御定全唐诗','yuding','','[]','夜靜河漢高，獨坐庭前月。忽起故園思，動作經年別。',24,'御定全唐詩/json/274.json','["夜靜河漢高，獨坐庭前月。忽起故園思，動作經年別。"]'),
('yuding-17','堤上柳','戴叔倫','唐','御定全唐诗','yuding','','[]','垂柳萬條絲，春來織別離。行人攀折處，閨妾斷腸時。',24,'御定全唐詩/json/274.json','["垂柳萬條絲，春來織別離。行人攀折處，閨妾斷腸時。"]'),
('yuding-18','遣興','戴叔倫','唐','御定全唐诗','yuding','','[]','明月臨滄海，閑雲戀故山。詩名滿天下，終日掩柴關。',24,'御定全唐詩/json/274.json','["明月臨滄海，閑雲戀故山。詩名滿天下，終日掩柴關。"]'),
('yuding-19','贈張揮使','戴叔倫','唐','御定全唐诗','yuding','','[]','謫戍孤城小，思家萬里遙。漢廷求衛霍，劍佩上青霄。',24,'御定全唐詩/json/274.json','["謫戍孤城小，思家萬里遙。漢廷求衛霍，劍佩上青霄。"]'),
('yuding-20','偶成','戴叔倫','唐','御定全唐诗','yuding','','[]','野水連天碧，峰巒入海青。滄浪者誰子，一曲醉中聽。',24,'御定全唐詩/json/274.json','["野水連天碧，峰巒入海青。滄浪者誰子，一曲醉中聽。"]'),
('yuding-21','畫蟬','戴叔倫','唐','御定全唐诗','yuding','','[]','飲露身何潔，吟風韻更長。斜陽千萬樹，無處避螳螂。',24,'御定全唐詩/json/274.json','["飲露身何潔，吟風韻更長。斜陽千萬樹，無處避螳螂。"]'),
('yuding-22','題天柱山圖','戴叔倫','唐','御定全唐诗','yuding','','[]','拔翠五雲中，擎天不計功。誰能淩絕頂，看取日升東。',24,'御定全唐詩/json/274.json','["拔翠五雲中，擎天不計功。誰能淩絕頂，看取日升東。"]'),
('yuding-23','松鶴','戴叔倫','唐','御定全唐诗','yuding','','[]','雨濕松陰涼，風落松花細。獨鶴愛清幽，飛來不飛去。',24,'御定全唐詩/json/274.json','["雨濕松陰涼，風落松花細。獨鶴愛清幽，飛來不飛去。"]'),
('yuding-24','草堂一上人','戴叔倫','唐','御定全唐诗','yuding','','[]','一公持一缽，相複度遙岑。地瘦無黃獨，春來草更深。',24,'御定全唐詩/json/274.json','["一公持一缽，相複度遙岑。地瘦無黃獨，春來草更深。"]'),
('yuding-25','題黃司直園','戴叔倫','唐','御定全唐诗','yuding','','[]','為憶去年梅，淩寒特地來。門前空臘盡，渾未有花開。',24,'御定全唐詩/json/274.json','["為憶去年梅，淩寒特地來。門前空臘盡，渾未有花開。"]'),
('yuding-26','北山游亭','戴叔倫','唐','御定全唐诗','yuding','','[]','西崦水泠泠，沿岡有遊亭。自從春草長，遙見只青青。',24,'御定全唐詩/json/274.json','["西崦水泠泠，沿岡有遊亭。自從春草長，遙見只青青。"]'),
('yuding-27','贈李唐山人','戴叔倫','唐','御定全唐诗','yuding','','[]','此意無所欲，閉門風景遲。柳條將白髮，相對共垂絲。',24,'御定全唐詩/json/274.json','["此意無所欲，閉門風景遲。柳條將白髮，相對共垂絲。"]'),
('yuding-28','題秦隱君麗句亭','戴叔倫','唐','御定全唐诗','yuding','','[]','北人歸欲盡，猶自住蕭山。閉戶不曾出，詩名滿世間。',24,'御定全唐詩/json/274.json','["北人歸欲盡，猶自住蕭山。閉戶不曾出，詩名滿世間。"]'),
('yuding-29','答孫常州見憶','戴叔倫','唐','御定全唐诗','yuding','','[]','畫鷁春風裏，迢遙去若飛。那能寄相憶，不並子猷歸。',24,'御定全唐詩/json/274.json','["畫鷁春風裏，迢遙去若飛。那能寄相憶，不並子猷歸。"]'),
('yuding-30','送裴明州效南朝體','戴叔倫','唐','御定全唐诗','yuding','','[]','沅水連湘水，千波萬浪中。知郎未得去，慚愧石尤風。',24,'御定全唐詩/json/274.json','["沅水連湘水，千波萬浪中。知郎未得去，慚愧石尤風。"]'),
('yuding-31','戲留顧十一明府','戴叔倫','唐','御定全唐诗','yuding','','[]','江明雨初歇，山暗雲猶濕。未可動歸橈，前程風浪急。',24,'御定全唐詩/json/274.json','["江明雨初歇，山暗雲猶濕。未可動歸橈，前程風浪急。"]'),
('yuding-32','答崔載華','戴叔倫','唐','御定全唐诗','yuding','','[]','文案日成堆，愁眉拽不開。偷歸甕間臥，逢個楚狂來。',24,'御定全唐詩/json/274.json','["文案日成堆，愁眉拽不開。偷歸甕間臥，逢個楚狂來。"]'),
('yuding-33','將赴行營勸客同醉','戴叔倫','唐','御定全唐诗','yuding','','[]','絲管霜天夜，煙塵淮水西。明朝上征去，相伴醉如泥。',24,'御定全唐詩/json/274.json','["絲管霜天夜，煙塵淮水西。明朝上征去，相伴醉如泥。"]'),
('yuding-34','夏夜江樓會別','戴叔倫','唐','御定全唐诗','yuding','','[]','不作十日別，煩君此相留。雨餘江上月，好醉竹間樓。',24,'御定全唐詩/json/274.json','["不作十日別，煩君此相留。雨餘江上月，好醉竹間樓。"]'),
('yuding-35','歲除日奉推事使牒追赴撫州辨對留別崔法曹陸大祝處士上人同賦人字口號','戴叔倫','唐','御定全唐诗','yuding','','[]','上國杳未到，流年忽複新。回車不自識，君定送何人。',24,'御定全唐詩/json/274.json','["上國杳未到，流年忽複新。回車不自識，君定送何人。"]'),
('yuding-36','江館會別','戴叔倫','唐','御定全唐诗','yuding','','[]','離亭一會宿，能有幾人同。莫以回車泣，前途不盡窮。',24,'御定全唐詩/json/274.json','["離亭一會宿，能有幾人同。莫以回車泣，前途不盡窮。"]'),
('yuding-37','容州回逢陸三別','戴叔倫','唐','御定全唐诗','yuding','','[]','西南積水遠，老病喜生歸。此地故人別，空餘淚滿衣。',24,'御定全唐詩/json/274.json','["西南積水遠，老病喜生歸。此地故人別，空餘淚滿衣。"]'),
('yuding-38','古意寄呈王侍郎','戴叔倫','唐','御定全唐诗','yuding','','[]','夜光貯懷袖，待報一顧恩。日向江湖老，此心誰為論。',24,'御定全唐詩/json/274.json','["夜光貯懷袖，待報一顧恩。日向江湖老，此心誰為論。"]'),
('yuding-39','送李大夫渡口阻風','戴叔倫','唐','御定全唐诗','yuding','','[]','浪息定何時，龍門到恐遲。輕舟不敢渡，空立望旌旗。',24,'御定全唐詩/json/274.json','["浪息定何時，龍門到恐遲。輕舟不敢渡，空立望旌旗。"]'),
('yuding-40','過三閭廟','戴叔倫','唐','御定全唐诗','yuding','','[]','沅湘流不盡，屈宋怨何深。日暮秋煙起，蕭蕭楓樹林。',24,'御定全唐詩/json/274.json','["沅湘流不盡，屈宋怨何深。日暮秋煙起，蕭蕭楓樹林。"]'),
('yuding-41','泊湘口','戴叔倫','唐','御定全唐诗','yuding','','[]','湘山千嶺樹，桂水九秋波。露重猿聲絕，風清月色多。',24,'御定全唐詩/json/274.json','["湘山千嶺樹，桂水九秋波。露重猿聲絕，風清月色多。"]'),
('yuding-42','游道林寺','戴叔倫','唐','御定全唐诗','yuding','','[]','佳山路不遠，俗侶到常稀。及此煙霞暮，相看複欲歸。',24,'御定全唐詩/json/274.json','["佳山路不遠，俗侶到常稀。及此煙霞暮，相看複欲歸。"]'),
('yuding-43','後宮曲','戴叔倫','唐','御定全唐诗','yuding','','[]','初入長門宮，謂言君戲妾。寧知秋風至，吹盡庭前葉。',24,'御定全唐詩/json/274.json','["初入長門宮，謂言君戲妾。寧知秋風至，吹盡庭前葉。"]'),
('yuding-44','新別離','戴叔倫','唐','御定全唐诗','yuding','','[]','手把杏花枝，未曾經別離。黃昏掩閨後，寂寞心自知。',24,'御定全唐詩/json/274.json','["手把杏花枝，未曾經別離。黃昏掩閨後，寂寞心自知。"]'),
('yuding-45','夏日登鶴岩偶成','戴叔倫','唐','御定全唐诗','yuding','','[]','天風吹我上層岡，露灑長松六月涼。',32,'御定全唐詩/json/274.json','["天風吹我上層岡，露灑長松六月涼。", "願借老僧雙白鶴，碧雲深處共翱翔。"]'),
('yuding-46','題淨居寺','戴叔倫','唐','御定全唐诗','yuding','','[]','玉壺山下雲居寺，六百年來選佛場。',32,'御定全唐詩/json/274.json','["玉壺山下雲居寺，六百年來選佛場。", "滿地白雲關不住，石泉流出落花香。"]'),
('yuding-47','昭君詞','戴叔倫','唐','御定全唐诗','yuding','','[]','漢家宮闕夢中歸，幾度氈房淚濕衣。',32,'御定全唐詩/json/274.json','["漢家宮闕夢中歸，幾度氈房淚濕衣。", "惆悵不如邊雁影，秋風猶得向南飛。"]'),
('yuding-48','織女詞','戴叔倫','唐','御定全唐诗','yuding','','[]','鳳梭停織鵲無音，夢憶仙郎夜夜心。',32,'御定全唐詩/json/274.json','["鳳梭停織鵲無音，夢憶仙郎夜夜心。", "難得相逢容易別，銀河爭似妾愁深。"]'),
('yuding-49','塞上曲二首','戴叔倫','唐','御定全唐诗','yuding','','[]','軍門頻納受降書，一劍橫行萬里餘。',64,'御定全唐詩/json/274.json','["軍門頻納受降書，一劍橫行萬里餘。", "漢祖謾誇婁敬策，卻將公主嫁單于。", "漢家旌幟滿陰山，不遣胡兒匹馬還。", "願得此身長報國，何須生入玉門關。"]'),
('yuding-50','閨怨','戴叔倫','唐','御定全唐诗','yuding','','[]','看花無語淚如傾，多少春風怨別情。',32,'御定全唐詩/json/274.json','["看花無語淚如傾，多少春風怨別情。", "不識玉門關外路，夢中昨夜到邊城。"]'),
('yuding-51','春怨','戴叔倫','唐','御定全唐诗','yuding','','[]','金鴨香消欲斷魂，梨花春雨掩重門。',32,'御定全唐詩/json/274.json','["金鴨香消欲斷魂，梨花春雨掩重門。", "欲知別後相思意，回看羅衣積淚痕。"]'),
('yuding-52','旅次寄湖南張郎中','戴叔倫','唐','御定全唐诗','yuding','','[]','閉門茅底偶為鄰，北阮那憐南阮貧。',32,'御定全唐詩/json/274.json','["閉門茅底偶為鄰，北阮那憐南阮貧。", "卻是梅花無世態，隔牆分送一枝春。"]'),
('yuding-53','題友人山居','戴叔倫','唐','御定全唐诗','yuding','','[]','四郭青山處處同，客懷無計答秋風。',32,'御定全唐詩/json/274.json','["四郭青山處處同，客懷無計答秋風。", "數家茅屋清溪上，千樹蟬聲落日中。"]'),
('yuding-54','別鄭谷','戴叔倫','唐','御定全唐诗','yuding','','[]','朝陽齋前桃李樹，手栽清蔭接比鄰。',32,'御定全唐詩/json/274.json','["朝陽齋前桃李樹，手栽清蔭接比鄰。", "明年此地看花發，愁向東風憶故人。"]'),
('yuding-55','贈鶴林上人','戴叔倫','唐','御定全唐诗','yuding','','[]','日日澗邊尋茯芩，岩扉常掩鳳山青。',32,'御定全唐詩/json/274.json','["日日澗邊尋茯芩，岩扉常掩鳳山青。", "歸來掛衲高林下，自剪芭蕉寫佛經。"]'),
('yuding-56','題稚川山水','戴叔倫','唐','御定全唐诗','yuding','','[]','松下茅亭五月涼，汀沙雲樹晚蒼蒼。',32,'御定全唐詩/json/274.json','["松下茅亭五月涼，汀沙雲樹晚蒼蒼。", "行人無限秋風思，隔水青山似故鄉。"]'),
('yuding-57','過柳溪道院','戴叔倫','唐','御定全唐诗','yuding','','[]','溪上誰家掩竹扉，鳥啼渾似惜春暉。',32,'御定全唐詩/json/274.json','["溪上誰家掩竹扉，鳥啼渾似惜春暉。", "日斜深巷無人跡，時見梨花片片飛。"]'),
('yuding-58','荔枝','戴叔倫','唐','御定全唐诗','yuding','','[]','紅顆真珠誠可愛，白須太守亦何癡。',32,'御定全唐詩/json/274.json','["紅顆真珠誠可愛，白須太守亦何癡。", "十年結子知誰在，自向中庭種荔枝。"]'),
('yuding-59','憶原上人','戴叔倫','唐','御定全唐诗','yuding','','[]','一兩棕鞋八尺藤，廣陵行遍又金陵。',32,'御定全唐詩/json/274.json','["一兩棕鞋八尺藤，廣陵行遍又金陵。", "不知竹雨竹風夜，吟對秋山那寺燈。"]'),
('yuding-60','閑思','戴叔倫','唐','御定全唐诗','yuding','','[]','伯勞東去鶴西還，雲總無心亦度山。',32,'御定全唐詩/json/274.json','["伯勞東去鶴西還，雲總無心亦度山。", "何似嚴陵灘上客，一竿長伴白鷗閑。"]'),
('yuding-61','蘭溪棹歌','戴叔倫','唐','御定全唐诗','yuding','','[]','涼月如眉掛柳灣，越中山色鏡中看。',32,'御定全唐詩/json/274.json','["涼月如眉掛柳灣，越中山色鏡中看。", "蘭溪三日桃花雨，半夜鯉魚來上灘。"]'),
('yuding-62','蘇溪亭','戴叔倫','唐','御定全唐诗','yuding','','[]','蘇溪亭上草漫漫，誰倚東風十二闌。',32,'御定全唐詩/json/274.json','["蘇溪亭上草漫漫，誰倚東風十二闌。", "燕子不歸春事晚，一汀煙雨杏花寒。"]'),
('yuding-63','敬酬陸山人二首','戴叔倫','唐','御定全唐诗','yuding','','[]','党議連誅不可聞，直臣高士去紛紛。',64,'御定全唐詩/json/274.json','["党議連誅不可聞，直臣高士去紛紛。", "當時漏奪無人問，出宰東陽笑殺君。", "由來海畔逐樵漁，奉詔因乘使者車。", "卻掌山中子男印，自看猶是舊潛夫。"]'),
('yuding-64','答崔法曹賦四雪','戴叔倫','唐','御定全唐诗','yuding','','[]','楚僧躡雪來招隱，先訪高人積雪中。',32,'御定全唐詩/json/274.json','["楚僧躡雪來招隱，先訪高人積雪中。", "已別剡溪逢雪去，雪山修道與師同。"]'),
('yuding-65','撫州被推昭雪答陸太祝三首','戴叔倫','唐','御定全唐诗','yuding','','[]','求理由來許便宜，漢朝龔遂不為疵。',96,'御定全唐詩/json/274.json','["求理由來許便宜，漢朝龔遂不為疵。", "如今謗起翻成累，唯有新人子細知。", "貧交相愛果無疑，共向人間聽直詞。", "從古以來何限枉，慚知暗室不曾欺。", "春風旅館長庭蕪，俯首低眉一老夫。", "已對鐵冠窮事本，不知廷尉念冤無。"]'),
('yuding-66','送獨孤cl還京','戴叔倫','唐','御定全唐诗','yuding','','[]','舉家相逐還鄉去，不向秋風怨別時。',32,'御定全唐詩/json/274.json','["舉家相逐還鄉去，不向秋風怨別時。", "湖水兩重山萬里，定知行盡到京師。"]'),
('yuding-67','臨流送顧東陽','戴叔倫','唐','御定全唐诗','yuding','','[]','海上獨歸慚不及，邑中遺愛定無雙。',32,'御定全唐詩/json/274.json','["海上獨歸慚不及，邑中遺愛定無雙。", "蘭橈起唱逐流去，卻恨山溪通外江。"]'),
('yuding-68','行營送馬侍禦','戴叔倫','唐','御定全唐诗','yuding','','[]','萬里羽書來未絕，五關烽火晝仍傳。',32,'御定全唐詩/json/274.json','["萬里羽書來未絕，五關烽火晝仍傳。", "故人多病盡歸去，唯有劉楨不得眠。"]'),
('yuding-69','送秦系','戴叔倫','唐','御定全唐诗','yuding','','[]','五都來往無舊業，一代公卿盡故人。',32,'御定全唐詩/json/274.json','["五都來往無舊業，一代公卿盡故人。", "不肯低頭受羈束，遠師溪上拂纓塵。"]'),
('yuding-70','送裴判官回湖南','戴叔倫','唐','御定全唐诗','yuding','','[]','莫怕南風且盡歡，湘山多雨夏中寒。',32,'御定全唐詩/json/274.json','["莫怕南風且盡歡，湘山多雨夏中寒。", "送君萬里不覺遠，此地曾為心鐵官。"]'),
('yuding-71','再巡道永留別','戴叔倫','唐','御定全唐诗','yuding','','[]','鬢下初驚白髮時，更逢離別助秋悲。',32,'御定全唐詩/json/274.json','["鬢下初驚白髮時，更逢離別助秋悲。", "從今不學四方事，已共家人海上期。"]'),
('yuding-72','別崔法曹','戴叔倫','唐','御定全唐诗','yuding','','[]','欲作別離西入秦，芝田棗徑往來頻。',32,'御定全唐詩/json/274.json','["欲作別離西入秦，芝田棗徑往來頻。", "東湖此夕更留醉，逢著廬山學道人。"]'),
('yuding-73','送蕭二','戴叔倫','唐','御定全唐诗','yuding','','[]','擬向田間老此身，寒郊怨別甚於春。',32,'御定全唐詩/json/274.json','["擬向田間老此身，寒郊怨別甚於春。", "又聞故里朋遊盡，到日知逢何處人。"]'),
('yuding-74','湘川野望','戴叔倫','唐','御定全唐诗','yuding','','[]','懷王獨與佞人謀，聞道忠臣入亂流。',32,'御定全唐詩/json/274.json','["懷王獨與佞人謀，聞道忠臣入亂流。", "今日登高望不見，楚雲湘水各悠悠。"]'),
('yuding-75','將至道州寄李使君','戴叔倫','唐','御定全唐诗','yuding','','[]','九疑深路繞山回，木落天清猿晝哀。',32,'御定全唐詩/json/274.json','["九疑深路繞山回，木落天清猿晝哀。", "猶隔簫韶一峰在，遙傳五馬向東來。"]'),
('yuding-76','與虞沔州謁藏真上人','戴叔倫','唐','御定全唐诗','yuding','','[]','故侯將我到山中，更上西峰見遠公。',32,'御定全唐詩/json/274.json','["故侯將我到山中，更上西峰見遠公。", "共問置心何處好，主人揮手指虛空。"]'),
('yuding-77','題招隱寺','戴叔倫','唐','御定全唐诗','yuding','','[]','昨日臨川謝病還，求田問舍獨相關。',32,'御定全唐詩/json/274.json','["昨日臨川謝病還，求田問舍獨相關。", "宋時有井如今在，卻種胡麻不買山。"]'),
('yuding-78','過珥瀆單老','戴叔倫','唐','御定全唐诗','yuding','','[]','毫末成圍海變田，單家依舊住溪邊。',32,'御定全唐詩/json/274.json','["毫末成圍海變田，單家依舊住溪邊。", "比來已向人間老，今日相過卻少年。"]'),
('yuding-79','族兄各年八十餘見招游洞','戴叔倫','唐','御定全唐诗','yuding','','[]','鶴發婆娑鄉里親，相邀共看往年春。',32,'御定全唐詩/json/274.json','["鶴發婆娑鄉里親，相邀共看往年春。", "擬將兒女歸來住，且是茅山見老人。"]'),
('yuding-80','登高回乘月尋僧','戴叔倫','唐','御定全唐诗','yuding','','[]','插鬢茱萸來未盡，共隨明月下沙堆。',32,'御定全唐詩/json/274.json','["插鬢茱萸來未盡，共隨明月下沙堆。", "高緇寂寂不相問，醉客無端入定來。"]'),
('yuding-81','贈殷亮','戴叔倫','唐','御定全唐诗','yuding','','[]','日日河邊見水流，傷春未已複悲秋。',32,'御定全唐詩/json/274.json','["日日河邊見水流，傷春未已複悲秋。", "山中舊宅無人住，來往風塵共白頭。"]'),
('yuding-82','夜發袁江寄李潁川劉侍禦','戴叔倫','唐','御定全唐诗','yuding','','[]','半夜回舟入楚鄉，月明山水共蒼蒼。',32,'御定全唐詩/json/274.json','["半夜回舟入楚鄉，月明山水共蒼蒼。", "孤猿更叫秋風裏，不是愁人亦斷腸。"]'),
('yuding-83','對酒示申屠學士','戴叔倫','唐','御定全唐诗','yuding','','[]','三重江水萬重山，山裏春風度日閑。',32,'御定全唐詩/json/274.json','["三重江水萬重山，山裏春風度日閑。", "且向白雲求一醉，莫教愁夢到鄉關。"]'),
('yuding-84','對月答袁明府','戴叔倫','唐','御定全唐诗','yuding','','[]','山下孤城月上遲，相留一醉本無期。',32,'御定全唐詩/json/274.json','["山下孤城月上遲，相留一醉本無期。", "明年此夕遊何處，縱有清光知對誰。"]'),
('yuding-85','送前上饒嚴明府攝玉山','戴叔倫','唐','御定全唐诗','yuding','','[]','家在故林吳楚間，冰為溪水玉為山。',32,'御定全唐詩/json/274.json','["家在故林吳楚間，冰為溪水玉為山。", "更將舊政化鄰邑，遙見逋人相逐還。"]'),
('yuding-86','聽歌回馬上贈崔法曹','戴叔倫','唐','御定全唐诗','yuding','','[]','秋風裏許杏花開，杏樹傍邊醉客來。',32,'御定全唐詩/json/274.json','["秋風裏許杏花開，杏樹傍邊醉客來。", "共待夜深聽一曲，醒人騎馬斷腸回。"]'),
('yuding-87','酬駱侍禦答詩','戴叔倫','唐','御定全唐诗','yuding','','[]','風傳畫閣空知曉，雨濕江城不見春。',32,'御定全唐詩/json/274.json','["風傳畫閣空知曉，雨濕江城不見春。", "堆案繞床君莫怪，已經愁思古時人。"]'),
('yuding-88','送孫直游郴州','戴叔倫','唐','御定全唐诗','yuding','','[]','孤舟上水過湘沅，桂嶺南枝花正繁。',32,'御定全唐詩/json/274.json','["孤舟上水過湘沅，桂嶺南枝花正繁。", "行客自知心有托，不聞驚浪與啼猿。"]'),
('yuding-89','麓山寺會送尹秀才','戴叔倫','唐','御定全唐诗','yuding','','[]','湖上逢君亦不閑，暫將離別到深山。',32,'御定全唐詩/json/274.json','["湖上逢君亦不閑，暫將離別到深山。", "飄蓬驚鳥那自定，強欲相留雲樹間。"]'),
('yuding-90','送董頲','戴叔倫','唐','御定全唐诗','yuding','','[]','霜雁群飛下楚田，羈人掩淚望秦天。',32,'御定全唐詩/json/274.json','["霜雁群飛下楚田，羈人掩淚望秦天。", "君行江海無定所，別後相思何處邊。"]'),
('yuding-91','別張員外','戴叔倫','唐','御定全唐诗','yuding','','[]','木葉紛紛湘水濱，此中何事往頻頻。',32,'御定全唐詩/json/274.json','["木葉紛紛湘水濱，此中何事往頻頻。", "臨風自笑歸時晚，更送浮雲逐故人。"]'),
('yuding-92','送張評事','戴叔倫','唐','御定全唐诗','yuding','','[]','城郭喧喧爭送遠，危梁嫋嫋渡東津。',32,'御定全唐詩/json/274.json','["城郭喧喧爭送遠，危梁嫋嫋渡東津。", "楊花輾轉引征騎，莫怪山中多看人。"]'),
('yuding-93','送呂少府','戴叔倫','唐','御定全唐诗','yuding','','[]','共醉流芳獨歸去，故園高士日相親。',32,'御定全唐詩/json/274.json','["共醉流芳獨歸去，故園高士日相親。", "深山古路無楊柳，折取桐花寄遠人。"]'),
('yuding-94','送人游嶺南','戴叔倫','唐','御定全唐诗','yuding','','[]','少別華陽萬里游，近南風景不曾秋。',32,'御定全唐詩/json/274.json','["少別華陽萬里游，近南風景不曾秋。", "紅芳綠筍是行路，縱有啼猿聽卻幽。"]'),
('yuding-95','妻亡後別妻弟','戴叔倫','唐','御定全唐诗','yuding','','[]','楊柳青青滿路垂，贈行惟折古松枝。',32,'御定全唐詩/json/274.json','["楊柳青青滿路垂，贈行惟折古松枝。", "停舟一對湘江哭，哭罷無言君自知。"]'),
('yuding-96','和崔法曹建溪聞猿','戴叔倫','唐','御定全唐诗','yuding','','[]','曾向巫山峽裏行，羈猿一叫一回驚。',32,'御定全唐詩/json/274.json','["曾向巫山峽裏行，羈猿一叫一回驚。", "聞道建溪腸欲斷，的知斷著第三聲。"]'),
('yuding-97','湘南即事','戴叔倫','唐','御定全唐诗','yuding','','[]','盧橘花開楓葉衰，出門何處望京師。',32,'御定全唐詩/json/274.json','["盧橘花開楓葉衰，出門何處望京師。", "沅湘日夜東流去，不為愁人住少時。"]'),
('yuding-98','代書寄京洛舊游','戴叔倫','唐','御定全唐诗','yuding','','[]','今年十月溫風起，湘水悠悠生白蘋。欲寄遠書還不敢，卻愁驚動故鄉人。',32,'御定全唐詩/json/274.json','["今年十月溫風起，湘水悠悠生白蘋。欲寄遠書還不敢，卻愁驚動故鄉人。"]'),
('yuding-99','蘄州行營作','戴叔倫','唐','御定全唐诗','yuding','','[]','蘄水城西向北看，桃花落盡柳花殘。',32,'御定全唐詩/json/274.json','["蘄水城西向北看，桃花落盡柳花殘。", "朱旗半卷山川小，白馬連嘶草樹寒。"]'),
('yuding-100','題武當逸禪師蘭若','戴叔倫','唐','御定全唐诗','yuding','','[]','我身本似遠行客，況是亂時多病身。',32,'御定全唐詩/json/274.json','["我身本似遠行客，況是亂時多病身。", "經山涉水向何處，羞見竹林禪定人。"]'),
('yuding-101','穀城逢楊評事','戴叔倫','唐','御定全唐诗','yuding','','[]','遠自五陵獨竄身，築陽山中歸路新。',32,'御定全唐詩/json/274.json','["遠自五陵獨竄身，築陽山中歸路新。", "橫流夜長不得渡，駐馬荒亭逢故人。"]'),
('yuding-102','聽韓使君美人歌','戴叔倫','唐','御定全唐诗','yuding','','[]','仙人此夜忽淩波，更唱瑤台一遍歌。',32,'御定全唐詩/json/274.json','["仙人此夜忽淩波，更唱瑤台一遍歌。", "嫁與將軍天上住，人間可得再相過。"]'),
('yuding-103','轉應詞','戴叔倫','唐','御定全唐诗','yuding','','[]','邊草，邊草，邊草盡來共老。山南山北雪晴，',20,'御定全唐詩/json/274.json','["邊草，邊草，邊草盡來共老。山南山北雪晴，"]'),
('yuding-104','精舍對雨','戴叔倫','唐','御定全唐诗','yuding','','[]','空門寂寂澹吾身，溪雨微微洗客塵。',32,'御定全唐詩/json/274.json','["空門寂寂澹吾身，溪雨微微洗客塵。", "臥向白雲晴未盡，任他黃鳥醉芳春。"]'),
('yuding-105','宿灌陽灘','戴叔倫','唐','御定全唐诗','yuding','','[]','十月江邊蘆葉飛，灌陽灘冷上舟遲。',32,'御定全唐詩/json/274.json','["十月江邊蘆葉飛，灌陽灘冷上舟遲。", "今朝未遇高風便，還與沙鷗宿水湄。"]'),
('yuding-106','酬贈張眾甫','戴叔倫','唐','御定全唐诗','yuding','','[]','野人無本意，散木任天材。分向空山老，何言上苑來。',60,'御定全唐詩/json/274.json','["野人無本意，散木任天材。分向空山老，何言上苑來。", "迢遙千里道，依倚九層台。出處寧知命，輪轅豈自媒。", "更慚張處士，相與別蒿萊。"]'),
('yuding-107','客舍秋懷呈駱正字士則','戴叔倫','唐','御定全唐诗','yuding','','[]','無言堪自喻，偶坐更相悲。木落驚年長，門閑惜草衰。',48,'御定全唐詩/json/274.json','["無言堪自喻，偶坐更相悲。木落驚年長，門閑惜草衰。", "買山猶未得，諫獵又非時。設被浮名系，歸休漸欲遲。"]'),
('yuding-108','寄中書李舍人紓','戴叔倫','唐','御定全唐诗','yuding','','[]','萍翻蓬自卷，不共本心期。複入重城裏，頻看百草滋。',48,'御定全唐詩/json/274.json','["萍翻蓬自卷，不共本心期。複入重城裏，頻看百草滋。", "水流歸思遠，花發長年悲。盡日春風起，無人見此時。"]'),
('yuding-109','贈康老人洽','戴叔倫','唐','御定全唐诗','yuding','','[]','酒泉布衣舊才子，少小知名帝城裏。一篇飛入九重門，',120,'御定全唐詩/json/274.json','["酒泉布衣舊才子，少小知名帝城裏。一篇飛入九重門，", "南鄰北裏日經過，處處淹留樂事多。不脫弊裘輕錦綺，", "暗將心事隔風塵，盡擲年光逐杯酒。青門幾度見春歸，", "繁霜入鬢何足論，舊國連天不知處。爾來倏忽五十年，", "百人會中一身在，被褐飲瓢終不改。陌頭車馬共營營，"]'),
('yuding-110','暮春游長沙東湖贈辛兗州巢父二首','戴叔倫','唐','御定全唐诗','yuding','','[]','湘流分曲浦，繚繞古城東。岸轉千家合，林開一鏡空。',96,'御定全唐詩/json/274.json','["湘流分曲浦，繚繞古城東。岸轉千家合，林開一鏡空。", "人生無事少，心賞幾回同。且複忘羈束，悠悠落照中。", "回環路不盡，曆覽意彌新。古木佘田火，澄江蕩槳人。", "緩歌尋極浦，一醉送殘春。莫恨長沙遠，他年憶此辰。"]'),
('yuding-111','同兗州張秀才過王侍禦參謀宅賦十韻','戴叔倫','唐','御定全唐诗','yuding','','[]','十年官不進，斂跡無怨咎。漂蕩海內遊，淹留楚鄉久。',120,'御定全唐詩/json/274.json','["十年官不進，斂跡無怨咎。漂蕩海內遊，淹留楚鄉久。", "因參戎幕下，寄宅湘川口。翦竹開廣庭，瞻山敞虛牖。", "閑門早春至，陋巷新晴後。覆地落殘梅，和風嫋輕柳。", "逢迎車馬客，邀結風塵友。意愜時會文，夜長聊飲酒。", "秉心轉孤直，沈照隨可否。豈學屈大夫，憂慚對漁叟。"]'),
('yuding-112','同辛兗州巢父虛副端岳相思獻酬之作因紓歸懷兼呈辛魏二院長楊長寧','戴叔倫','唐','御定全唐诗','yuding','','[]','暮角發高城，情人坐中起。臨觴不及醉，分散秋風裏。',84,'御定全唐詩/json/274.json','["暮角發高城，情人坐中起。臨觴不及醉，分散秋風裏。", "雖有明日期，離心若千里。前歡反惆悵，後會還如此。", "焉得夜淹留，一回終宴喜。羈遊複牽役，皆去重湖水。", "早晚泛歸舟，吾從數君子。"]'),
('yuding-113','酬袁太祝長卿小湖村山居書懷見寄','戴叔倫','唐','御定全唐诗','yuding','','[]','背江居隙地，辭職作遺人。耕鑿資餘力，樵漁逐四鄰。',72,'御定全唐詩/json/274.json','["背江居隙地，辭職作遺人。耕鑿資餘力，樵漁逐四鄰。", "麥秋桑葉大，梅雨稻田新。籬落栽山果，池塘養海鱗。", "放歌聊自足，幽思忽相親。餘亦歸休者，依君老此身。"]'),
('yuding-114','送汶水王明府','戴叔倫','唐','御定全唐诗','yuding','','[]','何時別故鄉，歸去佩銅章。親族移家盡，閭閻百戰場。',48,'御定全唐詩/json/274.json','["何時別故鄉，歸去佩銅章。親族移家盡，閭閻百戰場。", "背關餘古木，近塞足風霜。遺老應相賀，知君不下堂。"]'),
('yuding-115','奉同汴州李相公勉送郭布殿中出巡','戴叔倫','唐','御定全唐诗','yuding','','[]','軒車出東閣，都邑繞南河。馬首先春至，人心比歲和。',48,'御定全唐詩/json/274.json','["軒車出東閣，都邑繞南河。馬首先春至，人心比歲和。", "省風傳隱恤，持法去煩苛。卻想埋輪者，論功此日多。"]'),
('yuding-116','送東陽顧明府罷歸','戴叔倫','唐','御定全唐诗','yuding','','[]','祖帳臨鮫室，黎人擁鷁舟。坐藍高士去，繼組鄙夫留。',48,'御定全唐詩/json/274.json','["祖帳臨鮫室，黎人擁鷁舟。坐藍高士去，繼組鄙夫留。", "白日落寒水，青楓繞曲洲。相看作離別，一倍不禁愁。"]'),
('yuding-117','撫州對事後送外生宋垓歸饒州覲侍呈上姊夫','戴叔倫','唐','御定全唐诗','yuding','','[]','淮汴初喪亂，蔣山烽火起。與君隨親族，奔迸辭故里。',192,'御定全唐詩/json/274.json','["淮汴初喪亂，蔣山烽火起。與君隨親族，奔迸辭故里。", "京口附商客，海門正狂風。憂心不敢住，夜發驚浪中。", "雲開方見日，潮盡爐峰出。石壁轉棠陰，鄱陽寄茅室。", "淹留三十年，分種越人田。骨肉無半在，鄉園猶未旋。", "爾家習文藝，旁究天人際。父子自相傳，優遊聊卒歲。", "學成不求達，道勝那厭貧。時入閭巷醉，好是羲皇人。", "頃因物役牽，偶逐簪組輩。謗書喧朝市，撫己慚淺昧。", "世業大小禮，近通顏謝詩。念渠還領會，非敢獨為師。"]'),
('yuding-118','永康孫明府頲秩滿將歸枉路訪別','戴叔倫','唐','御定全唐诗','yuding','','[]','門前水流咽，城下亂山多。非是還家路，寧知枉騎過。',48,'御定全唐詩/json/274.json','["門前水流咽，城下亂山多。非是還家路，寧知枉騎過。", "風煙複欲隔，悲笑屢相和。不學陶公醉，無因奈別何。"]'),
('yuding-119','將赴湖南留別東陽舊僚兼示吏人','戴叔倫','唐','御定全唐诗','yuding','','[]','智力苦不足，黎甿殊未安。忽從新命去，複隔舊僚歡。',72,'御定全唐詩/json/274.json','["智力苦不足，黎甿殊未安。忽從新命去，複隔舊僚歡。", "曉路整車馬，離亭會衣冠。冰堅細流咽，燒盡亂峰寒。", "耆老相餞送，兒童亦悲酸。桐鄉寄生怨，欲話此情難。"]'),
('yuding-120','撫州處士胡泛見送北回兩館至南昌縣界查溪蘭若別','戴叔倫','唐','御定全唐诗','yuding','','[]','移樽鋪山曲，祖帳查溪陰。鋪山即遠道，查溪非故林。',72,'御定全唐詩/json/274.json','["移樽鋪山曲，祖帳查溪陰。鋪山即遠道，查溪非故林。", "淒然誦新詩，落淚沾素襟。郡政我何有，別情君獨深。", "禪庭古樹秋，宿雨清沉沉。揮袂千里遠，悲傷去住心。"]'),
('yuding-121','將巡郴永途中作','戴叔倫','唐','御定全唐诗','yuding','','[]','行役留三楚，思歸又一春。自疑冠下發，聊此鏡中人。',48,'御定全唐詩/json/274.json','["行役留三楚，思歸又一春。自疑冠下發，聊此鏡中人。", "機息知名誤，形衰恨道貧。空將舊泉石，長與夢相親。"]'),
('yuding-122','桂陽北嶺偶過野人所居，聊書即事呈王永州邕李道州圻','戴叔倫','唐','御定全唐诗','yuding','','[]','犬吠空山響，林深一徑存。隔雲尋板屋，渡水到柴門。',144,'御定全唐詩/json/274.json','["犬吠空山響，林深一徑存。隔雲尋板屋，渡水到柴門。", "日晝風煙靜，花明草樹繁。乍疑秦世客，漸識楚人言。", "不記逃鄉里，居然長子孫。種田燒險谷，汲井鑿高原。", "畦葉藏春雉，庭柯宿旅猿。嶺陰無瘴癘，地隙有蘭蓀。", "內戶均皮席，枯瓢沃野餐。遠心知自負，幽賞詎能論。", "轉步重崖合，瞻途落照昏。他時願攜手，莫比武陵源。"]'),
('yuding-123','下鼻亭瀧行八十裏聊狀艱險，寄青苗鄭副端朔陽','戴叔倫','唐','御定全唐诗','yuding','','[]','瀧水天際來，鼻山地中坼。盤渦幾十處，疊溜皆千尺。',144,'御定全唐詩/json/274.json','["瀧水天際來，鼻山地中坼。盤渦幾十處，疊溜皆千尺。", "直寫卷沈沙，驚翻沖絕壁。淙淙振崖谷，洶洶竟朝夕。", "人語不自聞，日光亂相射。艤舟始搖漾，舉棹旋奔激。", "既下同建瓴，半空方避石。前危苦未盡，後險何其迫。", "倏閃疾風雷，蒼皇蕩魂魄。因隨伏流出，忽與跳波隔。", "遠想欲回軒，豈茲還泛鷁。雲涯多候館，努力勤登曆。"]'),
('yuding-124','少女生日感懷','戴叔倫','唐','御定全唐诗','yuding','','[]','五逢晬日今方見，置爾懷中自惘然。乍喜老身辭遠役，',40,'御定全唐詩/json/274.json','["五逢晬日今方見，置爾懷中自惘然。乍喜老身辭遠役，", "還有蔡家殘史籍，可能分與外人傳。"]'),
('yuding-125','張評事涉秦居士系見訪郡齋，即同賦中字','戴叔倫','唐','御定全唐诗','yuding','','[]','軺車忽枉轍，郡府自生風。遣吏山禽在，開樽野客同。',72,'御定全唐詩/json/274.json','["軺車忽枉轍，郡府自生風。遣吏山禽在，開樽野客同。", "古牆抽臘筍，喬木颺春鴻。能賦傳幽思，清言盡至公。", "城欹殘照入，池曲大江通。此地人來少，相歡一醉中。"]'),
('yuding-126','小雪','戴叔倫','唐','御定全唐诗','yuding','','[]','花雪隨風不厭看，更多還肯失林巒。',32,'御定全唐詩/json/274.json','["花雪隨風不厭看，更多還肯失林巒。", "愁人正在書窗下，一片飛來一片寒。"]'),
('yuding-127','句','戴叔倫','唐','御定全唐诗','yuding','','[]','鄰里龍沙北。。',31,'御定全唐詩/json/274.json','["鄰里龍沙北。。", "麥秋桑葉大，梅雨稻田新。籬落栽山果，池塘養錦鱗。"]'),
('yuding-0','競渡歌','張建封','唐','御定全唐诗','yuding','','[]','五月五日天晴明，楊花繞江啼曉鶯。使君未出郡齋外，',120,'御定全唐詩/json/275.json','["五月五日天晴明，楊花繞江啼曉鶯。使君未出郡齋外，", "兩岸羅衣破暈香，銀釵照日如霜刃。鼓聲三下紅旗開，", "鼓聲漸急標將近，兩龍望標目如瞬。坡上人呼霹靂驚，", "瘡眉血首爭不定，輸岸一朋心似燒。只將輸贏分罰賞，", "吾今細觀競渡兒，何殊當路權相持。不思得岸各休去，"]'),
('yuding-1','酬韓校書愈打球歌','張建封','唐','御定全唐诗','yuding','','[]','僕本修文持筆者，今來帥領紅旌下。不能無事習蛇矛，',96,'御定全唐詩/json/275.json','["僕本修文持筆者，今來帥領紅旌下。不能無事習蛇矛，", "護軍對引相向去，風呼月旋朋先開。俯身仰擊複傍擊，", "儒生疑我新發狂，武夫愛我生雄光。杖移鬃底拂尾後，", "凡情莫辨捷中能，拙目翻驚巧時失。韓生訝我為斯藝，"]'),
('yuding-2','春山夜月','于良史','唐','御定全唐诗','yuding','','[]','春山多勝事，賞玩夜忘歸。掬水月在手，弄花香滿衣。',48,'御定全唐詩/json/275.json','["春山多勝事，賞玩夜忘歸。掬水月在手，弄花香滿衣。", "興來無遠近，欲去惜芳菲。南望鳴鐘處，樓臺深翠微。"]'),
('yuding-3','宿藍田山口奉寄沈員外','于良史','唐','御定全唐诗','yuding','','[]','山暝飛群鳥，川長泛四鄰。煙歸河畔草，月照渡頭人。',48,'御定全唐詩/json/275.json','["山暝飛群鳥，川長泛四鄰。煙歸河畔草，月照渡頭人。", "朋友懷東道，鄉關戀北辰。去留無所適，岐路獨迷津。"]'),
('yuding-4','冬日野望寄李贊府','于良史','唐','御定全唐诗','yuding','','[]','地際朝陽滿，天邊宿霧收。風兼殘雪起，河帶斷冰流。',48,'御定全唐詩/json/275.json','["地際朝陽滿，天邊宿霧收。風兼殘雪起，河帶斷冰流。", "北闕馳心極，南圖尚旅遊。登臨思不已，何處得銷愁。"]'),
('yuding-5','閒居寄薛華','于良史','唐','御定全唐诗','yuding','','[]','隱幾讀黃老，閒居耳目清。僻居人事少，多病道心生。',48,'御定全唐詩/json/275.json','["隱幾讀黃老，閒居耳目清。僻居人事少，多病道心生。", "雨洗山林濕，鴉鳴池館晴。晚來因廢卷，行藥至西城。"]'),
('yuding-6','江上送友人','于良史','唐','御定全唐诗','yuding','','[]','看爾動行棹，未收離別筵。千帆忽見及，亂卻故人船。',48,'御定全唐詩/json/275.json','["看爾動行棹，未收離別筵。千帆忽見及，亂卻故人船。", "紛泊雁群起，逶迤沙漵連。長亭十裏外，應是少人煙。"]'),
('yuding-7','田家秋日送友','于良史','唐','御定全唐诗','yuding','','[]','蒼茫日初宴，遙野雲初收。殘雨北山裏，夕陽東渡頭。',48,'御定全唐詩/json/275.json','["蒼茫日初宴，遙野雲初收。殘雨北山裏，夕陽東渡頭。", "舟依漁溓合，水入田家流。何意君迷駕，山林應有秋。"]'),
('yuding-8','自吟','于良史','唐','御定全唐诗','yuding','','[]','出身三十年，發白衣猶碧。日暮倚朱門，從朱汙袍赤。',24,'御定全唐詩/json/275.json','["出身三十年，發白衣猶碧。日暮倚朱門，從朱汙袍赤。"]'),
('yuding-9','感興','崔膺','唐','御定全唐诗','yuding','','[]','富貴難義合，困窮易感恩。古來忠烈士，多出貧賤門。',72,'御定全唐詩/json/275.json','["富貴難義合，困窮易感恩。古來忠烈士，多出貧賤門。", "世上桃李樹，但結繁華子。白屋抱關人，青雲壯心死。", "本以勢利交，勢盡交情已。如何失情後，始歎門易軌。"]'),
('yuding-10','別佳人','崔膺','唐','御定全唐诗','yuding','','[]','壟上流泉壟下分，斷腸嗚咽不堪聞。',32,'御定全唐詩/json/275.json','["壟上流泉壟下分，斷腸嗚咽不堪聞。", "嫦娥一入月中去，巫峽千秋空白雲。"]'),
('yuding-11','禦溝新柳','馮宿','唐','御定全唐诗','yuding','','[]','夾道天渠遠，垂絲禦柳新。千條宜向日，萬戶共迎春。',72,'御定全唐詩/json/275.json','["夾道天渠遠，垂絲禦柳新。千條宜向日，萬戶共迎春。", "輕翠含煙發，微音逐吹頻。靜看思渡口，回望憶江濱。", "嫋嫋分游騎，依依駐旅人。陽和如可及，攀折在茲辰。"]'),
('yuding-12','酬白樂天劉夢得','馮宿','唐','御定全唐诗','yuding','','[]','共稱洛邑難其選，何幸天書用不才。遙約和風新草木，',40,'御定全唐詩/json/275.json','["共稱洛邑難其選，何幸天書用不才。遙約和風新草木，", "明歲杏園花下集，須知春色自東來。"]'),
('yuding-13','樂府答孟東野戲贈','陸長源','唐','御定全唐诗','yuding','','[]','芙蓉初出水，菡萏露中花。幾吹著枯木，無奈值空槎。',24,'御定全唐詩/json/275.json','["芙蓉初出水，菡萏露中花。幾吹著枯木，無奈值空槎。"]'),
('yuding-14','酬孟十二新居見寄','陸長源','唐','御定全唐诗','yuding','','[]','大道本夷曠，高情亦沖虛。因隨白雲意，偶逐青蘿居。',120,'御定全唐詩/json/275.json','["大道本夷曠，高情亦沖虛。因隨白雲意，偶逐青蘿居。", "青蘿紛蒙密，四序無慘舒。餘清濯子襟，散彩還吾廬。", "去歲登美第，策名在公車。將必繼管蕭，豈惟躡應徐。", "首夏尚清和，殘芳遍丘墟。褰幃蔭窗柳，汲井滋園蔬。", "達者貴知心，古人不願餘。愛君蔣生徑，且著茂陵書。"]'),
('yuding-15','答東野夷門雪','陸長源','唐','御定全唐诗','yuding','','[]','好丹與素道不同，失意得途事皆別。東鄰少年樂未央，',24,'御定全唐詩/json/275.json','["好丹與素道不同，失意得途事皆別。東鄰少年樂未央，"]'),
('yuding-16','句','陸長源','唐','御定全唐诗','yuding','','[]','忽然一曲稱君心，破卻中人百家產。',33,'御定全唐詩/json/275.json','["忽然一曲稱君心，破卻中人百家產。", "。", "城外平人驅欲盡，帳中猶打袞花球。"]'),
('yuding-17','寄興國池鶴上劉相公','張眾甫','唐','御定全唐诗','yuding','','[]','馴狎經時久，褵褷短翮存。不隨淮海變，空愧稻粱恩。',48,'御定全唐詩/json/275.json','["馴狎經時久，褵褷短翮存。不隨淮海變，空愧稻粱恩。", "獨立秋天靜，單棲夕露繁。欲飛還斂翼，詎敢望乘軒。"]'),
('yuding-18','送李司直使吳','張眾甫','唐','御定全唐诗','yuding','','[]','使臣方擁傳，王事遠辭家。震澤逢殘雨，新豐過落花。',48,'御定全唐詩/json/275.json','["使臣方擁傳，王事遠辭家。震澤逢殘雨，新豐過落花。", "水萍千葉散，風柳萬條斜。何處看離恨，春江無限沙。"]'),
('yuding-19','送李觀之宣州謁袁中丞賦得三州渡','張眾甫','唐','御定全唐诗','yuding','','[]','古渡大江濱，西南距要津。自當舟楫路，應濟往來人。',48,'御定全唐詩/json/275.json','["古渡大江濱，西南距要津。自當舟楫路，應濟往來人。", "翻浪驚飛鳥，回風起綠蘋。君看波上客，歲晚獨垂綸。"]'),
('yuding-20','宿慧山寺','王武陵','唐','御定全唐诗','yuding','','[]','秋日游古寺，秋山正蒼蒼。泛舟次岩壑，稽首金仙堂。',72,'御定全唐詩/json/275.json','["秋日游古寺，秋山正蒼蒼。泛舟次岩壑，稽首金仙堂。", "下有寒泉流，上有珍禽翔。石門吐明月，竹木涵清光。", "中夜河沉沉，但聞松桂香。曠然出塵境，憂慮澹已忘。"]'),
('yuding-21','秋暮登北樓','王武陵','唐','御定全唐诗','yuding','','[]','秋滿空山悲客心，山樓晴望散幽襟。一川紅樹迎霜老，',40,'御定全唐詩/json/275.json','["秋滿空山悲客心，山樓晴望散幽襟。一川紅樹迎霜老，", "三年海上音書絕，鄉國蕭條惟夢尋。"]'),
('yuding-22','宿慧山寺','朱宿','唐','御定全唐诗','yuding','','[]','古寺隱秋山，登攀度林樾。悠然青蓮界，此地塵境絕。',96,'御定全唐詩/json/275.json','["古寺隱秋山，登攀度林樾。悠然青蓮界，此地塵境絕。", "機閑任晝昏，慮澹知生滅。微吹遞遙泉，疏鬆對殘月。", "庭虛露華綴，池淨荷香發。心悟形未留，遲遲履歸轍。", "歲月人間促，煙霞此地多。殷勤竹林寺，更得幾回過。"]'),
('yuding-0','送惟良上人歸江南','盧綸','唐','御定全唐诗','yuding','','[]','落日映危檣，歸僧向岳陽。注瓶寒浪靜，讀律夜船香。',48,'御定全唐詩/json/276.json','["落日映危檣，歸僧向岳陽。注瓶寒浪靜，讀律夜船香。", "苦霧沈山影，陰霾發海光。群生一何負，多病禮醫王。"]'),
('yuding-1','送韓都護還邊','盧綸','唐','御定全唐诗','yuding','','[]','好勇知名早，爭雄上將間。戰多春入塞，獵慣夜登山。',48,'御定全唐詩/json/276.json','["好勇知名早，爭雄上將間。戰多春入塞，獵慣夜登山。", "陣合龍蛇動，軍移草木閑。今來部曲盡，白首過蕭關。"]'),
('yuding-2','送吉中孚校書歸楚州舊山','盧綸','唐','御定全唐诗','yuding','','[]','青袍芸閣郎，談笑挹侯王。舊籙藏雲穴，新詩滿帝鄉。',264,'御定全唐詩/json/276.json','["青袍芸閣郎，談笑挹侯王。舊籙藏雲穴，新詩滿帝鄉。", "名高閑不得，到處人爭識。誰知冰雪顏，已雜風塵色。", "此去複如何，東皋岐路多。藉芳臨紫陌，回首憶滄波。", "年來倦蕭索，但說淮南樂。並楫湖上游，連檣月中泊。", "沿溜入閶門，千燈夜市喧。喜逢鄰舍伴，遙語問鄉園。", "下淮風自急，樹杪分郊邑。送客隨岸行，離人出帆立。", "漁村繞水田，澹澹隔晴煙。欲就林中醉，先期石上眠。", "林昏天未曙，但向雲邊去。暗入無路山，心知有花處。", "登高日轉明，下望見春城。洞裏草空長，塚邊人自耕。", "寥寥行異境，過盡千峰影。露色凝古壇，泉聲落寒井。", "仙成不可期，多別自堪悲。為問桃源客，何人見亂時。"]'),
('yuding-3','送姨弟裴均尉諸暨','盧綸','唐','御定全唐诗','yuding','','[]','相悲得成長，同是外家恩。舊業廢三畝，弱年成一門。',48,'御定全唐詩/json/276.json','["相悲得成長，同是外家恩。舊業廢三畝，弱年成一門。", "城開山日早，吏散渚禽喧。東閣謬容止，予心君冀言。"]'),
('yuding-4','送鄧州崔長史','盧綸','唐','御定全唐诗','yuding','','[]','出山車騎次諸侯，坐領圖書見督郵。繞郭桑麻通淅口，',40,'御定全唐詩/json/276.json','["出山車騎次諸侯，坐領圖書見督郵。繞郭桑麻通淅口，", "聞說元規偏愛月，知君長得伴登樓。"]'),
('yuding-5','送鹽鐵裴判官入蜀','盧綸','唐','御定全唐诗','yuding','','[]','傳詔收方貢，登車著賜衣。榷商蠻客富，稅地芋田肥。',48,'御定全唐詩/json/276.json','["傳詔收方貢，登車著賜衣。榷商蠻客富，稅地芋田肥。", "雲白風雷歇，林清洞穴稀。炎涼君莫問，見即在忘歸。"]'),
('yuding-6','送魏廣下第歸揚州','盧綸','唐','御定全唐诗','yuding','','[]','楚鄉雲水內，春日眾山開。淮浪參差起，江帆次第來。',48,'御定全唐詩/json/276.json','["楚鄉雲水內，春日眾山開。淮浪參差起，江帆次第來。", "獨歸初失桂，共醉忽停杯。漢詔年年有，何愁掩上才。"]'),
('yuding-7','送潘述應宏詞下第歸江南','盧綸','唐','御定全唐诗','yuding','','[]','愁與醉相和，昏昏竟若何。感年懷闕久，失意夢鄉多。',48,'御定全唐詩/json/276.json','["愁與醉相和，昏昏竟若何。感年懷闕久，失意夢鄉多。", "雨裏行青草，山前望白波。江樓覆棋好，誰引仲宣過。"]'),
('yuding-8','送從舅成都縣丞廣歸蜀','盧綸','唐','御定全唐诗','yuding','','[]','褒穀通岷嶺，青冥此路深。晚程椒瘴熱，野飯荔枝陰。',48,'御定全唐詩/json/276.json','["褒穀通岷嶺，青冥此路深。晚程椒瘴熱，野飯荔枝陰。", "古郡三刀夜，春橋萬里心。唯應對楊柳，暫醉卓家琴。"]'),
('yuding-9','送宋校書赴宣州幕','盧綸','唐','御定全唐诗','yuding','','[]','南想宣城郡，清江野戍閑。艨艟高映浦，睥睨曲隨山。',48,'御定全唐詩/json/276.json','["南想宣城郡，清江野戍閑。艨艟高映浦，睥睨曲隨山。", "名寄圖書內，威生將吏間。春行板橋暮，應伴庾公還。"]'),
('yuding-10','送李縱別駕加員外郎卻赴常州幕','盧綸','唐','御定全唐诗','yuding','','[]','霄漢正聯飛，江湖又獨歸。暫歡同賜被，不待易朝衣。',48,'御定全唐詩/json/276.json','["霄漢正聯飛，江湖又獨歸。暫歡同賜被，不待易朝衣。", "山雨迎軍晚，蘆風候火微。還當宴鈴閣，謝守亦光輝。"]'),
('yuding-11','送元贊府重任龍門縣','盧綸','唐','御定全唐诗','yuding','','[]','二職亞陶公，歸程與夢同。柳垂平澤雨，魚躍大河風。',48,'御定全唐詩/json/276.json','["二職亞陶公，歸程與夢同。柳垂平澤雨，魚躍大河風。", "混跡威長在，孤清志自雄。應嗤向隅者，空寄路塵中。"]'),
('yuding-12','送黎燧尉陽翟','盧綸','唐','御定全唐诗','yuding','','[]','玉貌承嚴訓，金聲稱上才。列筵青草偃，驟馬綠楊開。',48,'御定全唐詩/json/276.json','["玉貌承嚴訓，金聲稱上才。列筵青草偃，驟馬綠楊開。", "潘縣花添發，梅家鶴暫來。誰知望恩者，空逐路人回。"]'),
('yuding-13','送丹陽趙少府','盧綸','唐','御定全唐诗','yuding','','[]','恭聞林下別，未至亦沾裳。荻岸雨聲盡，江天虹影長。',48,'御定全唐詩/json/276.json','["恭聞林下別，未至亦沾裳。荻岸雨聲盡，江天虹影長。", "佩韋宗懶慢，偷橘愛芳香。遙想從公後，稱榮在上堂。"]'),
('yuding-14','送菊潭王明府','盧綸','唐','御定全唐诗','yuding','','[]','組綬掩衰顏，輝光裏第間。晚涼經灞水，清晝入商山。',48,'御定全唐詩/json/276.json','["組綬掩衰顏，輝光裏第間。晚涼經灞水，清晝入商山。", "行境逢花發，彈琴見鶴還。唯應理農後，鄉老賀君閑。"]'),
('yuding-15','送陳明府赴萍縣','盧綸','唐','御定全唐诗','yuding','','[]','素舸載陶公，南隨萬里風。梅花成雪嶺，橘樹當家僮。',48,'御定全唐詩/json/276.json','["素舸載陶公，南隨萬里風。梅花成雪嶺，橘樹當家僮。", "祠掩荒山下，田開野荻中。歲終書善績，應與古碑同。"]'),
('yuding-16','送申屠正字往湖南迎親兼謁趙和州因呈上侍郎使君并戲簡前歷陽李明府','盧綸','唐','御定全唐诗','yuding','','[]','曉月朣朦映水關，水邊因到曆陽山。千艘財貨朱橋下，',40,'御定全唐詩/json/276.json','["曉月朣朦映水關，水邊因到曆陽山。千艘財貨朱橋下，", "歡餘若問南行計，知念天涯負米還。"]'),
('yuding-17','送李尚書郎君昆季侍從歸覲滑州','盧綸','唐','御定全唐诗','yuding','','[]','鳳雛聯翼美王孫，彩服戎裝擬塞垣。金鼎對筵調野膳，',40,'御定全唐詩/json/276.json','["鳳雛聯翼美王孫，彩服戎裝擬塞垣。金鼎對筵調野膳，", "更說務農將罷戰，敢持歌頌慶晨昏。"]'),
('yuding-18','送張調參軍侍從歸覲荊南因寄長林司空十四曙','盧綸','唐','御定全唐诗','yuding','','[]','玉勒侍行襜，郗超未有髯。守儒輕獵騎，承誨訪沈潛。',48,'御定全唐詩/json/276.json','["玉勒侍行襜，郗超未有髯。守儒輕獵騎，承誨訪沈潛。", "雲勢將峰雜，江聲與嶼兼。還當見王粲，應念二毛添。"]'),
('yuding-19','送馬尚書郎君侍從歸覲太原','盧綸','唐','御定全唐诗','yuding','','[]','玉人垂玉鞭，百騎帶櫜鞬。從賞野郵靜，獻新秋果鮮。',48,'御定全唐詩/json/276.json','["玉人垂玉鞭，百騎帶櫜鞬。從賞野郵靜，獻新秋果鮮。", "塞屯豐雨雪，虜帳失山川。遙想稱觴後，唯當共被眠。"]'),
('yuding-20','送張成季往江上賦得垂楊','盧綸','唐','御定全唐诗','yuding','','[]','垂楊真可憐，地勝覺春偏。一穗雨聲裏，千條池色前。',48,'御定全唐詩/json/276.json','["垂楊真可憐，地勝覺春偏。一穗雨聲裏，千條池色前。", "露繁光的皪，日麗影團圓。若到隋堤望，應逢花滿船。"]'),
('yuding-21','送陝府王司法','盧綸','唐','御定全唐诗','yuding','','[]','東門雪覆塵，出送陝城人。粉郭朝喧市，朱橋夜掩津。',48,'御定全唐詩/json/276.json','["東門雪覆塵，出送陝城人。粉郭朝喧市，朱橋夜掩津。", "上寮應重學，小吏已甘貧。謝脁曾為掾，希君一比鄰。"]'),
('yuding-22','送太常李主簿歸覲省','盧綸','唐','御定全唐诗','yuding','','[]','粲粲美仍都，清閒一貴儒。定交分玉劍，發詠寫冰壺。',48,'御定全唐詩/json/276.json','["粲粲美仍都，清閒一貴儒。定交分玉劍，發詠寫冰壺。", "風景隨台位，河山入障圖。上堂多慶樂，肯念穀中愚。"]'),
('yuding-23','送從叔程歸西川幕','盧綸','唐','御定全唐诗','yuding','','[]','千山冰雪晴，山靜錦花明。群鶴棲蓮府，諸戎拜柳營。',48,'御定全唐詩/json/276.json','["千山冰雪晴，山靜錦花明。群鶴棲蓮府，諸戎拜柳營。", "浪依巴字息，風入蜀關清。豈念在貧巷，竹林鳴鳥聲。"]'),
('yuding-24','送萬巨','盧綸','唐','御定全唐诗','yuding','','[]','把酒留君聽琴，難堪歲暮離心。霜葉無風自落，',35,'御定全唐詩/json/276.json','["把酒留君聽琴，難堪歲暮離心。霜葉無風自落，", "望斷青山獨立，更知何處相尋。"]'),
('yuding-25','途中遇雨馬上口號留別張劉二端公','盧綸','唐','御定全唐诗','yuding','','[]','陰雷慢轉野雲長，駿馬雙嘶愛雨涼。',32,'御定全唐詩/json/276.json','["陰雷慢轉野雲長，駿馬雙嘶愛雨涼。", "應念龍鍾在泥滓，欲摧肝膽事王章。"]'),
('yuding-26','送夔州班使君','盧綸','唐','御定全唐诗','yuding','','[]','曉日照樓船，三軍拜峽前。白雲隨浪散，青壁與城連。',48,'御定全唐詩/json/276.json','["曉日照樓船，三軍拜峽前。白雲隨浪散，青壁與城連。", "萬嶺岷峨雪，千家橘柚川。還知楚河內，天子許經年。"]'),
('yuding-27','送從舅成都丞廣歸蜀','盧綸','唐','御定全唐诗','yuding','','[]','巴字天邊水，秦人去是歸。棧長山雨響，溪亂火田稀。',48,'御定全唐詩/json/276.json','["巴字天邊水，秦人去是歸。棧長山雨響，溪亂火田稀。", "俗富行應樂，官雄祿豈微。魏舒終有淚，還識寧家衣。"]'),
('yuding-28','無題','盧綸','唐','御定全唐诗','yuding','','[]','恥將名利托交親，只向尊前樂此身。才大不應成滯客，',40,'御定全唐詩/json/276.json','["恥將名利托交親，只向尊前樂此身。才大不應成滯客，", "□□□□□□□，豈能偏遣老風塵。"]'),
('yuding-29','題念濟寺','盧綸','唐','御定全唐诗','yuding','','[]','靈空聞偈夜清淨，雨裏花枝朝暮開。',32,'御定全唐詩/json/276.json','["靈空聞偈夜清淨，雨裏花枝朝暮開。", "故友九泉留語別，逐臣千里寄書來。"]'),
('yuding-30','河口逢江州朱道士因聽琴','盧綸','唐','御定全唐诗','yuding','','[]','廬山道士夜攜琴，映月相逢辨語音。',32,'御定全唐詩/json/276.json','["廬山道士夜攜琴，映月相逢辨語音。", "引坐霜中彈一弄，滿船商客有歸心。"]'),
('yuding-31','送夏侯校書歸華陰別墅','盧綸','唐','御定全唐诗','yuding','','[]','山前白鶴村，竹雪覆柴門。候客定為黍，務農因燎原。',60,'御定全唐詩/json/276.json','["山前白鶴村，竹雪覆柴門。候客定為黍，務農因燎原。", "乳冰懸暗井，蓮石照晴軒。貰酒鄰里睦，曝衣場圃喧。", "依然望君去，余性亦何昏。"]'),
('yuding-32','送絳州郭參軍','盧綸','唐','御定全唐诗','yuding','','[]','炎天故絳路，千里麥花香。董澤雷聲發，汾橋水氣涼。',48,'御定全唐詩/json/276.json','["炎天故絳路，千里麥花香。董澤雷聲發，汾橋水氣涼。", "府趨隨宓賤，野宴接王祥。送客今何幸，經宵醉玉堂。"]'),
('yuding-33','中書舍人李座上送潁陽徐少府','盧綸','唐','御定全唐诗','yuding','','[]','潁陽春色似河陽，一望繁花一縣香。',32,'御定全唐詩/json/276.json','["潁陽春色似河陽，一望繁花一縣香。", "今日送官君最恨，可憐才子白須長。"]'),
('yuding-34','與從弟瑾同下第後出關言別','盧綸','唐','御定全唐诗','yuding','','[]','同作金門獻賦人，二年悲見故園春。',128,'御定全唐詩/json/276.json','["同作金門獻賦人，二年悲見故園春。", "到闕不沾新雨露，還家空帶舊風塵。", "雜花飛盡柳陰陰，官路逶迤綠草深。", "對酒已成千里客，望山空寄兩鄉心。", "出關愁暮一沾裳，滿野蓬生古戰場。", "孤村樹色昏殘雨，遠寺鐘聲帶夕陽。", "誰憐苦志已三冬，卻欲躬耕學老農。", "流水白雲尋不盡，期君何處得相逢。"]'),
('yuding-35','赴虢州留別故人','盧綸','唐','御定全唐诗','yuding','','[]','世故相逢各未閑，百年多在別離間。',32,'御定全唐詩/json/276.json','["世故相逢各未閑，百年多在別離間。", "昨夜秋風今夜雨，不知何處入空山。"]'),
('yuding-36','冬夜贈別友人','盧綸','唐','御定全唐诗','yuding','','[]','愁聽千家流水聲，相思獨向月中行。侵階暗草秋霜重，',40,'御定全唐詩/json/276.json','["愁聽千家流水聲，相思獨向月中行。侵階暗草秋霜重，", "更送乘軺歸上國，應憐貢禹未成名。"]'),
('yuding-37','送顧秘書獻書後歸岳州','盧綸','唐','御定全唐诗','yuding','','[]','黃葉落不盡，蒼苔隨雨生。當軒置尊酒，送客歸江城。',48,'御定全唐詩/json/276.json','["黃葉落不盡，蒼苔隨雨生。當軒置尊酒，送客歸江城。", "竹裏聞機杼，舟中見弟兄。岳陽賢太守，應為改鄉名。"]'),
('yuding-38','送衛司法河中覲省','盧綸','唐','御定全唐诗','yuding','','[]','出身因強學，不以外家榮。年少無遺事，官閑有政聲。',48,'御定全唐詩/json/276.json','["出身因強學，不以外家榮。年少無遺事，官閑有政聲。", "曉山臨野渡，落日照軍營。共賞高堂下，連行弟與兄。"]'),
('yuding-39','送從叔牧永州','盧綸','唐','御定全唐诗','yuding','','[]','五侯軒蓋行何疾，零陵太守登車日。零陵太守淚盈巾，',72,'御定全唐詩/json/276.json','["五侯軒蓋行何疾，零陵太守登車日。零陵太守淚盈巾，", "彼方韶景無時節，山水諸花恣開發。客投津戍少聞猿，", "浪裏爭迎三蜀貨，月中喧泊九江船。今朝小阮同夷老，"]'),
('yuding-40','送趙真長歸夏縣舊山依陽征君讀書','盧綸','唐','御定全唐诗','yuding','','[]','臨杯忽泫然，非是惡離弦。塵陌望松雪，我衰君少年。',48,'御定全唐詩/json/276.json','["臨杯忽泫然，非是惡離弦。塵陌望松雪，我衰君少年。", "幽僧曝山果，寒鹿守冰泉。感物如有待，況依回也賢。"]'),
('yuding-41','留別耿湋侯釗馮著','盧綸','唐','御定全唐诗','yuding','','[]','相識少相知，與君俱已衰。笙鏞新宅第，岐路古山陂。',48,'御定全唐詩/json/276.json','["相識少相知，與君俱已衰。笙鏞新宅第，岐路古山陂。", "學道功難就，為儒事本遲。惟當與漁者，終老遂其私。"]'),
('yuding-42','送渾煉歸覲卻赴闕庭','盧綸','唐','御定全唐诗','yuding','','[]','露幕擁簪裾，台庭餞伯魚。彩衣人競看，銀詔帝親書。',120,'御定全唐詩/json/276.json','["露幕擁簪裾，台庭餞伯魚。彩衣人競看，銀詔帝親書。", "知子當元老，為臣餞二疏。執珪期已迫，捧膳步甯徐。", "而我誠愚者，夫君豈病諸。探題多決勝，饌玉每分餘。", "榮比成功後，恩同造化初。甑塵方欲合，籠翮或將舒。", "榆莢錢難比，楊花雪不如。明朝古堤路，心斷玉人車。"]'),
('yuding-43','送崔邠拾遺','盧綸','唐','御定全唐诗','yuding','','[]','皎潔無瑕清玉壺，曉乘華幰向天衢。石建每聞宗謹孝，',40,'御定全唐詩/json/276.json','["皎潔無瑕清玉壺，曉乘華幰向天衢。石建每聞宗謹孝，", "今日攀車複何者，轅門垂白一愚夫。"]'),
('yuding-44','送渾別駕赴舒州','盧綸','唐','御定全唐诗','yuding','','[]','江平蘆荻齊，五兩貼檣低。繞郭覆晴雪，滿船聞曙雞。',48,'御定全唐詩/json/276.json','["江平蘆荻齊，五兩貼檣低。繞郭覆晴雪，滿船聞曙雞。", "鱣魴宜入貢，橘柚亦成蹊。還似海沂日，風清無鼓鼙。"]'),
('yuding-45','送從叔士准赴任潤州司士','盧綸','唐','御定全唐诗','yuding','','[]','雲起山城暮，沉沉江上天。風吹建業雨，浪入廣陵船。',48,'御定全唐詩/json/276.json','["雲起山城暮，沉沉江上天。風吹建業雨，浪入廣陵船。", "久是吳門客，嘗聞謝守賢。終悲去國遠，淚盡竹林前。"]'),
('yuding-46','送尹樞令狐楚及第後歸覲','盧綸','唐','御定全唐诗','yuding','','[]','佳人比香草，君子即芳蘭。寶器金罍重，清音玉佩寒。',48,'御定全唐詩/json/276.json','["佳人比香草，君子即芳蘭。寶器金罍重，清音玉佩寒。", "貢文齊受寵，獻禮兩承歡。鞍馬並汾地，爭迎陸與潘。"]'),
('yuding-47','東潭宴餞河南趙少府','盧綸','唐','御定全唐诗','yuding','','[]','十載奉戎軒，日聞君子言。方將賀榮爵，遽乃愴離尊。',72,'御定全唐詩/json/276.json','["十載奉戎軒，日聞君子言。方將賀榮爵，遽乃愴離尊。", "岸轉臺閣麗，潭清弦管繁。松篁難晦節，雨露不私恩。", "坐使吏相勉，居為儒所尊。可憐桃李樹，先發信陵門。"]'),
('yuding-48','賦得館娃宮送王山人游江東','盧綸','唐','御定全唐诗','yuding','','[]','蒼蒼楓樹林，草合廢宮深。越水風浪起，吳王歌管沈。',48,'御定全唐詩/json/276.json','["蒼蒼楓樹林，草合廢宮深。越水風浪起，吳王歌管沈。", "燕歸巢已盡，鶴語塚難尋。旅泊彼何夜，希君抽玉琴。"]'),
('yuding-49','送暢當還舊山','盧綸','唐','御定全唐诗','yuding','','[]','常逢明月馬塵間，是夜照君歸處山。',32,'御定全唐詩/json/276.json','["常逢明月馬塵間，是夜照君歸處山。", "山中松桂花盡發，頭白屬君如等閒。"]'),
('yuding-50','斅顏魯公送挺贇歸翠微寺','盧綸','唐','御定全唐诗','yuding','','[]','挺贇惠學該儒釋，袖有顏徐真草跡。一齋三請紀行詩，',40,'御定全唐詩/json/276.json','["挺贇惠學該儒釋，袖有顏徐真草跡。一齋三請紀行詩，", "虎跡印雪大如鬥，閏月暮天過得無。"]'),
('yuding-51','送契玄法師赴內道場','盧綸','唐','御定全唐诗','yuding','','[]','昏昏醉老夫，灌頂遇醍醐。嬪禦呈心鏡，君王賜髻珠。',48,'御定全唐詩/json/276.json','["昏昏醉老夫，灌頂遇醍醐。嬪禦呈心鏡，君王賜髻珠。", "降魔須戰否，問疾敢行無。深契何相秘，儒宗本不殊。"]'),
('yuding-52','送暢當赴山南幕','盧綸','唐','御定全唐诗','yuding','','[]','含情脫佩刀，持以佐賢豪。是月霜霰下，伊人行役勞。',48,'御定全唐詩/json/276.json','["含情脫佩刀，持以佐賢豪。是月霜霰下，伊人行役勞。", "事將名共易，文與行空高。去矣奉戎律，悲君為我曹。"]'),
('yuding-53','顏侍禦廳叢篁詠送薛存誠','盧綸','唐','御定全唐诗','yuding','','[]','玉幹百餘莖，生君此堂側。拂簾寒雨響，擁砌深溪色。',36,'御定全唐詩/json/276.json','["玉幹百餘莖，生君此堂側。拂簾寒雨響，擁砌深溪色。", "何事鳳凰雛，茲焉理歸翼。"]'),
('yuding-54','秋晚河西縣樓送渾中允赴朝闕','盧綸','唐','御定全唐诗','yuding','','[]','高樓吹玉簫，車馬上河橋。岐路自奔隘，壺觴終寂寥。',48,'御定全唐詩/json/276.json','["高樓吹玉簫，車馬上河橋。岐路自奔隘，壺觴終寂寥。", "芳蘭生貴裏，片玉立清朝。今日台庭望，心遙非地遙。"]'),
('yuding-55','達奚中丞東齋壁畫山水各賦一物得樹杪懸泉送長安趙元陽少府','盧綸','唐','御定全唐诗','yuding','','[]','素壁畫飛泉，從雲落樹顛。練垂疑葉響，雲並覺枝偏。',48,'御定全唐詩/json/276.json','["素壁畫飛泉，從雲落樹顛。練垂疑葉響，雲並覺枝偏。", "利物得雙劍，為儒當一賢。應思灑塵陌，調膳亦芳鮮。"]'),
('yuding-56','送信州姚使君','盧綸','唐','御定全唐诗','yuding','','[]','朱幡徐轉候群官，猿鳥無聲郡宇寬。楚國上腴收賦重，',40,'御定全唐詩/json/276.json','["朱幡徐轉候群官，猿鳥無聲郡宇寬。楚國上腴收賦重，", "幾日政聲聞戶外，九江行旅得相歡。"]'),
('yuding-57','送暢當','盧綸','唐','御定全唐诗','yuding','','[]','四望無極路，千里流大河。秋風滿離袂，唯老事唯多。',24,'御定全唐詩/json/276.json','["四望無極路，千里流大河。秋風滿離袂，唯老事唯多。"]'),
('yuding-58','送史兵曹判官赴樓煩','盧綸','唐','御定全唐诗','yuding','','[]','渥窪龍種散雲時，千里繁花乍別離。中有重臣承霈澤，',40,'御定全唐詩/json/276.json','["渥窪龍種散雲時，千里繁花乍別離。中有重臣承霈澤，", "敢謝親賢得瓊玉，仲宣能賦亦能詩。"]'),
('yuding-59','送曇延法師講罷赴上都','盧綸','唐','御定全唐诗','yuding','','[]','金縷袈裟國大師，能銷壞宅火燒時。',32,'御定全唐詩/json/276.json','["金縷袈裟國大師，能銷壞宅火燒時。", "複來擁膝說無住，知向人天何處期。"]'),
('yuding-60','送道士郤彝素歸內道場','盧綸','唐','御定全唐诗','yuding','','[]','病老正相仍，忽逢張道陵。羽衣風淅淅，仙貌玉棱棱。',48,'御定全唐詩/json/276.json','["病老正相仍，忽逢張道陵。羽衣風淅淅，仙貌玉棱棱。", "叱我問中壽，教人祈上升。樓居五雲裏，幾與武皇登。"]'),
('yuding-61','賦得彭祖樓送楊德宗歸徐州幕','盧綸','唐','御定全唐诗','yuding','','[]','四戶八窗明，玲瓏逼上清。外欄黃鵠下，中柱紫芝生。',48,'御定全唐詩/json/276.json','["四戶八窗明，玲瓏逼上清。外欄黃鵠下，中柱紫芝生。", "每帶雲霞色，時聞簫管聲。望君兼有月，幢蓋儼層城。"]'),
('yuding-62','送餞從叔辭豐州幕歸嵩陽舊居','盧綸','唐','御定全唐诗','yuding','','[]','白須宗孫侍坐時，願持壽酒前致詞。鄙詞何所擬，',110,'御定全唐詩/json/276.json','["白須宗孫侍坐時，願持壽酒前致詞。鄙詞何所擬，", "屯田布錦周千里，牧馬攢花溢萬群。白雲本是喬松伴，", "豐州聞說似涼州，沙塞晴明部落稠。行客已去依獨戍，", "洞裏先生那怪遲，人天無路自無期。砂泉丹井非同味，", "莫著戎衣期上清，東方曼倩逢人輕。"]'),
('yuding-63','送靜居法師','盧綸','唐','御定全唐诗','yuding','','[]','五色香幢重複重，寶輿升座發神鐘。薝蔔名花飄不斷，',40,'御定全唐詩/json/276.json','["五色香幢重複重，寶輿升座發神鐘。薝蔔名花飄不斷，", "願比靈山前世別，多生還得此相逢。"]'),
('yuding-64','送劉判官赴豐州','盧綸','唐','御定全唐诗','yuding','','[]','銜杯吹急管，滿眼起風砂。大漠山沈雪，長城草發花。',48,'御定全唐詩/json/276.json','["銜杯吹急管，滿眼起風砂。大漠山沈雪，長城草發花。", "策行須恥戰，虜在莫言家。餘亦祈勳者，如何別左車。"]'),
('yuding-65','將赴京留獻令公','盧綸','唐','御定全唐诗','yuding','','[]','沙鶴驚鳴野雨收，大河風物颯然秋。',32,'御定全唐詩/json/276.json','["沙鶴驚鳴野雨收，大河風物颯然秋。", "力微恩重諒難報，不是行人不解愁。"]'),
('yuding-66','落第後歸山下舊居留別劉起居昆季','盧綸','唐','御定全唐诗','yuding','','[]','寂寞過朝昏，沈憂豈易論。有時空蔔命，無事可酬恩。',120,'御定全唐詩/json/276.json','["寂寞過朝昏，沈憂豈易論。有時空蔔命，無事可酬恩。", "寄食依鄰里，成家望子孫。風塵知世路，衰賤到君門。", "醉裏因多感，愁中欲強言。花林逢廢井，戰地識荒園。", "悵別臨晴野，悲春上古原。鳥歸山外樹，人過水邊村。", "潘岳方稱老，嵇康本厭喧。誰堪將落羽，回首仰飛翻。"]'),
('yuding-67','將赴閿鄉灞上留別錢起員外','盧綸','唐','御定全唐诗','yuding','','[]','暖景登橋望，分明春色來。離心自惆悵，車馬亦裴回。',48,'御定全唐詩/json/276.json','["暖景登橋望，分明春色來。離心自惆悵，車馬亦裴回。", "遠雪和霜積，高花占日開。從官竟何事，憂患已相催。"]'),
('yuding-68','虢州逢侯釗同尋南觀因贈別','盧綸','唐','御定全唐诗','yuding','','[]','相見翻惆悵，應憐責廢官。過深慚祿在，識淺賴刑寬。',96,'御定全唐詩/json/276.json','["相見翻惆悵，應憐責廢官。過深慚祿在，識淺賴刑寬。", "獨失耕農業，同思弟侄歡。衰貧羞客過，卑束會君難。", "放鶴登雲壁，澆花繞石壇。興還江海上，跡在是非端。", "林密風聲細，山高雨色寒。悠然此中別，賓僕亦闌幹。"]'),
('yuding-69','赴池州拜覲舅氏留上考功郎中舅','盧綸','唐','御定全唐诗','yuding','','[]','孤賤易蹉跎，其如酷似何。衰榮同族少，生長外家多。',48,'御定全唐詩/json/276.json','["孤賤易蹉跎，其如酷似何。衰榮同族少，生長外家多。", "別國桑榆在，沾衣血淚和。應憐失行雁，霜霰寄煙波。"]'),
('yuding-70','送從侄滁州覲省','盧綸','唐','御定全唐诗','yuding','','[]','愛爾似龍媒，翩翩千里回。書從外氏學，竹自晉時栽。',48,'御定全唐詩/json/276.json','["愛爾似龍媒，翩翩千里回。書從外氏學，竹自晉時栽。", "擁棹逢鷗舞，憑闌見雨來。上堂多慶樂，不醉莫停杯。"]'),
('yuding-71','奉和聖制麟德殿宴百僚','盧綸','唐','御定全唐诗','yuding','','[]','雲辟禦筵張，山呼聖壽長。玉欄豐瑞草，金陛立神羊。',72,'御定全唐詩/json/276.json','["雲辟禦筵張，山呼聖壽長。玉欄豐瑞草，金陛立神羊。", "台鼎資庖膳，天星奉酒漿。蠻夷陪作位，犀象舞成行。", "網已祛三面，歌因守四方。千秋不可極，花發滿宮香。"]'),
('yuding-72','和考功王員外杪秋憶終南舊居','盧綸','唐','御定全唐诗','yuding','','[]','靜憶溪邊宅，知君許謝公。曉霜凝耒耜，初日照梧桐。',96,'御定全唐詩/json/276.json','["靜憶溪邊宅，知君許謝公。曉霜凝耒耜，初日照梧桐。", "澗鼠喧藤蔓，山禽竄石叢。白雲當嶺雨，黃葉繞階風。", "野果垂橋上，高泉落水中。歡榮來自間，羸賤賞曾同。", "月滿珠藏海，天晴鶴在籠。餘陰如可寄，願得隱牆東。"]'),
('yuding-73','酬暢當尋嵩岳麻道士見寄','盧綸','唐','御定全唐诗','yuding','','[]','聞逐樵夫閑看棋，忽逢人世是秦時。開雲種玉嫌山淺，',40,'御定全唐詩/json/276.json','["聞逐樵夫閑看棋，忽逢人世是秦時。開雲種玉嫌山淺，", "煩君遠示青囊籙，願得相從一問師。"]'),
('yuding-74','酬李端長安寓居偶詠見寄','盧綸','唐','御定全唐诗','yuding','','[]','自別前峰隱，同為外累侵。幾年親酒會，此日有僧尋。',120,'御定全唐詩/json/276.json','["自別前峰隱，同為外累侵。幾年親酒會，此日有僧尋。", "學稼功還棄，論邊事亦沈。眾歡徒滿目，專愛久離心。", "覽鬢絲垂鏡，彈琴淚灑襟。訪田悲洛下，寄宅憶山陰。", "薄溜漫青石，橫雲架碧林。壞簷藤障密，衰菜棘籬深。", "流散俱多故，憂傷並在今。唯當俟高躅，歸止共抽簪。"]'),
('yuding-75','和常舍人晚秋集賢院即事十二韻寄贈江南徐薛二侍郎','盧綸','唐','御定全唐诗','yuding','','[]','綸閣九華前，森沈彩仗連。洞門開旭日，清禁肅秋天。',144,'御定全唐詩/json/276.json','["綸閣九華前，森沈彩仗連。洞門開旭日，清禁肅秋天。", "霜滿朝容備，鐘餘漏唱傳。搖璫陪羽扇，端弁入爐煙。", "麟筆刪金篆，龍綃薦玉編。汲書荀勖定，漢史蔡邕專。", "禦竹潛通筍，宮池暗瀉泉。亂叢縈弱蕙，墜葉灑枯蓮。", "列署齊遊日，重江並謫年。登封思議草，侍講憶同筵。", "滄海風濤廣，黝山瘴雨偏。唯應緘上寶，贈遠一呈妍。"]'),
('yuding-76','酬苗員外仲夏歸郊居遇雨見寄','盧綸','唐','御定全唐诗','yuding','','[]','雷響風仍急，人歸鳥亦還。亂雲方至水，驟雨已喧山。',48,'御定全唐詩/json/276.json','["雷響風仍急，人歸鳥亦還。亂雲方至水，驟雨已喧山。", "田鼠依林上，池魚戲草間。因茲屏埃霧，一詠一開顏。"]'),
('yuding-77','和太常王卿立秋日即事','盧綸','唐','御定全唐诗','yuding','','[]','嵩高雲日明，潘岳賦初成。籬槿花無色，階桐葉有聲。',96,'御定全唐詩/json/276.json','["嵩高雲日明，潘岳賦初成。籬槿花無色，階桐葉有聲。", "絳紗垂簟淨，白羽拂衣輕。鴻雁悲天遠，龜魚覺水清。", "別弦添楚思，牧馬動邊情。田雨農官問，林風苑吏驚。", "松篁終茂盛，蓬艾自衰榮。遙仰憑軒夕，惟應喜宋生。"]'),
('yuding-0','和李使君三郎早秋城北亭樓宴崔司士因寄關中弟張評事時遇','盧綸','唐','御定全唐诗','yuding','','[]','黃花古城路，上盡見青山。桑柘晴川口，牛羊落照間。',72,'御定全唐詩/json/277.json','["黃花古城路，上盡見青山。桑柘晴川口，牛羊落照間。", "野情隨卷幔，軍士隔重關。道合偏多賞，官微獨不閑。", "鶴分琴久罷，書到雁應還。為謝登龍客，瓊枝寄一攀。"]'),
('yuding-1','和趙端公九日登石亭上和州家兄','盧綸','唐','御定全唐诗','yuding','','[]','洛浦想江津，悲歡共此辰。采花湖岸菊，望國舊樓人。',48,'御定全唐詩/json/277.json','["洛浦想江津，悲歡共此辰。采花湖岸菊，望國舊樓人。", "雁別聲偏苦，松寒色轉新。傳書問漁叟，借寇爾何因。"]'),
('yuding-2','酬趙少尹戲示諸侄元陽等因以見贈','盧綸','唐','御定全唐诗','yuding','','[]','八龍三虎儼成行，瓊樹花開鶴翼張。且請同觀舞鴝鵒，',40,'御定全唐詩/json/277.json','["八龍三虎儼成行，瓊樹花開鶴翼張。且請同觀舞鴝鵒，", "謬入阮家逢慶樂，竹林因得奉壺觴。"]'),
('yuding-3','奉和戶曹叔夏夜寓直寄呈同曹諸公並見示','盧綸','唐','御定全唐诗','yuding','','[]','斂板捧清詞，恭聞侍直時。暮塵歸眾騎，邃宇舍諸司。',72,'御定全唐詩/json/277.json','["斂板捧清詞，恭聞侍直時。暮塵歸眾騎，邃宇舍諸司。", "華月先燈至，清風與簟隨。亂螢光熠熠，行樹影離離。", "龍臥人寧識，鵬摶鷃豈知。便因當五夜，敢望竹林期。"]'),
('yuding-4','和金吾裴將軍使往河北宣慰因訪張氏昆季舊居兼寄趙侍郎趙卿拜陵未迴','盧綸','唐','御定全唐诗','yuding','','[]','飛軒不駐輪，感激漢儒臣。氣懾千夫勇，恩傳萬里春。',48,'御定全唐詩/json/277.json','["飛軒不駐輪，感激漢儒臣。氣懾千夫勇，恩傳萬里春。", "古原收野燎，寒笛怨空鄰。書此達良友，五陵風雨頻。"]'),
('yuding-5','和太常李主簿秋中山下別墅即事','盧綸','唐','御定全唐诗','yuding','','[]','清秋來幾時，宋玉已先知。曠朗霞映竹，澄明山滿池。',48,'御定全唐詩/json/277.json','["清秋來幾時，宋玉已先知。曠朗霞映竹，澄明山滿池。", "葺橋雙鶴赴，收果眾猿隨。韶樂方今奏，雲林徒蔽虧。"]'),
('yuding-6','酬韋渚秋夜有懷見寄','盧綸','唐','御定全唐诗','yuding','','[]','蕭條良夜永，秋草對衰顏。露下鳥初定，月明人自閑。',48,'御定全唐詩/json/277.json','["蕭條良夜永，秋草對衰顏。露下鳥初定，月明人自閑。", "獨悲無舊業，共喜出時艱。為問功成後，同遊何處山。"]'),
('yuding-7','同吉中孚夢桃源','盧綸','唐','御定全唐诗','yuding','','[]','春雨夜不散，夢中山亦陰。雲中碧潭水，路暗紅花林。',72,'御定全唐詩/json/277.json','["春雨夜不散，夢中山亦陰。雲中碧潭水，路暗紅花林。", "花水自深淺，無人知古今。", "夜靜春夢長，夢逐仙山客。園林滿芝朮，雞犬傍籬柵。", "幾處花下人，看予笑頭白。"]'),
('yuding-8','同柳侍郎題侯釗侍郎新昌裏','盧綸','唐','御定全唐诗','yuding','','[]','清源君子居，左右盡圖書。三徑春自足，一瓢歡有餘。',48,'御定全唐詩/json/277.json','["清源君子居，左右盡圖書。三徑春自足，一瓢歡有餘。", "庭莎成野席，闌藥是家蔬。幽顯豈殊跡，昔賢徒病諸。"]'),
('yuding-9','酬孫侍禦春日見寄','盧綸','唐','御定全唐诗','yuding','','[]','經過裏巷春，同是謝家鄰。顧我覺衰早，荷君留醉頻。',48,'御定全唐詩/json/277.json','["經過裏巷春，同是謝家鄰。顧我覺衰早，荷君留醉頻。", "松高猶覆草，鶴起暫縈塵。始悟達人志，患名非患貧。"]'),
('yuding-10','和王員外冬夜寓直','盧綸','唐','御定全唐诗','yuding','','[]','高步長裾錦帳郎，居然自是漢賢良。潘嶽敘年因鬢髮，',40,'御定全唐詩/json/277.json','["高步長裾錦帳郎，居然自是漢賢良。潘嶽敘年因鬢髮，", "坐見重門儼朝騎，可憐雲路獨翱翔。"]'),
('yuding-11','酬金部王郎中省中春日見寄','盧綸','唐','御定全唐诗','yuding','','[]','南宮樹色曉森森，雖有春光未有陰。鶴侶正疑芳景引，',40,'御定全唐詩/json/277.json','["南宮樹色曉森森，雖有春光未有陰。鶴侶正疑芳景引，", "更有阮郎迷路處，萬株紅樹一溪深。"]'),
('yuding-12','奉和陝州十四翁中丞寄雷州二十翁司戶','盧綸','唐','御定全唐诗','yuding','','[]','聯飛獨不前，迥落海南天。賈傅竟行矣，邵公唯泫然。',48,'御定全唐詩/json/277.json','["聯飛獨不前，迥落海南天。賈傅竟行矣，邵公唯泫然。", "瘴開山更遠，路極水無邊。沈劣本多感，況聞原上篇。"]'),
('yuding-13','和李中丞酬萬年房署少府過汾州景雲觀因以寄上房與李早年同居此觀','盧綸','唐','御定全唐诗','yuding','','[]','顯晦澹無跡，賢哉常晏如。如何警孤鶴，忽乃傳雙魚。',96,'御定全唐詩/json/277.json','["顯晦澹無跡，賢哉常晏如。如何警孤鶴，忽乃傳雙魚。", "敘以泉石舊，悵然風景餘。低回青油幕，夢寐白雲居。", "玉洞桂香滿，雪壇松影疏。沈思矚仙侶，紓組正軍書。", "積學早成道，感恩難遂初。梅生諒多感，歸止豈吾廬。"]'),
('yuding-14','酬陳翃郎中冬至攜柳郎竇郎歸河中舊居見寄','盧綸','唐','御定全唐诗','yuding','','[]','三旬一休沐，清景滿林廬。南郭群儒從，東床兩客居。',60,'御定全唐詩/json/277.json','["三旬一休沐，清景滿林廬。南郭群儒從，東床兩客居。", "燒煙浮雪野，麥隴潤冰渠。班白皆持酒，蓬茅盡有書。", "終期買寒渚，同此利蒲魚。"]'),
('yuding-15','酬李益端公夜宴見贈','盧綸','唐','御定全唐诗','yuding','','[]','戚戚一西東，十年今始同。可憐歌酒夜，相對兩衰翁。',24,'御定全唐詩/json/277.json','["戚戚一西東，十年今始同。可憐歌酒夜，相對兩衰翁。"]'),
('yuding-16','和陳翃郎中拜本府少尹兼侍御史獻上侍中因呈同院諸公','盧綸','唐','御定全唐诗','yuding','','[]','金印垂鞍白馬肥，不同疏廣老方歸。三千士裏文章伯，',40,'御定全唐詩/json/277.json','["金印垂鞍白馬肥，不同疏廣老方歸。三千士裏文章伯，", "鄉中賀者唯爭路，不識傳呼獬豸威。"]'),
('yuding-17','和王倉少尹暇日言懷','盧綸','唐','御定全唐诗','yuding','','[]','清秋多暇日，況乃是夫君。習靜通仙事，書空閱篆文。',48,'御定全唐詩/json/277.json','["清秋多暇日，況乃是夫君。習靜通仙事，書空閱篆文。", "劍飛終上漢，鶴夢不離雲。無限煙霄路，何嗟跡未分。"]'),
('yuding-18','和崔侍郎游萬固寺','盧綸','唐','御定全唐诗','yuding','','[]','聞說中方高樹林，曙華先照囀春禽。風雲才子冶游思，',40,'御定全唐詩/json/277.json','["聞說中方高樹林，曙華先照囀春禽。風雲才子冶游思，", "賀君此去君方至，河水東流西日沉。"]'),
('yuding-19','和裴延齡尚書寄題果州謝舍人仙居','盧綸','唐','御定全唐诗','yuding','','[]','飄然去謁八仙翁，自地從天香滿空。紫蓋迥標雙鶴上，',40,'御定全唐詩/json/277.json','["飄然去謁八仙翁，自地從天香滿空。紫蓋迥標雙鶴上，", "歌此因思捧金液，露盤長慶漢皇宮。"]'),
('yuding-20','酬崔侍禦早秋臥病書情見寄時君亦抱疾在假中','盧綸','唐','御定全唐诗','yuding','','[]','擲地金聲信有之，瑩然冰玉見清詞。元凱癖成官始貴，',40,'御定全唐詩/json/277.json','["擲地金聲信有之，瑩然冰玉見清詞。元凱癖成官始貴，", "寂寞罷琴風滿樹，幾多黃葉落蛛絲。"]'),
('yuding-21','酬靈澈上人','盧綸','唐','御定全唐诗','yuding','','[]','軍人奉役本無期，落葉花開總不知。',32,'御定全唐詩/json/277.json','["軍人奉役本無期，落葉花開總不知。", "走馬城中頭雪白，若為將面見湯師。"]'),
('yuding-22','敬酬大府二十四舅覽詩卷因以見示','盧綸','唐','御定全唐诗','yuding','','[]','郤公憐戇亦憐愚，忽賜金盤徑寸珠。徹底碧潭滋涸溜。',64,'御定全唐詩/json/277.json','["郤公憐戇亦憐愚，忽賜金盤徑寸珠。徹底碧潭滋涸溜。", "壓枝紅豔照枯株。九門洞啟延高論，百辟聯行挹大儒。", "顧己文章非酷似，敢將幽劣俟洪爐。"]'),
('yuding-23','雨中酬友人','盧綸','唐','御定全唐诗','yuding','','[]','看山獨行歸竹院，水繞前階草生遍。',32,'御定全唐詩/json/277.json','["看山獨行歸竹院，水繞前階草生遍。", "空林細雨暗無聲，唯有愁心兩相見。"]'),
('yuding-24','酬人失題','盧綸','唐','御定全唐诗','yuding','','[]','孤鸞將鶴群，晴日麗春雲。何幸晚飛者，清音長此聞。',24,'御定全唐詩/json/277.json','["孤鸞將鶴群，晴日麗春雲。何幸晚飛者，清音長此聞。"]'),
('yuding-25','哭司農苗主簿','盧綸','唐','御定全唐诗','yuding','','[]','原頭殯禦繞新塋，原下行人望哭聲。',32,'御定全唐詩/json/277.json','["原頭殯禦繞新塋，原下行人望哭聲。", "更想秋山連古木，唯應石上見君名。"]'),
('yuding-26','得耿湋司法書因敘長安故友零落兵部苗員外發祕省李校書端相次傾逝潞府崔功曹峒長林司空丞曙俱謫遠方余以搖落之時對書增歎因呈河中鄭倉曹暢參軍昆季','盧綸','唐','御定全唐诗','yuding','','[]','鬢似衰蓬心似灰，驚悲相集老相催。故友九泉留語別，',40,'御定全唐詩/json/277.json','["鬢似衰蓬心似灰，驚悲相集老相催。故友九泉留語別，", "幸接野居宜屣步，冀君清夜一申哀。"]'),
('yuding-27','同兵部李紓侍郎刑部包佶侍郎哭皇甫侍禦曾','盧綸','唐','御定全唐诗','yuding','','[]','攀龍與泣麟，哀樂不同塵。九陌霄漢侶，一燈冥漠人。',48,'御定全唐詩/json/277.json','["攀龍與泣麟，哀樂不同塵。九陌霄漢侶，一燈冥漠人。", "舟沈驚海闊，蘭折怨霜頻。已矣複何見，故山應更春。"]'),
('yuding-28','綸與吉侍郎中孚司空郎中曙苗員外發崔補闕峒耿拾遺湋李校書端風塵追遊向三十載數公皆負當時盛稱榮耀未幾俱沈下泉暢博士當感懷前蹤有五十韻見寄輒有所酬以申悲舊兼寄夏侯侍御審侯倉曹釗','盧綸','唐','御定全唐诗','yuding','','[]','稟命孤且賤，少為病所嬰。八歲始讀書，四方遂有兵。',576,'御定全唐詩/json/277.json','["稟命孤且賤，少為病所嬰。八歲始讀書，四方遂有兵。", "童心幸不羈，此去負平生。是月胡入洛，明年天隕星。", "夜行登灞陵，惝恍靡所征。雲海一翻蕩，魚龍俱不寧。", "因浮襄江流，遠寄鄱陽城。鄱陽富學徒，誚我戇無營。", "諭以詩禮義，勖隨賓薦名。舟車更滯留，水陸互陰晴。", "曉望怯雲陣，夜愁驚鶴聲。淒淒指宋郊，浩浩入秦京。", "沴氣既風散，皇威如日明。方逢粟比金，未識公與卿。", "十上不可待，三年竟無成。偶為達者知，揚我于王廷。", "素志且不立，青袍徒見縈。昏孱夙自保，靜躁本殊形。", "始趨甘棠陰，旋遇密人迎。考實績無取，責能才固輕。", "新豐古離宮，宮樹鎖雲扃。中複蒞茲邑，往惟曾所經。", "繚垣何逶迤，水殿亦崢嶸。夜雨滴金砌，陰風吹玉楹。", "官曹雖檢率，國步日夷平。命蹇固安分，禍來非有萌。", "因逢駭浪飄，幾落無辜刑。巍巍登壇臣，獨正天柱傾。", "悄悄失途子，分將秋草並。百年甘守素，一顧乃拾青。", "相逢十月交，眾卉飄已零。感舊諒戚戚，問孤懇煢煢。", "侍郎文章宗，傑出淮楚靈。掌賦若吹籟，司言如建瓴。", "郎中善餘慶，雅韻與琴清。鬱鬱松帶雪，蕭蕭鴻入冥。", "員外真貴儒，弱冠被華纓。月香飄桂實，乳溜滴瓊英。", "補闕思沖融，巾拂藝亦精。彩蝶戲芳圃，瑞雲凝翠屏。", "拾遺興難侔，逸調曠無程。九醞貯彌潔，三花寒轉馨。", "校書才智雄，舉世一娉婷。賭墅鬼神變，屬詞鸞鳳驚。", "差肩曳長裾，總轡奉和鈴。共賦瑤台雪，同觀金穀箏。", "倚天方比劍，沈井忽如瓶。神昧不可問，天高莫爾聽。"]'),
('yuding-29','酬李叔度秋夜喜相遇因傷關東僚友喪逝見贈','盧綸','唐','御定全唐诗','yuding','','[]','寒月照秋城，秋風泉澗鳴。過時見蘭蕙，獨夜感衰榮。',96,'御定全唐詩/json/277.json','["寒月照秋城，秋風泉澗鳴。過時見蘭蕙，獨夜感衰榮。", "酒散同移疾，心悲似遠行。以愚求作友，何德敢稱兄。", "穀變波長急，松枯藥未成。恐看新鬢色，怯問故人名。", "野澤雲陰散，荒原日氣生。羈飛本難定，非是惡弦驚。"]'),
('yuding-30','同李益傷秋','盧綸','唐','御定全唐诗','yuding','','[]','歲去人頭白，秋來樹葉黃。搔頭向黃葉，與爾共悲傷。',24,'御定全唐詩/json/277.json','["歲去人頭白，秋來樹葉黃。搔頭向黃葉，與爾共悲傷。"]'),
('yuding-31','白髮歎','盧綸','唐','御定全唐诗','yuding','','[]','發白曉梳頭，女驚妻淚流。不知絲色後，堪得幾回秋。',24,'御定全唐詩/json/277.json','["發白曉梳頭，女驚妻淚流。不知絲色後，堪得幾回秋。"]'),
('yuding-32','逢病軍人','盧綸','唐','御定全唐诗','yuding','','[]','行多有病住無糧，萬里還鄉未到鄉。',32,'御定全唐詩/json/277.json','["行多有病住無糧，萬里還鄉未到鄉。", "蓬鬢哀吟古城下，不堪秋氣入金瘡。"]'),
('yuding-33','村南逢病叟','盧綸','唐','御定全唐诗','yuding','','[]','雙膝過頤頂在肩，四鄰知姓不知年。',32,'御定全唐詩/json/277.json','["雙膝過頤頂在肩，四鄰知姓不知年。", "臥驅鳥雀惜禾黍，猶恐諸孫無社錢。"]'),
('yuding-34','七夕詩','盧綸','唐','御定全唐诗','yuding','','[]','祥光若可求，閨女夜登樓。月露浩方下，河雲凝不流。',48,'御定全唐詩/json/277.json','["祥光若可求，閨女夜登樓。月露浩方下，河雲凝不流。", "鉛華潛警曙，機杼暗傳秋。回想斂餘眷，人天俱是愁。"]'),
('yuding-35','七夕詩','盧綸','唐','御定全唐诗','yuding','','[]','涼風吹玉露，河漢有幽期。星彩光仍隱，雲容掩複離。',48,'御定全唐詩/json/277.json','["涼風吹玉露，河漢有幽期。星彩光仍隱，雲容掩複離。", "良宵驚曙早，閏歲怨秋遲。何事金閨子，空傳得網絲。"]'),
('yuding-36','長門怨','盧綸','唐','御定全唐诗','yuding','','[]','空空古廊殿，寒月落斜暉。臥聽未央曲，滿箱歌舞衣。',24,'御定全唐詩/json/277.json','["空空古廊殿，寒月落斜暉。臥聽未央曲，滿箱歌舞衣。"]'),
('yuding-37','妾薄命','盧綸','唐','御定全唐诗','yuding','','[]','妾年初二八，兩度嫁狂夫。薄命今猶在，堅貞掃地無。',24,'御定全唐詩/json/277.json','["妾年初二八，兩度嫁狂夫。薄命今猶在，堅貞掃地無。"]'),
('yuding-38','倫開府席上賦得詠美人名解愁','盧綸','唐','御定全唐诗','yuding','','[]','不敢苦相留，明知不自由。顰眉乍欲語，斂笑又低頭。',48,'御定全唐詩/json/277.json','["不敢苦相留，明知不自由。顰眉乍欲語，斂笑又低頭。", "舞態兼些醉，歌聲似帶羞。今朝總見也，只不解人愁。"]'),
('yuding-39','王評事駙馬花燭詩','盧綸','唐','御定全唐诗','yuding','','[]','萬條銀燭引天人，十月長安半夜春。',128,'御定全唐詩/json/277.json','["萬條銀燭引天人，十月長安半夜春。", "步障三千隘將斷，幾多珠翠落香塵。", "一人女婿萬人憐，一夜調疏抵百年。", "為報司徒好將息，明珠解轉又能圓。", "人主人臣是親家，千秋萬歲保榮華。", "幾時曾向高天上，得見今宵月裏花。", "比翼和鳴雙鳳凰，欲棲金帳滿城香。", "平明卻入天泉裏，日氣曈曨五色光。"]'),
('yuding-40','和趙給事白蠅拂歌','盧綸','唐','御定全唐诗','yuding','','[]','華堂多眾珍，白拂稱殊異。柄裁沈節香襲人，',84,'御定全唐詩/json/277.json','["華堂多眾珍，白拂稱殊異。柄裁沈節香襲人，", "皎然素色不因染，淅爾涼風非為秋。群蠅青蒼恣遊息，", "此時滿筵看一舉，荻花忽旋楊花舞，砉如寒隼驚暮禽，", "若將揮玩閑臨水，願接波中一白鷗。"]'),
('yuding-41','蕭常侍癭柏亭歌','盧綸','唐','御定全唐诗','yuding','','[]','柏之異者山中靈，何人斷絕為君亭。雲翻浪卷不可識，',120,'御定全唐詩/json/277.json','["柏之異者山中靈，何人斷絕為君亭。雲翻浪卷不可識，", "金貂主人漢三老，構此窮年下朝早。心規目制不暫疲，", "攢甍斗拱無斤跡，根癭聯懸同素壁。數層亂瀉雲裏峰，", "水精如意刁金色，雲母屏風透掩光。四階綿綿被纖草，", "愚儒敢欲賀成功，鸞鳳棲翔固不同。應念廢材今接地，"]'),
('yuding-42','慈恩寺石磬歌','盧綸','唐','御定全唐诗','yuding','','[]','靈山石磬生海西，海濤平處與山齊。長眉老僧同佛力，',96,'御定全唐詩/json/277.json','["靈山石磬生海西，海濤平處與山齊。長眉老僧同佛力，", "星漢徘徊山有風，禪翁靜扣月明中。群仙下雲龍出水，", "花宮杳杳響泠泠，無數沙門昏夢醒。古廊燈下見行道，", "豈如全質掛青松，數葉殘雲一片峰。吾師寶之壽中國，"]'),
('yuding-43','送張郎中還蜀歌','盧綸','唐','御定全唐诗','yuding','','[]','秦家禦史漢家郎，親專兩印征殊方。功成走馬朝天子，',112,'御定全唐詩/json/277.json','["秦家禦史漢家郎，親專兩印征殊方。功成走馬朝天子，", "瀘南五將望君還，願以天書示百蠻。曲棧重江初過雨，", "塞口雲生火候遲，煙中鶴唳軍行早。黃花川下水交橫，", "回首岷峨半天黑，傳觴接膝何由得。空令豪士仰威名，", "須臾醉起簫笳發，空見紅旌入白雲。"]'),
('yuding-44','宴席賦得姚美人拍箏歌','盧綸','唐','御定全唐诗','yuding','','[]','出簾仍有鈿箏隨，見罷翻令恨識遲。微收皓腕纏紅袖，',48,'御定全唐詩/json/277.json','["出簾仍有鈿箏隨，見罷翻令恨識遲。微收皓腕纏紅袖，", "鳳簫韶管寂不喧，繡幕紗窗儼秋月。有時輕弄和郎歌，"]'),
('yuding-45','陳翃郎中北亭送侯釗侍禦賦得帶冰流歌','盧綸','唐','御定全唐诗','yuding','','[]','溪中鳥鳴春景旦，一派寒冰忽開散。璧方鏡員流不斷，',40,'御定全唐詩/json/277.json','["溪中鳥鳴春景旦，一派寒冰忽開散。璧方鏡員流不斷，", "持此贈君君飲之，聖君識君冰玉姿。"]'),
('yuding-46','棲岩寺隋文帝馬腦盞歌','盧綸','唐','御定全唐诗','yuding','','[]','天宮寶器隋朝物，鎖在金函比金骨。開函捧之光乃發，',72,'御定全唐詩/json/277.json','["天宮寶器隋朝物，鎖在金函比金骨。開函捧之光乃發，", "規形環影相透徹，亂雪繁花千萬重。可憐貞質無今古，", "一留寒殿殿將壞，唯有幽光通隙塵。山中老僧眉似雪，"]'),
('yuding-47','難綰刀子歌','盧綸','唐','御定全唐诗','yuding','','[]','黃金鞘裏青蘆葉，麗若剪成銛且翣。輕冰薄玉狀不分，',48,'御定全唐詩/json/277.json','["黃金鞘裏青蘆葉，麗若剪成銛且翣。輕冰薄玉狀不分，", "淬之幾墮前池水，焉知不是蛟龍子。割雞刺虎皆若空，"]'),
('yuding-48','臘日觀咸甯王部曲娑勒擒豹歌','盧綸','唐','御定全唐诗','yuding','','[]','山頭曈曈日將出，山下獵圍照初日。前林有獸未識名，',112,'御定全唐詩/json/277.json','["山頭曈曈日將出，山下獵圍照初日。前林有獸未識名，", "陰方質子才三十，譯語受詞蕃語揖。舍鞍解甲疾如風，", "既蘇複吼拗仍怒，果協英謀生致之。拖自深叢目如電，", "始知縛虎如縛鼠，敗虜降羌生眼前。祝爾嘉詞爾無苦，", "非熊之兆慶無極，願紀雄名傳百蠻。"]'),
('yuding-49','賦得白鷗歌送李伯康歸使','盧綸','唐','御定全唐诗','yuding','','[]','積水深源，白鷗翻翻。倒影光素，於潭之間。',99,'御定全唐詩/json/277.json','["積水深源，白鷗翻翻。倒影光素，於潭之間。", "銜魚魚落亂驚鳴，爭撲蓮叢蓮葉傾。", "爾不見波中鷗鳥閑無營，何必汲汲勞其生。", "柳花冥蒙大堤口，悠揚相和乍無有。輕隨去浪杳不分，", "今日還同看鷗鳥，如何羽翮複參差。複參差，"]'),
('yuding-50','皇帝感詞','盧綸','唐','御定全唐诗','yuding','','[]','提劍風雷動，垂衣日月明。禁花呈瑞色，國老見星精。',192,'御定全唐詩/json/277.json','["提劍風雷動，垂衣日月明。禁花呈瑞色，國老見星精。", "發棹魚先躍，窺巢鳥不驚。山呼一萬歲，直入九重城。", "天香五鳳彩，禦馬六龍文。雨露清馳道，風雷翊上軍。", "高旍花外轉，行漏樂前聞。時見金鞭舉，空中指瑞雲。", "妙算干戈止，神謀宇宙清。兩階文物盛，七德武功成。", "校獵長楊苑，屯軍細柳營。歸來獻明主，歌舞溢春城。", "天樂下天中，雲輧儼在空。鉛黃豔河漢，笑語合笙鏞。", "已見長隨鳳，仍聞不避熊。君王親試舞，閶闔靜無風。"]'),
('yuding-0','天長久詞','盧綸','唐','御定全唐诗','yuding','','[]','玉砌紅花樹，香風不敢吹。春光解天意，偏發殿南枝。',136,'御定全唐詩/json/278.json','["玉砌紅花樹，香風不敢吹。春光解天意，偏發殿南枝。", "虹橋千步廊，半在水中央。天子方清暑，宮娃起夜妝。", "辭輦複當熊，傾心奉六宮。君王若看貌，甘在眾妃中。", "雲日呈祥禮物殊，彤庭生獻五單于。", "塞垣萬里無飛鳥，可是邊城用郅都。", "台殿雲深秋色微，君王初賜六宮衣。", "樓船泛罷歸猶早，行遣才人鬥射飛。"]'),
('yuding-1','和張僕射塞下曲','盧綸','唐','御定全唐诗','yuding','','[]','鷲翎金僕姑，燕尾繡蝥弧。獨立揚新令，千營共一呼。',144,'御定全唐詩/json/278.json','["鷲翎金僕姑，燕尾繡蝥弧。獨立揚新令，千營共一呼。", "林暗草驚風，將軍夜引弓。平明尋白羽，沒在石棱中。", "月黑雁飛高，單于夜遁逃。欲將輕騎逐，大雪滿弓刀。", "野幕敞瓊筵，羌戎賀勞旋。醉和金甲舞，雷鼓動山川。", "調箭又呼鷹，俱聞出世能。奔狐將迸雉，掃盡古丘陵。", "亭亭七葉貴，蕩蕩一隅清。他日題麟閣，唯應獨不名。"]'),
('yuding-2','古豔詩','盧綸','唐','御定全唐诗','yuding','','[]','殘妝色淺髻鬟開，笑映朱簾覷客來。',64,'御定全唐詩/json/278.json','["殘妝色淺髻鬟開，笑映朱簾覷客來。", "推醉唯知弄花鈿，潘郎不敢使人催。", "自拈裙帶結同心，暖處偏知香氣深。", "愛捉狂夫問閒事，不知歌舞用黃金。"]'),
('yuding-3','孤松吟酬渾贊善','盧綸','唐','御定全唐诗','yuding','','[]','深山荒松枝，雪壓半離披。朱門青松樹，萬葉承清露。',96,'御定全唐詩/json/278.json','["深山荒松枝，雪壓半離披。朱門青松樹，萬葉承清露。", "露重色逾鮮，吟風似遠泉。天寒香自發，日麗影常圓。", "陰郊一夜雪，榆柳皆枯折。回首望君家，翠蓋滿瓊花。", "捧君青松曲，自顧同衰木。曲罷不相親，深山頭白人。"]'),
('yuding-4','從軍行','盧綸','唐','御定全唐诗','yuding','','[]','二十在邊城，軍中得勇名。卷旗收敗馬，占磧擁殘兵。',72,'御定全唐詩/json/278.json','["二十在邊城，軍中得勇名。卷旗收敗馬，占磧擁殘兵。", "覆陣烏鳶起，燒山草木明。塞閑思遠獵，師老厭分營。", "雪嶺無人跡，冰河足雁聲。李陵甘此沒，惆悵漢公卿。"]'),
('yuding-5','和馬郎中畫鶴贊','盧綸','唐','御定全唐诗','yuding','','[]','高高華亭，有鶴在屏。削玉點漆，乘軒姓丁。',60,'御定全唐詩/json/278.json','["高高華亭，有鶴在屏。削玉點漆，乘軒姓丁。", "暮雲冥冥，雙垂雪翎。晨光炯炯，一直朱頂。", "含音儼容，絕粒遺影。君以為真，相期緱嶺。"]'),
('yuding-6','送朝長史赴荊南舊幕','盧綸','唐','御定全唐诗','yuding','','[]','元瑜思舊幕，幾夜夢旌旃。暑退蒹葭雨，秋生鼓角天。',48,'御定全唐詩/json/278.json','["元瑜思舊幕，幾夜夢旌旃。暑退蒹葭雨，秋生鼓角天。", "月明三峽路，浪裏九江船。□□□□□，□□□□□。"]'),
('yuding-7','送渭南崔少府歸徐郎中幕','盧綸','唐','御定全唐诗','yuding','','[]','葉下山邊路，行人見自悲。夜寒逢雪處，日暖到村時。',48,'御定全唐詩/json/278.json','["葉下山邊路，行人見自悲。夜寒逢雪處，日暖到村時。", "語少心長苦，愁深醉自遲。□□□□□，羨有幕中期。"]'),
('yuding-8','寄鄭七綱','盧綸','唐','御定全唐诗','yuding','','[]','小來落托複迍邅，一辱君知二十年，舍去形骸容傲慢，',40,'御定全唐詩/json/278.json','["小來落托複迍邅，一辱君知二十年，舍去形骸容傲慢，", "他日吳公如記問，願將黃綬比青氈。"]'),
('yuding-9','逢南中使因寄嶺外故人','盧綸','唐','御定全唐诗','yuding','','[]','見說南來處，蒼梧接桂林。過秋天更暖，邊海日長陰。',72,'御定全唐詩/json/278.json','["見說南來處，蒼梧接桂林。過秋天更暖，邊海日長陰。", "巴路緣雲出，蠻鄉入洞深。信回人自老，夢到月應沉。", "碧水通春色，青山寄遠心。炎方難久客，為爾一沾襟。"]'),
('yuding-10','代員將軍罷戰後歸舊裏贈朔北故人','盧綸','唐','御定全唐诗','yuding','','[]','結髮事疆場，全生俱到鄉。連雲防鐵嶺，同日破漁陽。',96,'御定全唐詩/json/278.json','["結髮事疆場，全生俱到鄉。連雲防鐵嶺，同日破漁陽。", "牧馬胡天晚，移軍磧路長。枕戈眠古戍，吹角立繁霜。", "歸老勳仍在，酬恩虜未亡。獨行過邑裏，多病對農桑。", "雄劍依塵橐，陰符寄藥囊。空餘麾下將，猶逐羽林郎。"]'),
('yuding-11','江北憶崔汶','盧綸','唐','御定全唐诗','yuding','','[]','夜問江西客，還知在楚鄉。全身出部伍，盡室逐漁商。',72,'御定全唐詩/json/278.json','["夜問江西客，還知在楚鄉。全身出部伍，盡室逐漁商。", "晴日游瓜步，新年對漢陽。月昏驚浪白，瘴起覺雲黃。", "望嶺家何處，登山淚幾行。閩中傳有雪，應且住南康。"]'),
('yuding-12','早春歸盩厔舊居卻寄耿拾遺湋李校書端','盧綸','唐','御定全唐诗','yuding','','[]','野日初晴麥壟分，竹園相接鹿成群。幾家廢井生青草，',40,'御定全唐詩/json/278.json','["野日初晴麥壟分，竹園相接鹿成群。幾家廢井生青草，", "可憐荒歲青山下，惟有松枝好寄君。"]'),
('yuding-13','春日山中憶崔峒吉中孚','盧綸','唐','御定全唐诗','yuding','','[]','延步愛清晨，空山日照春。蜜房那有主，石室自無鄰。',48,'御定全唐詩/json/278.json','["延步愛清晨，空山日照春。蜜房那有主，石室自無鄰。", "泉急魚依藻，花繁鳥近人。誰言失徒侶，唯與老相親。"]'),
('yuding-14','客舍喜崔補闕司空拾遺訪宿','盧綸','唐','御定全唐诗','yuding','','[]','步月訪諸鄰，蓬居宿近臣。烏裘先醉客，清鏡早朝人。',48,'御定全唐詩/json/278.json','["步月訪諸鄰，蓬居宿近臣。烏裘先醉客，清鏡早朝人。", "壞壁煙垂網，香街火照塵。悲榮俱是分，吾亦樂吾貧。"]'),
('yuding-15','苦雨聞包諫議欲見訪戲贈','盧綸','唐','御定全唐诗','yuding','','[]','草氣廚煙咽不開，繞床連壁盡生苔。',32,'御定全唐詩/json/278.json','["草氣廚煙咽不開，繞床連壁盡生苔。", "常時多病因多雨，那敢煩君車馬來。"]'),
('yuding-16','客舍苦雨即事寄錢起郎士元二員外','盧綸','唐','御定全唐诗','yuding','','[]','積雨暮淒淒，羈人狀鳥棲。響空宮樹接，覆水野雲低。',120,'御定全唐詩/json/278.json','["積雨暮淒淒，羈人狀鳥棲。響空宮樹接，覆水野雲低。", "穴蟻多隨草，巢蜂半墜泥。繞池牆蘚合，擁溜瓦松齊。", "舊圃平如海，新溝曲似溪。壞闌留眾蝶，欹棟止群雞。", "莠盛終無實，槎枯返有荑。綠萍藏廢井，黃葉隱危堤。", "閭裏歡將絕，朝昏望亦迷。不知霄漢侶，何路可相攜。"]'),
('yuding-17','郊居對雨寄趙涓給事包佶郎中','盧綸','唐','御定全唐诗','yuding','','[]','暑雨青山裏，隨風到野居。亂漚浮曲砌，懸溜響前除。',120,'御定全唐詩/json/278.json','["暑雨青山裏，隨風到野居。亂漚浮曲砌，懸溜響前除。", "塵鏡愁多掩，蓬頭懶更梳。夜窗淒枕席，陰壁潤圖書。", "蕭颯宜新竹，龍鍾拾野蔬。石泉空自咽，藥圃不堪鋤。", "濁水淙深轍，荒蘭擁敗渠。繁枝留宿鳥，碎浪出寒魚。", "桑屐時登望，荷衣自卷舒。應憐在泥滓，無路托高車。"]'),
('yuding-18','藍溪期蕭道士采藥不至','盧綸','唐','御定全唐诗','yuding','','[]','春風生百藥，幾處術苗香。人遠花空落，溪深日複長。',48,'御定全唐詩/json/278.json','["春風生百藥，幾處術苗香。人遠花空落，溪深日複長。", "病多知藥性，老近憶仙方。清節何由見，三山桂自芳。"]'),
('yuding-19','雪謗後書事上皇甫大夫','盧綸','唐','御定全唐诗','yuding','','[]','盛德總群英，高標仰國楨。獨安巡狩日，曾掩趙張名。',192,'御定全唐詩/json/278.json','["盛德總群英，高標仰國楨。獨安巡狩日，曾掩趙張名。", "業就難辭寵，朝回更授兵。曉川分牧馬，夜雪覆連營。", "長策威殊俗，嘉謀翊聖明。畫圖規陣勢，夢筆紀山行。", "綬拂池中影，珂搖竹外聲。賜歡征妓樂，陪醉問公卿。", "卻憶經前事，翻疑得此生。分深存沒感，恩在子孫榮。", "覽鏡愁將老，捫心喜複驚。豈言沈族重，但覺殺身輕。", "有淚沾墳典，無家集弟兄。東西遭世難，流浪識交情。", "閱古宗文舉，推才慕正平。應憐守貧賤，又欲事躬耕。"]'),
('yuding-20','春日憶司空文明','盧綸','唐','御定全唐诗','yuding','','[]','桃李風多日欲陰，百勞飛處落花深。',32,'御定全唐詩/json/278.json','["桃李風多日欲陰，百勞飛處落花深。", "貧居靜久難逢信，知隔春山不可尋。"]'),
('yuding-21','臥病寓居龍興觀枉馮十七著作書知罷攝洛陽赴緱氏因題十四韻寄馮生并贈喬尊師','盧綸','唐','御定全唐诗','yuding','','[]','乞假依山宅，蹉跎屬歲周。弱荑輕采拾，鈍質稱歸休。',168,'御定全唐詩/json/278.json','["乞假依山宅，蹉跎屬歲周。弱荑輕采拾，鈍質稱歸休。", "潘嶽衰將至，劉楨病未瘳。步遲乘羽客，起晏滯書郵。", "幸以編方驗，終貽骨肉憂。灼龜爐氣冷，曝藥樹陰稠。", "語命心堪醉，傷離夢亦愁。葷膻居已絕，鸞鶴見無由。", "世累如塵積，年光劇水流。躡雲知有路，濟海豈無舟。", "倚玉翻成難，投磚敢望酬。卑棲君就祿，羸憊我逢秋。", "腐葉填荒轍，陰螢出古溝。依然在遐想，願子勵風猷。"]'),
('yuding-22','秋夜寄馮著作','盧綸','唐','御定全唐诗','yuding','','[]','河漢淨無雲，鴻聲此夜聞。素心難比石，蒼鬢欲如君。',48,'御定全唐詩/json/278.json','["河漢淨無雲，鴻聲此夜聞。素心難比石，蒼鬢欲如君。", "露槿月中落，風螢池上分。何言千載友，同跡不同群。"]'),
('yuding-23','洛陽早春憶吉中孚校書、司空曙主簿因寄清江上人','盧綸','唐','御定全唐诗','yuding','','[]','值迥逢高駐馬頻，雪晴閑看洛陽春。鶯聲報遠同芳信，',40,'御定全唐詩/json/278.json','["值迥逢高駐馬頻，雪晴閑看洛陽春。鶯聲報遠同芳信，", "年來百事皆無緒，唯與湯師結淨因。"]'),
('yuding-24','偶逢姚校書憑附書達河南郤推官因以戲贈','盧綸','唐','御定全唐诗','yuding','','[]','寄書常切到常遲，今日憑君君莫辭。',32,'御定全唐詩/json/278.json','["寄書常切到常遲，今日憑君君莫辭。", "若問玉人殊易識，蓮花府裏最清羸。"]'),
('yuding-25','夜中得循州趙司馬侍郎書因寄回使','盧綸','唐','御定全唐诗','yuding','','[]','瘴海寄雙魚，中宵達我居。兩行燈下淚，一紙嶺南書。',48,'御定全唐詩/json/278.json','["瘴海寄雙魚，中宵達我居。兩行燈下淚，一紙嶺南書。", "地說炎蒸極，人稱老病餘。殷勤報賈傅，莫共酒杯疏。"]'),
('yuding-26','晚次新豐北野老家書事呈贈韓質明府','盧綸','唐','御定全唐诗','yuding','','[]','機鳴舂響日暾暾，雞犬相和漢古村。數派清泉黃菊盛，',40,'御定全唐詩/json/278.json','["機鳴舂響日暾暾，雞犬相和漢古村。數派清泉黃菊盛，", "共說年來但無事，不知何者是君恩。"]'),
('yuding-27','書情上大尹十兄','盧綸','唐','御定全唐诗','yuding','','[]','紫陌絕纖埃，油幢千騎來。剖辭紛若雨，奔吏殷成雷。',120,'御定全唐詩/json/278.json','["紫陌絕纖埃，油幢千騎來。剖辭紛若雨，奔吏殷成雷。", "聖澤初憂壅，群心本在台。海鱗方潑剌，雲翼暫徘徊。", "芳室芝蘭茂，春蹊桃李開。江湖餘派少，鴻雁遠聲哀。", "命厭蓍龜誘，年驚弟侄催。磨鉛慚砥礪，揮策愧駑駘。", "玉管能喧谷，金爐可變灰。應憐費思者，銜淚亦銜枚。"]'),
('yuding-28','春思貽李方陵','盧綸','唐','御定全唐诗','yuding','','[]','長安三月春，難別複難親。不識冶遊伴，多逢憔悴人。',48,'御定全唐詩/json/278.json','["長安三月春，難別複難親。不識冶遊伴，多逢憔悴人。", "漸知歡澹薄，轉覺老殷勤。去矣盡如此，此辭悲未陳。"]'),
('yuding-29','驛中望山戲贈渭南陸贄主簿','盧綸','唐','御定全唐诗','yuding','','[]','官微多懼事多同，拙性偏無主驛功。',32,'御定全唐詩/json/278.json','["官微多懼事多同，拙性偏無主驛功。", "山在門前登不得，鬢毛衰盡路塵中。"]'),
('yuding-30','太白西峰偶宿車祝二尊師石室晨登前巘憑眺書懷即事寄呈鳳翔齊員外張侍御','盧綸','唐','御定全唐诗','yuding','','[]','弱齡誠昧鄙，遇勝惟求止。如何羈滯中，得步青冥裏。',180,'御定全唐詩/json/278.json','["弱齡誠昧鄙，遇勝惟求止。如何羈滯中，得步青冥裏。", "青冥有桂叢，冰雪兩仙翁。毛節未歸海，丹梯閑倚空。", "逍遙擬上清，洞府不知名。醮罷雨雷至，客辭山忽明。", "山明鳥聲樂，日氣生岩壑。岩壑樹修修，白雲如水流。", "白雲消散盡，隴塞儼然秋。積阻關河固，綿聯烽戍稠。", "五營承廟略，四野失邊愁。籲嗟系塵役，又負靈仙跡。", "芝朮自芳香，泥沙幾沉溺。書此欲沾衣，平生事每違。", "煙霄不可仰，鸞鶴自追隨。"]'),
('yuding-31','贈韓山人','盧綸','唐','御定全唐诗','yuding','','[]','見君何事不慚顏，白髮生來未到山。',32,'御定全唐詩/json/278.json','["見君何事不慚顏，白髮生來未到山。", "更歎無家又無藥，往來唯在酒徒間。"]'),
('yuding-32','贈李果毅','盧綸','唐','御定全唐诗','yuding','','[]','向日磨金鏃，當風著錦衣。上城邀賊語，走馬截雕飛。',24,'御定全唐詩/json/278.json','["向日磨金鏃，當風著錦衣。上城邀賊語，走馬截雕飛。"]'),
('yuding-33','春日書情贈別司空曙','盧綸','唐','御定全唐诗','yuding','','[]','壯志隨年盡，謀身意未安。風塵交契闊，老大別離難。，',25,'御定全唐詩/json/278.json','["壯志隨年盡，謀身意未安。風塵交契闊，老大別離難。，"]'),
('yuding-34','冬曉呈鄰里','盧綸','唐','御定全唐诗','yuding','','[]','終夜寢衣冷，開門思曙光。空階一叢葉，華室四鄰霜。',48,'御定全唐詩/json/278.json','["終夜寢衣冷，開門思曙光。空階一叢葉，華室四鄰霜。", "望闕覺天迥，憶山愁路荒。途中一留滯，雙鬢颯然蒼。"]'),
('yuding-35','首冬寄河東昭德里書事貽鄭損倉曹','盧綸','唐','御定全唐诗','yuding','','[]','清冬和暖天，老鈍晝多眠。日愛閭巷靜，每聞官吏賢。',48,'御定全唐詩/json/278.json','["清冬和暖天，老鈍晝多眠。日愛閭巷靜，每聞官吏賢。", "寒菹供家食，腐葉宿廚煙。且複執杯酒，無煩輕議邊。"]'),
('yuding-36','渾贊善東齋戲贈陳歸','盧綸','唐','御定全唐诗','yuding','','[]','長裾珠履颯輕塵，閑以琴書列上賓。',32,'御定全唐詩/json/278.json','["長裾珠履颯輕塵，閑以琴書列上賓。", "公子無讎可邀請，侯嬴此坐是何人。"]'),
('yuding-37','春日臥病示趙季黃','盧綸','唐','御定全唐诗','yuding','','[]','病中饒淚眼常昏，聞說花開亦閉門。語少漸知琴思苦，',40,'御定全唐詩/json/278.json','["病中饒淚眼常昏，聞說花開亦閉門。語少漸知琴思苦，", "今日支離顧形影，向君凡在幾重恩。"]'),
('yuding-38','秋幕中夜獨坐遲明因陪陳翃郎中晨謁上公因書即事兼呈同院諸公','盧綸','唐','御定全唐诗','yuding','','[]','風淒露泫然，明月在山巔。獨倚古庭樹，仰看深夜天。',144,'御定全唐詩/json/278.json','["風淒露泫然，明月在山巔。獨倚古庭樹，仰看深夜天。", "葉翻螢不定，蟲思草無邊。南舍機杼發，東方雲景鮮。", "簪裘肅已整，車騎儼將前。百雉拱雙戟，萬夫尊一賢。", "琳琅多謀蘊，律呂更相宣。曉桂香浥露，新鴻晴滿川。", "熙熙造化功，穆穆唐堯年。顧己草同賤，誓心金匪堅。", "蹇辭慚自寡，渴病老難痊。書此更何問，邊韶唯晝眠。"]'),
('yuding-39','寄贈庫部王郎中','盧綸','唐','御定全唐诗','yuding','','[]','諤諤漢名臣，從天令若春。敘辭皆詔旨，稱宦即星辰。',120,'御定全唐詩/json/278.json','["諤諤漢名臣，從天令若春。敘辭皆詔旨，稱宦即星辰。", "草木承風偃，雲雷施澤均。威懲治粟尉，恩洽讓田人。", "泉貨方將散，京坻自此陳。五營俱益灶，千里不停輪。", "未遠金門籍，旋清玉塞塵。碩儒推慶重，良友頌公頻。", "鶴發逢新鏡，龍門躍舊鱗。荷君偏有問，深感浩難申。"]'),
('yuding-40','寄贈暢當山居','盧綸','唐','御定全唐诗','yuding','','[]','古村荒石路，歲晏獨言歸。山雪厚三尺，社榆粗十圍。',48,'御定全唐詩/json/278.json','["古村荒石路，歲晏獨言歸。山雪厚三尺，社榆粗十圍。", "虯龍寧守蟄，鸞鶴豈矜飛。君子固安分，毋聽勞者譏。"]'),
('yuding-41','偶宿山中憶暢當','盧綸','唐','御定全唐诗','yuding','','[]','深山夜雪晴，坐憶曉山明。讀易罷三卷，彈琴當五更。',48,'御定全唐詩/json/278.json','["深山夜雪晴，坐憶曉山明。讀易罷三卷，彈琴當五更。", "薜蘿枯有影，岩壑凍無聲。此夕一相望，君應知我誠。"]'),
('yuding-42','秋中野望寄舍弟綬兼令呈上西川尚書舅','盧綸','唐','御定全唐诗','yuding','','[]','憂來思遠望，高處殊非愜。夜露濕蒼山，秋陂滿黃葉。',144,'御定全唐詩/json/278.json','["憂來思遠望，高處殊非愜。夜露濕蒼山，秋陂滿黃葉。", "人隨雁迢遞，棧與雲重疊。骨肉暫分離，形神遂疲苶。", "紅旌渭陽騎，幾日勞登涉。蜀道藹松筠，巴江盛舟楫。", "小生即何限，簡誨偏盈篋。舊恨尚填膺，新悲複縈睫。", "因求種瓜利，自喜歸耕捷。井臼賴依鄰，兒童亦勝汲。", "塵容不在照，雪鬢那堪鑷。唯有餐霞心，知夫與天接。"]'),
('yuding-43','行藥前軒呈董山人','盧綸','唐','御定全唐诗','yuding','','[]','不覺老將至，瘦來方自驚。朝昏多病色，起坐有勞聲。',48,'御定全唐詩/json/278.json','["不覺老將至，瘦來方自驚。朝昏多病色，起坐有勞聲。", "腠暖苦肌癢，藏虛唯耳鳴。桑公富靈術，一為保餘生。"]');
